window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["c16-fire-sprinkler"] = window.COURSE_LANG["c16-fire-sprinkler"] || {};
window.COURSE_LANG["c16-fire-sprinkler"]["es"] = [
  {id:1, q:"El clásico 'triángulo del fuego' representa los tres elementos que deben estar presentes para la combustión. ¿Qué conjunto los enumera correctamente?", opts:["Presión, velocidad y densidad","Agua, aire y electricidad","Humo, llama y ceniza","Combustible, oxígeno (comburente) y calor"], re:"El triángulo del fuego es el combustible, un agente oxidante (típicamente oxígeno) y el calor; si se elimina cualquiera de ellos, la combustión se detiene. Esta es la base de la supresión de incendios. Fuente: fundamentos de ciencia del fuego de la NFPA; descripción general del tetraedro del fuego de la WFCA."},
  {id:2, q:"El 'tetraedro del fuego' agrega un cuarto elemento al triángulo del fuego. ¿Cuál es ese cuarto elemento?", opts:["La reacción química en cadena autosostenida","Solamente una chispa de ignición","Una fuente de combustible presurizada","Un espacio confinado"], re:"El tetraedro agrega la reacción química en cadena no inhibida al combustible, el oxígeno y el calor. Agentes como los agentes limpios/halón actúan interrumpiendo esta reacción. Fuente: WFCA 'Fire Tetrahedron Explained'; tetraedro del fuego de Firetrace."},
  {id:3, q:"Un sistema de rociadores contra incendios a base de agua extingue o controla el fuego principalmente mediante cuál mecanismo principal?", opts:["Enfriamiento — eliminando el calor del fuego y de la superficie del combustible","Sofocando el combustible con una manta de espuma","Agregando oxígeno para diluir el humo","Interrumpiendo eléctricamente la llama"], re:"La alta capacidad calorífica y el calor de vaporización del agua hacen del enfriamiento (eliminación del calor) su modo dominante de supresión; también proporciona cierto humedecimiento/prehumedecimiento de la superficie. Fuente: fundamentos de ciencia del fuego de la NFPA; métodos de supresión del tetraedro del fuego."},
  {id:4, q:"¿Aproximadamente qué porcentaje de oxígeno contiene el aire normal, del cual depende la combustión?", opts:["Cerca del 5 por ciento","Cerca del 50 por ciento","Cerca del 21 por ciento","Cerca del 78 por ciento"], re:"El aire es aproximadamente 21% oxígeno (y ~78% nitrógeno); la mayoría de la combustión con llama se suprime cuando el oxígeno cae por debajo de ~15-16%. Fuente: tetraedro del fuego de la WFCA (oxígeno ~21%, los incendios necesitan un mínimo de ~16%)."},
  {id:5, q:"¿Cuál de los tres modos de transferencia de calor es el MÁS responsable de llevar los gases calientes del fuego hacia el elemento térmico de un rociador montado en el techo y activarlo?", opts:["Conducción a través del acero del edificio","Radiación desde superficies frías","Convección — la columna ascendente de gases calientes","Evaporación del anticongelante"], re:"La convección (la columna flotante de gases calientes que forma un chorro de techo) tiene el mayor efecto sobre la activación del rociador; el chorro de techo calienta el elemento térmico. Fuente: NFSA 'Fire Dynamics and Sprinkler Activation.'"},
  {id:6, q:"La transferencia de calor por contacto directo a través de un material sólido (por ejemplo, una tubería caliente que calienta un miembro adyacente) se denomina:", opts:["Convección","Radiación","Conducción","Sublimación"], re:"La conducción es la transferencia de calor dentro de los sólidos o entre sólidos en contacto. La convección mueve el calor por el movimiento de fluidos/gases; la radiación por ondas electromagnéticas. Fuente: fundamentos del comportamiento del fuego y de transferencia de calor (Warren Forensics; Adaston)."},
  {id:7, q:"La transferencia de calor por ondas electromagnéticas que pueden encender materiales a través de un espacio de aire sin contacto se denomina:", opts:["Convección","Conducción","Radiación","Difusión"], re:"La radiación transfiere calor en forma de ondas electromagnéticas y puede encender materiales a distancia (por ejemplo, rompiendo ventanas, encendiendo edificios cercanos). Fuente: fundamentos de transferencia de calor (Warren Forensics; Ark-FP)."},
  {id:8, q:"Un incendio de Clase A involucra qué tipo de combustible?", opts:["Equipo eléctrico energizado","Combustibles ordinarios como madera, papel y tela","Líquidos inflamables como la gasolina","Metales combustibles como el magnesio"], re:"Clase A = combustibles ordinarios (madera, papel, tela, muchos plásticos); el agua es muy adecuada para los incendios de Clase A. Fuente: definiciones de clases de fuego de la NFPA 10; clases de fuego de Pye-Barker."},
  {id:9, q:"¿Qué clase de fuego involucra LÍQUIDOS y gases inflamables o combustibles (gasolina, aceite, solventes)?", opts:["Clase A","Clase C","Clase B","Clase D"], re:"Clase B = líquidos y gases inflamables (gasolina, aceite, solventes). El agua sola puede propagar estos incendios, por lo que se usan espuma u otros agentes. Fuente: definiciones de clases de fuego de la NFPA 10; Swartz Fire & Safety."},
  {id:10, q:"¿Qué clase de fuego involucra equipo eléctrico ENERGIZADO, donde un agente conductor como el agua es peligroso?", opts:["Clase B","Clase A","Clase C","Clase K"], re:"Clase C = incendios en equipo eléctrico energizado; se requieren agentes no conductores. Una vez que se retira la energía, puede convertirse en un incendio de Clase A o B. Fuente: NFPA 10; clases de fuego de UCLA Health."},
  {id:11, q:"Los incendios de Clase K, que requieren agentes químicos húmedos especiales, involucran qué combustible?", opts:["Aceites y grasas de cocina (cocinas comerciales)","Metales combustibles","Equipo electrónico energizado","Papel y madera"], re:"Clase K = aceites/grasas de cocina; los agentes químicos húmedos saponifican la grasa para enfriarla y sellarla contra la reignición. Fuente: NFPA 10; NFPA 17A / clases de fuego de Pye-Barker."},
  {id:12, q:"Cuando el agua absorbe calor y se convierte en vapor, la gran expansión de volumen ayuda a la supresión al:", opts:["Agregar combustible al fuego","Desplazar el oxígeno alrededor del fuego y absorber calor","Aumentar la reacción química en cadena","Elevar la temperatura del combustible"], re:"La conversión en vapor absorbe grandes cantidades de calor (calor latente de vaporización) y la expansión del vapor desplaza el oxígeno cerca del foco del incendio, ayudando al control. Fuente: fundamentos de supresión de incendios; el agua como agente de Clase A (NFPA)."},
  {id:13, q:"La temperatura a la que un material desprende suficiente vapor para encenderse momentáneamente cuando hay una fuente de ignición presente se denomina su:", opts:["Punto de ebullición","Punto de congelación","Punto de inflamación","Calor específico"], re:"El punto de inflamación es la temperatura más baja a la que un líquido desprende vapor en concentración suficiente para inflamarse (encenderse momentáneamente) cerca de una fuente de ignición. Fuente: NFPA 30 / fundamentos de ciencia del fuego (líquidos inflamables y combustibles)."},
  {id:14, q:"El 'flashover' (combustión súbita generalizada) en un incendio de compartimento se refiere a:", opts:["La primera llama que se hace visible","Un cortocircuito eléctrico","El agua que se convierte súbitamente en vapor en un rociador","La ignición casi simultánea de todos los combustibles expuestos en una habitación al alcanzar su participación total"], re:"El flashover es la transición a la participación total de la habitación cuando el calor radiante enciende casi todas las superficies expuestas a la vez. Los rociadores residenciales (NFPA 13D) buscan prevenir el flashover para permitir el escape. Fuente: fundamentos de dinámica del fuego; objetivo de seguridad de vida de la NFPA 13D."},
  {id:15, q:"En comparación con simplemente 'controlar' un incendio, 'suprimir' un incendio significa:", opts:["Solo activar la alarma","Reducir bruscamente la tasa de liberación de calor y prevenir el recrecimiento, trabajando hacia la extinción","Mantener constante el tamaño del fuego","Ventilar el humo del edificio"], re:"El control limita el crecimiento del fuego y prehumedece los alrededores; la supresión reduce bruscamente la liberación de calor y previene el recrecimiento (el objetivo de los rociadores ESFR). Fuente: conceptos de control vs. supresión de la NFPA 13; intención de diseño ESFR."},
  {id:16, q:"¿Por qué generalmente NO se recomienda el agua sola como agente primario en un incendio de charco de líquido inflamable de Clase B?", opts:["Se congela demasiado rápido","Los combustibles más livianos que el agua pueden flotar y propagarse, y el agua puede salpicar el líquido en llamas","El agua agrega nitrógeno al fuego","El agua no es conductora"], re:"Muchos líquidos inflamables son más livianos que el agua e inmiscibles con ella, por lo que un chorro de agua puede propagar el combustible en llamas; para tales incendios se usa espuma (no agua sola). Fuente: NFPA 10/11; selección de agentes por clase de fuego."},
  {id:17, q:"En términos de supresión de incendios, aplicar una manta de espuma sobre la superficie de un combustible líquido funciona principalmente al:", opts:["Enfriar la reacción en cadena eléctricamente","Separar el combustible del oxígeno (y suprimir los vapores)","Agregar oxígeno","Aumentar el calor radiante"], re:"La espuma cubre el combustible, excluyendo el oxígeno y suprimiendo los vapores inflamables (también enfría). Esto ataca las patas de oxígeno y vapor de combustible del tetraedro. Fuente: fundamentos de espuma de la NFPA 11; métodos de supresión del tetraedro del fuego."},
  {id:18, q:"En un sistema de rociadores de tubería húmeda, la tubería normalmente está llena de:", opts:["Solamente aire presurizado","Agua bajo presión","Nitrógeno presurizado","Gas anticongelante"], re:"Un sistema de tubería húmeda tiene la tubería constantemente llena de agua bajo presión, por lo que el agua se descarga inmediatamente cuando un rociador se abre. Fuente: definición de sistema de tubería húmeda de la NFPA 13; NFPA 'Types of Sprinkler Systems.'"},
  {id:19, q:"¿Qué afirmación sobre la velocidad de entrega de agua es correcta para los sistemas de tubería húmeda?", opts:["Son los más lentos de todos los tipos de sistemas","Entregan agua más rápido que los sistemas de tubería seca, de preacción o de diluvio porque el agua ya está en el rociador","Entregan agua solo después de que un detector se active","Requieren un acelerador para entregar agua"], re:"Debido a que el agua ya está en la tubería sin activación intermedia, los sistemas de tubería húmeda entregan agua más rápido que cualquier otro tipo de sistema, minimizando el crecimiento del fuego. Fuente: NFPA 'Sprinkler System Basics: Types of Sprinkler Systems.'"},
  {id:20, q:"¿Cuál es la mayor limitación que hace que un sistema estándar de tubería húmeda no sea adecuado para algunas áreas?", opts:["No se puede usar por encima de 2 pisos","No puede usar rociadores colgantes","Requiere generadores de nitrógeno","El agua en la tubería puede congelarse en espacios sin calefacción/bajo cero"], re:"El agua estancada en la tubería húmeda la hace inadecuada para áreas sujetas a congelación a menos que estén protegidas (por ejemplo, bucle anticongelante o se use tubería seca/preacción en su lugar). Fuente: NFPA 13; diferencias entre húmeda y seca de Ryan F.P."},
  {id:21, q:"En un sistema de tubería húmeda, un rociador individual opera (se abre) cuando:", opts:["Un detector de humo envía una señal","El panel de alarma contra incendios lo ordena","Su elemento sensible al calor (ampolla de vidrio o eslabón fusible) alcanza su temperatura nominal","Se activa una estación manual de tracción"], re:"Cada rociador cerrado se abre individualmente cuando su propio elemento térmico alcanza su temperatura nominal; solo operan los rociadores sobre el fuego. Fuente: NFPA 13; guía de sensibilidad térmica de QRFS."},
  {id:22, q:"Una idea errónea común es que 'todos los rociadores se activan a la vez' en un incendio. En un sistema típico de tubería húmeda:", opts:["Cada rociador del edificio se descarga junto","Ningún rociador opera sin el panel de alarma","La mitad de los rociadores del edificio operan","Solo opera(n) el/los rociador(es) cuyo elemento térmico ha alcanzado su temperatura nominal"], re:"Los rociadores estándar se activan individualmente por calor; generalmente solo uno o unos pocos sobre el fuego se abren, a diferencia de un sistema de diluvio. Fuente: materiales de educación pública de la NFPA; operación de la NFPA 13."},
  {id:23, q:"¿Qué válvula se usa comúnmente en un montante de tubería húmeda para detectar el flujo de agua e iniciar una alarma?", opts:["Una válvula de retención de alarma","Una válvula de diluvio","Una válvula de tubería seca","Una válvula reductora de presión"], re:"Un montante de tubería húmeda normalmente usa una válvula de retención de alarma (o un montante tipo 'shotgun' con un interruptor de flujo) para detectar el flujo e iniciar la alarma de flujo de agua. Fuente: Code Red Consultants 'Alarm Check Valves'; componentes del montante de la NFPA 13."},
  {id:24, q:"En un sistema de tubería húmeda, el propósito de una CÁMARA DE RETARDO asociada con la válvula de retención de alarma es:", opts:["Almacenar anticongelante","Reducir las falsas alarmas por breves sobrepresiones de agua","Acelerar la entrega de agua","Drenar todo el sistema"], re:"La cámara de retardo agrega un breve retraso mecánico para que las sobrepresiones momentáneas de suministro no activen la alarma de flujo de agua; se llena antes de que suene la alarma. Fuente: NFPA 13; guarnición de la válvula de retención de alarma de Code Red Consultants."},
  {id:25, q:"Un gong de motor de agua (alarma mecánica) en un sistema húmedo es accionado por:", opts:["La energía eléctrica del edificio","Solamente la presión/flujo de agua","Solamente una batería de respaldo","Aire comprimido"], re:"El gong de motor de agua es accionado hidráulicamente por el flujo de agua del sistema y no necesita electricidad, proporcionando una alarma mecánica audible. Fuente: QRFS 'How Does a Water Motor Gong Work.'"},
  {id:26, q:"¿Cuál de estas es una VENTAJA clave de los sistemas de tubería húmeda sobre otros tipos?", opts:["Simplicidad, confiabilidad, bajo mantenimiento y la entrega de agua más rápida","Son los más complejos mecánicamente","Nunca necesitan drenajes","Eliminan la necesidad de un suministro de agua"], re:"Los sistemas de tubería húmeda son los más simples y confiables, con la menor cantidad de componentes y la entrega de agua más rápida, razón por la cual son los más utilizados. Fuente: NFPA 'Types of Sprinkler Systems'; guía técnica de Engineered Fire Systems."},
  {id:27, q:"Para un edificio de oficinas pequeño y normalmente calefaccionado, ¿qué tipo de sistema suele ser la opción predeterminada y más económica?", opts:["Sistema de diluvio","Sistema de preacción de doble enclavamiento","Sistema de tubería húmeda","Sistema de tubería seca"], re:"En ocupaciones calefaccionadas, un sistema de tubería húmeda es normalmente la opción predeterminada — el más simple, barato y rápido. Los de tubería seca/preacción/diluvio se reservan para condiciones de congelación o de peligro especial. Fuente: orientación de selección de sistemas de la NFPA; guía de Engineered Fire Systems."},
  {id:28, q:"¿Qué permite hacer a un técnico un drenaje principal (típicamente de 2 pulg.) en el montante de tubería húmeda?", opts:["Agregar nitrógeno","Aumentar la presión del aire","Drenar el sistema y realizar una prueba de flujo de drenaje principal del suministro de agua","Anular permanentemente el preventor de retorno de flujo"], re:"El drenaje principal permite drenar el sistema y se usa para la prueba de drenaje principal que verifica la condición del suministro de agua. Fuente: prueba de drenaje principal de la NFPA 13/NFPA 25; componentes del montante."},
  {id:29, q:"Si un edificio calefaccionado tiene un área pequeña sin calefacción (como una marquesina de muelle de carga), una solución común de sistema húmedo para solo esa área es:", opts:["Convertir todo el edificio a diluvio","Retirar todos los rociadores de allí","Un bucle anticongelante o un rociador colgante seco/de pared seco derivado del sistema húmedo","Llenar la tubería del área con nitrógeno"], re:"Las áreas pequeñas expuestas a congelación derivadas de un sistema húmedo se sirven comúnmente con un bucle anticongelante listado o con rociadores colgantes secos/de pared secos que mantienen el agua atrás en el espacio calefaccionado. Fuente: disposiciones de anticongelante y rociadores secos de la NFPA 13; guía de rociadores secos de QRFS."},
  {id:30, q:"¿Por qué un sistema de tubería húmeda debe mantener un suministro continuo de agua a presión adecuada?", opts:["Para mantener el compresor de aire funcionando","Para evitar que las ampollas de vidrio se congelen","Para que cualquier rociador en operación reciba inmediatamente agua al flujo y presión requeridos","Para mantener cerrada la válvula de diluvio"], re:"La operación depende de que el suministro entregue el flujo/presión requeridos a los rociadores en operación; los cálculos hidráulicos confirman que el suministro satisface la demanda. Fuente: requisitos de suministro de agua y diseño hidráulico de la NFPA 13."},
  {id:31, q:"En un sistema de tubería húmeda, la conexión de prueba del inspector se usa para:", opts:["Agregar anticongelante al sistema","Presurizar el sistema con aire","Simular el flujo de un solo rociador para verificar que la alarma de flujo de agua opera","Probar la presión de mantenimiento de la bomba contra incendios"], re:"La conexión de prueba del inspector descarga agua a un flujo equivalente al orificio del rociador más pequeño para confirmar que la alarma de flujo de agua funciona. Fuente: conexión de prueba del inspector de la NFPA 13/NFPA 25."},
  {id:32, q:"¿Qué elemento térmico de rociador se mantiene cerrado por una cápsula de vidrio llena de líquido que se rompe cuando el líquido se expande?", opts:["Rociador de eslabón fusible","Dispositivo de apertura rápida","Rociador abierto (de diluvio)","Rociador de ampolla de vidrio"], re:"En un rociador de ampolla de vidrio, el líquido calentado se expande hasta que la ampolla se rompe, liberando la tapa. Los tipos de eslabón fusible en cambio usan una aleación de soldadura que se derrite. Fuente: sensibilidad térmica de rociadores de QRFS; operación de rociadores de NFSA."},
  {id:33, q:"El 'factor K' del rociador es una medida de la del rociador:", opts:["Color de la temperatura nominal","Tamaño de la rosca de la tubería","Coeficiente de descarga — que relaciona el caudal con la raíz cuadrada de la presión","Resistencia a la corrosión"], re:"El factor K es el coeficiente de descarga en Q = K√P; un factor K mayor deja pasar más agua a una presión dada. Fuente: principios hidráulicos de la NFPA 13; definición del factor K del rociador."},
  {id:34, q:"Los rociadores de pulverización estándar verticales y colgantes comúnmente tienen un factor K nominal de alrededor de:", opts:["K=1000","K=200","K=0.5","K=5.6 (alrededor de 80 en la familia de unidades de EE. UU., p. ej., K5.6/K8.0)"], re:"Los rociadores de orificio estándar son típicamente K5.6 (1/2 pulg.) o K8.0, muy por debajo de los cabezales ESFR de alto flujo (K14.2-K25.2). Fuente: tablas de rociadores de la NFPA 13; factores K de ESFR vs. estándar de CA-FIRE."},
  {id:35, q:"En un sistema de rociadores de tubería seca, la tubería por encima de la válvula de tubería seca normalmente está llena de:", opts:["Agua bajo presión","Aire o nitrógeno presurizado","Solución anticongelante","Concentrado de espuma"], re:"Los sistemas de tubería seca mantienen la tubería bajo aire o nitrógeno presurizado; el aire mantiene cerrada la válvula de tubería seca hasta que un rociador se abre. Fuente: definición de sistema de tubería seca de la NFPA 13; guía de sistemas secos de QRFS."},
  {id:36, q:"La razón PRINCIPAL para usar un sistema de tubería seca en lugar de un sistema de tubería húmeda es:", opts:["Entregar agua más rápido","Evitar la necesidad de un suministro de agua","Reducir la cantidad de rociadores","Proteger espacios sujetos a congelación donde el agua estancada sería un problema"], re:"Los sistemas de tubería seca se usan donde las temperaturas de congelación congelarían el agua en un sistema húmedo (almacenes sin calefacción, estacionamientos, congeladores, etc.). Fuente: NFPA 13; QRFS 'A Guide to Dry Sprinkler Systems.'"},
  {id:37, q:"En una válvula de tubería seca, una cantidad relativamente pequeña de presión de aire retiene una presión de agua mucho mayor. Esto se conoce como el de la válvula:", opts:["Pérdida por fricción","Residual","Carga de velocidad","Diferencial"], re:"La válvula de tubería seca usa un diseño diferencial: un área mayor del badajo del lado del aire permite que una presión de aire modesta retenga una presión de agua mayor (p. ej., una relación de ~5.5:1 o 6:1). Fuente: NFSA 'Determining Differential for Dry Pipe Valves.'"},
  {id:38, q:"Si una válvula diferencial de tubería seca tiene aproximadamente un diferencial de 6:1, entonces aproximadamente 1 psi de aire puede retener aproximadamente:", opts:["1 psi de agua","0.6 psi de agua","60 psi de agua","6 psi de agua"], re:"A un diferencial de 6:1, 1 psi de aire retiene aproximadamente 6 psi de agua (p. ej., 30 psi de aire retiene ~180 psi de agua). Fuente: válvula diferencial de tubería seca de Construction-manuals; artículo del diferencial de NFSA."},
  {id:39, q:"Cuando un rociador en un sistema de tubería seca se abre, la secuencia es:", opts:["El agua fluye instantáneamente sin demora","Un detector debe activarse antes de que el aire pueda escapar","El aire escapa primero, la válvula de tubería seca se activa, luego el agua fluye hacia el rociador abierto","La válvula de diluvio abre todos los rociadores"], re:"El rociador abierto purga el aire, la presión del sistema cae, se pierde el diferencial, el badajo se activa, y el agua luego viaja hacia el rociador abierto — inherentemente más lento que la tubería húmeda. Fuente: NFPA 13; operación de sistemas secos de QRFS."},
  {id:40, q:"Un DISPOSITIVO DE APERTURA RÁPIDA como un acelerador se agrega a un sistema de tubería seca para:", opts:["Acelerar la activación de la válvula de tubería seca apresurando la caída de presión de aire en la válvula","Ralentizar la entrega de agua","Agregar anticongelante automáticamente","Aumentar la presión de aire durante un incendio"], re:"Un acelerador detecta la caída de presión de aire y redirige el aire a la cámara intermedia de la válvula, igualando la presión para que el badajo se active antes — reduciendo el tiempo de entrega de agua. Fuente: Code Red Consultants 'Quick-Opening Devices'; guía de pruebas de activación de QRFS."},
  {id:41, q:"Según la NFPA 13, los sistemas de tubería seca generalmente deben entregar agua a la conexión de prueba del inspector dentro de cuántos segundos (con excepciones establecidas para sistemas pequeños/equipados con QOD)?", opts:["10 segundos","30 minutos","5 minutos","60 segundos"], re:"La NFPA 13 establece un tiempo máximo de entrega de agua de 60 segundos a la conexión de prueba, con excepciones para sistemas =500 gal, o =750 gal con un dispositivo de apertura rápida. Fuente: NFPA 13 (2019) 8.2.3; Sprinkler Age 'Dry Pipe Water Delivery Time.'"},
  {id:42, q:"Sin un dispositivo de apertura rápida, la NFPA 13 limita el volumen de un sistema individual de tubería seca a un máximo de aproximadamente:", opts:["100 galones","5,000 galones","500 galones","50 galones"], re:"La NFPA 13 limita un sistema seco individual a 500 gal sin un dispositivo de apertura rápida (y 750 gal con uno) para mantener tiempos de entrega aceptables. Fuente: NFPA 13 8.2.3.3/8.2.3.4; UpCodes 'Size of Systems.'"},
  {id:43, q:"Con un dispositivo de apertura rápida, la NFPA 13 permite un volumen de sistema individual de tubería seca de hasta un máximo de aproximadamente:", opts:["2,000 galones","250 galones","750 galones","100 galones"], re:"Con un dispositivo de apertura rápida, el tamaño máximo de sistema seco individual es 750 gal; por encima de eso, se aplican las tablas de tiempo de entrega. Fuente: NFPA 13 8.2.3.4; artículo de QOD de Code Red Consultants."},
  {id:44, q:"¿Por qué los sistemas de tubería seca son más susceptibles a la corrosión interna que los sistemas de tubería húmeda?", opts:["El aire atrapado más el agua/condensado residual crean condiciones ricas en oxígeno que promueven la corrosión","Usan solo cobre","Funcionan a mayor presión de agua","Contienen anticongelante"], re:"La mezcla de oxígeno atrapado (aire) con humedad/condensado residual acelera la corrosión interna; a menudo se usa nitrógeno en lugar de aire para reducirla. Fuente: orientación sobre corrosión de ORR Protection; consideraciones de corrosión de la NFPA 13."},
  {id:45, q:"El uso de NITRÓGENO en lugar de aire comprimido en un sistema seco ayuda principalmente al:", opts:["Bajar el punto de congelación del agua","Eliminar la necesidad de una válvula de tubería seca","Aumentar la presión del agua","Reducir la corrosión interna porque el nitrógeno es inerte (desplaza el oxígeno)"], re:"El nitrógeno es inerte y pobre en oxígeno, por lo que ralentiza la oxidación/corrosión que el aire comprimido promueve dentro de la tubería seca/de preacción. Fuente: ORR Protection; nota técnica sobre nitrógeno de United Fire Systems."},
  {id:46, q:"Debido a que el agua residual puede quedar atrapada después de una activación, la tubería seca debe tener inclinación (pendiente) de modo que:", opts:["El condensado y el agua drenen hacia la válvula de tubería seca o hacia los drenajes auxiliares (de punto bajo)","La presión de aire aumente automáticamente","Los rociadores apunten hacia arriba","La alarma no pueda sonar"], re:"La NFPA 13 requiere que la tubería seca/de preacción tenga inclinación para drenar hacia la válvula o los drenajes auxiliares de punto bajo, de modo que el agua atrapada no se congele. Distribuidores principales ~1/4 pulg./10 pies, ramales ~1/2 pulg./10 pies. Fuente: requisitos de pendiente de la NFPA 13; guía de pendiente de FPS-EG."},
  {id:47, q:"Un 'drum drip' (drenaje de tambor) o drenaje auxiliar en un punto bajo de un sistema seco se proporciona para:", opts:["Agregar nitrógeno al montante","Probar la bomba contra incendios","Acelerar el acelerador","Retirar periódicamente el condensado/agua acumulado de las secciones bajas atrapadas"], re:"Los drenajes auxiliares de punto bajo (drum drips) permiten a los técnicos purgar el condensado que se acumula en las secciones atrapadas, previniendo la congelación y la corrosión. Fuente: orientación sobre drenajes auxiliares de AGF Mfg; drenajes auxiliares de la NFPA 13."},
  {id:48, q:"La NFPA 13 generalmente requiere que el suministro de aire o nitrógeno restaure la presión normal del sistema dentro de aproximadamente cuánto tiempo después de una caída?", opts:["30 minutos","5 segundos","8 horas","3 días"], re:"El suministro de aire/nitrógeno debe poder restaurar la presión normal del sistema dentro de 30 minutos; un dispositivo de mantenimiento de aire regula la presión de reposición. Fuente: NFPA 13 8.2.6; QRFS 'Air Compressors and Air Maintenance Devices.'"},
  {id:49, q:"¿Cuál es la función de un DISPOSITIVO DE MANTENIMIENTO DE AIRE en un sistema de tubería seca?", opts:["Abre todos los rociadores","Regula el aire de reposición para que el sistema permanezca a la presión de supervisión adecuada sin sobrepresurizarse","Drena el sistema después de un incendio","Reemplaza la válvula de tubería seca"], re:"El dispositivo de mantenimiento de aire (regulador con restricción/derivación) repone pequeñas fugas para mantener correcta la presión de aire de supervisión, evitando un rellenado rápido que podría enmascarar una activación. Fuente: guía del dispositivo de mantenimiento de aire de QRFS; NFPA 13."},
  {id:50, q:"Una compensación clave (desventaja) de la tubería seca frente a los sistemas de tubería húmeda es:", opts:["Cuestan menos y son más simples","Entrega de agua demorada y mayor complejidad/mantenimiento (suministro de aire, drenajes, corrosión)","No pueden proteger áreas de congelación","No usan válvulas"], re:"Los sistemas secos sacrifican velocidad y simplicidad: el agua se demora, y agregan suministros de aire, drenajes de punto bajo y gestión de la corrosión. Fuente: NFPA 'Types of Sprinkler Systems'; guía de Engineered Fire Systems."},
  {id:51, q:"Después de que un sistema de tubería seca se activa y se restaura, ¿por qué es especialmente importante drenar prontamente el agua atrapada en un congelador o espacio bajo cero?", opts:["Porque el agua atrapada puede congelarse en minutos y dañar/bloquear la tubería","Para recargar la batería","Para reiniciar los detectores de humo","Para bajar la presión del suministro de agua"], re:"En espacios a/por debajo de 0°F, el agua atrapada puede comenzar a congelarse en minutos después de una activación, por lo que los puntos bajos deben drenarse prontamente. Fuente: prevención de congelación de AGF Mfg; drenaje de áreas de congelación de la NFPA 13."},
  {id:52, q:"Un sistema de rociadores de preacción puede considerarse una combinación de:", opts:["Un sistema húmedo y un montante de incendio","Un sistema de tubería seca más un sistema separado de detección de incendios que controla una válvula de preacción","Dos válvulas de diluvio en serie","Un bucle anticongelante y una bomba contra incendios"], re:"Los sistemas de preacción usan rociadores cerrados en tubería mantenida seca (aire/nitrógeno o supervisada) y un sistema de detección separado que abre la válvula de preacción, admitiendo agua. Fuente: NFPA 13; NFPA 'Types of Sprinkler Systems.'"},
  {id:53, q:"El beneficio PRINCIPAL de un sistema de preacción es que:", opts:["Reduce el riesgo de descarga accidental de agua donde el daño por agua sería especialmente costoso","Descarga agua de todos los cabezales a la vez","Elimina la necesidad de rociadores","Entrega agua más rápido que un sistema húmedo"], re:"Al requerir un evento (detección y/o operación del rociador) antes de que el agua entre en la tubería, la preacción protege contra la descarga accidental en espacios como centros de datos, archivos y museos. Fuente: NFPA; descripción general de preacción de Impact Fire."},
  {id:54, q:"En un sistema de preacción de ENCLAVAMIENTO SIMPLE, el agua se admite en la tubería cuando:", opts:["El sistema de detección de incendios opera (un detector se activa)","Tanto un detector opera COMO un rociador se abre","Solo un rociador se abre sin detección","Se abre el drenaje principal"], re:"El enclavamiento simple admite agua al operar el sistema de detección (un evento); los rociadores cerrados luego se descargan a medida que se abren. Fuente: NFPA 13; orientación sobre enclavamiento simple/doble de SF-Fire."},
  {id:55, q:"En un sistema de preacción de DOBLE ENCLAVAMIENTO, el agua se admite en la tubería solo cuando:", opts:["Un detector O un rociador opera (cualquiera de los dos)","El panel de alarma pierde energía","El compresor de aire arranca","TANTO el sistema de detección opera COMO un rociador se abre"], re:"El doble enclavamiento requiere dos eventos independientes — detección Y operación del rociador (pérdida de aire) — antes de que entre el agua, brindando la máxima protección contra la descarga accidental (común en congeladores). Fuente: NFPA 13; orientación sobre doble enclavamiento de SF-Fire."},
  {id:56, q:"En un sistema de preacción SIN ENCLAVAMIENTO, el agua se admite en la tubería cuando:", opts:["Solo se reinicia el panel de alarma","Tanto la detección COMO el rociador deben operar","El sistema de detección opera O un rociador se abre","El sistema se drena"], re:"El sistema sin enclavamiento admite agua al operar la detección O los rociadores (cualquier evento), por lo que incluso la sola operación del rociador (sin detección) permitirá que entre el agua. Fuente: NFPA 13; comparación de enclavamientos de SF-Fire."},
  {id:57, q:"¿Qué aplicación es un uso CLÁSICO para un sistema de preacción debido a la sensibilidad al daño por agua?", opts:["Un centro de datos / sala de computadoras o un archivo de libros raros","Un estacionamiento abierto","Un muelle de carga exterior","Una terraza de piscina"], re:"Los sistemas de preacción son preferidos para centros de datos, salas de telecomunicaciones, archivos, bibliotecas y museos donde una descarga accidental sería muy dañina. Fuente: NFPA; aplicaciones de preacción de Impact Fire."},
  {id:58, q:"Para propósitos de entrega de agua, un sistema de preacción de DOBLE ENCLAVAMIENTO se trata generalmente como un:", opts:["Sistema de tubería seca (entrega demorada; área de diseño mayor)","Sistema de tubería húmeda","Sistema de diluvio con cabezales abiertos","Montante de incendio"], re:"Debido a que la tubería está seca y se requieren ambos eventos, los sistemas de doble enclavamiento se tratan como sistemas de tubería seca para el tiempo de entrega y usan un área de diseño mayor. Fuente: NFPA 13; discusión sobre preacción de BERMAD/phcppros."},
  {id:59, q:"La NFPA 13 limita la cantidad de rociadores automáticos controlados por una sola válvula de preacción a aproximadamente:", opts:["10 rociadores","1,000 rociadores","100,000 rociadores","25 rociadores"], re:"La NFPA 13 limita una sola válvula de preacción (de enclavamiento) a aproximadamente 1,000 rociadores automáticos. Fuente: NFPA 13; notas de diseño de preacción de NY-Engineers / NFSA."},
  {id:60, q:"Un sistema de DILUVIO difiere fundamentalmente de los sistemas húmedo, seco y de preacción porque usa:", opts:["Solo rociadores de ampolla de vidrio","Anticongelante en cada línea","Rociadores/boquillas ABIERTOS (sin elemento térmico) en la tubería","Una cámara de retardo en lugar de una válvula"], re:"En un sistema de diluvio todos los rociadores/boquillas están ABIERTOS (sin elemento sensible al calor); cuando la válvula de diluvio se abre, el agua fluye de cada cabezal simultáneamente. Fuente: NFPA 13; NFPA 'Types of Sprinkler Systems.'"},
  {id:61, q:"Un sistema de diluvio descarga agua mediante:", opts:["Cada rociador abriéndose individualmente al calentarse","Purgando aire a través de un acelerador","Derritiendo un eslabón fusible en un cabezal","La apertura de la válvula de diluvio (mediante un sistema de detección), inundando todos los cabezales abiertos a la vez"], re:"Un sistema de detección (calor/llama/humo) abre la válvula de diluvio, y debido a que todos los cabezales están abiertos, el agua se descarga de todo el sistema simultáneamente. Fuente: NFPA 13; descripciones generales de diluvio de VFP/Oliver."},
  {id:62, q:"Los sistemas de diluvio se usan típicamente en qué tipo de peligro?", opts:["Áreas de alto peligro con potencial de propagación rápida del fuego (hangares de aviones, áreas de líquidos inflamables/químicos, plantas de energía)","Oficinas de bajo peligro","Dormitorios residenciales","Archivos refrigerados"], re:"Los sistemas de diluvio son adecuados para incendios de alto peligro y propagación rápida — hangares de aviones (a menudo de agua-espuma según la NFPA 409), instalaciones de líquidos inflamables y químicos, y plantas de energía. Fuente: NFPA; aplicaciones de diluvio de Oliver/Interstate."},
  {id:63, q:"¿Qué controla principalmente cuándo se descarga un sistema de diluvio?", opts:["Un sistema separado de detección de incendios que señala a la válvula de diluvio que se abra","La temperatura nominal de los cabezales individuales","El punto de congelación del agua","La inclinación de la tubería"], re:"Debido a que los cabezales no tienen elemento térmico, el momento de la descarga está determinado enteramente por el sistema de detección separado que abre la válvula de diluvio. Fuente: NFPA 13; fundamentos del sistema de diluvio."},
  {id:64, q:"En un hangar de aviones, un sistema de diluvio se combina frecuentemente con qué agente para el control de incendios de líquidos inflamables?", opts:["Espuma contra incendios (diluvio de agua-espuma)","Polvo químico seco","Inundación de dióxido de carbono","Gas de agente limpio"], re:"Los grandes hangares de aviones comúnmente usan sistemas de diluvio de agua-espuma (según la NFPA 409) para combatir incendios de derrame de combustible sobre grandes áreas de piso. Fuente: NFPA 409; referencias de diluvio de agua-espuma (Security Fire / estudio de hangares de DTIC)."},
  {id:65, q:"¿Por qué los sistemas de preacción y diluvio se consideran MÁS complejos e intensivos en mantenimiento que los sistemas de tubería húmeda?", opts:["Usan menos piezas","Dependen de un sistema de detección separado y válvulas especiales que deben probarse y mantenerse","No tienen válvulas en absoluto","Nunca requieren ninguna prueba"], re:"Ambos dependen de equipos de detección y válvulas especiales (preacción/diluvio), agregando componentes, cableado y pruebas periódicas más allá de un simple sistema húmedo. Fuente: NFPA 13/NFPA 25; referencias de comparación de sistemas."},
  {id:66, q:"En comparación con un sistema de preacción de enclavamiento simple, un sistema de doble enclavamiento generalmente proporciona:", opts:["Entrega de agua más rápida","Sin requisito de detección","Cabezales de rociadores abiertos","Mayor protección contra la descarga accidental pero entrega de agua más lenta"], re:"Requerir tanto la detección como la operación del rociador maximiza la protección contra el flujo de agua inadvertido pero demora la entrega (se trata como tubería seca). Fuente: NFPA 13; comparación de enclavamientos de SF-Fire."},
  {id:67, q:"En un sistema de preacción, los rociadores cerrados se instalan típicamente en tubería que está:", opts:["Siempre llena de agua en todo momento","Llena de concentrado de espuma","Normalmente seca / supervisada (monitoreo con aire o presurizado), con el agua retenida por la válvula de preacción","Llena de anticongelante en cada ramal"], re:"La tubería de preacción está normalmente seca (a menudo supervisada con aire/nitrógeno de baja presión), y el agua es retenida por la válvula de preacción hasta que ocurre el evento de control. Fuente: NFPA 13; guía de diseño de preacción de Reliable."},
  {id:68, q:"Las boquillas abiertas de un sistema de diluvio dispuestas para aplicar agua sobre un área u objeto definido se usan a menudo para:", opts:["Distribución de agua potable","Enfriar/proteger equipo como transformadores o cabinas de pintura","Calentar el edificio","Reemplazar la alarma contra incendios"], re:"Los sistemas de diluvio/pulverización de agua aplican agua sobre una superficie u objeto (transformadores, recipientes, cabinas de pintura) para control, enfriamiento o protección contra exposición. Fuente: pulverización de agua de la NFPA 15 / aplicaciones de diluvio de la NFPA 13."},
  {id:69, q:"La tubería vertical en la fuente de un sistema de rociadores, donde generalmente se ubican la válvula de control principal y los dispositivos de alarma, se denomina:", opts:["Ramal","Montante","Distribuidor transversal","Bajante (drop nipple)"], re:"El montante es la tubería vertical de suministro que lleva el agua hacia arriba al sistema; el conjunto del montante típicamente contiene la válvula de control principal, la válvula de retención/alarma, los manómetros y los drenajes. Fuente: componentes del sistema de la NFPA 13; Capitol Fire 'Fire Sprinkler Parts.'"},
  {id:70, q:"En la disposición de la tubería de rociadores, las tuberías a las que los rociadores mismos están directamente conectados son los:", opts:["Distribuidores transversales","Ramales","Distribuidores de alimentación","Montantes"], re:"Los ramales son las tuberías que portan los rociadores; los ramales se conectan a los distribuidores transversales, que son alimentados por los distribuidores de alimentación desde el montante. Fuente: terminología de tuberías de la NFPA 13."},
  {id:71, q:"La tubería que suministra agua a los distribuidores transversales (que a su vez alimentan los ramales) es el:", opts:["Distribuidor de alimentación","Bajante (drop)","Subida (sprig)","Brazo (armover)"], re:"Los distribuidores de alimentación suministran a los distribuidores transversales; los distribuidores transversales suministran a los ramales; los ramales portan los rociadores. Fuente: terminología de tuberías / disposición del sistema de la NFPA 13."},
  {id:72, q:"Una CONEXIÓN DEL CUERPO DE BOMBEROS (FDC) en un sistema de rociadores permite al cuerpo de bomberos:", opts:["Drenar el sistema al alcantarillado","Probar los detectores de humo","Cerrar la red principal de agua municipal","Bombear agua/presión adicional al sistema desde su aparato"], re:"La FDC permite a los aparatos que responden aumentar el agua y la presión en el sistema de rociadores/montantes para complementar el suministro. Fuente: FDC de la NFPA 13/NFPA 14; guía de componentes de QRFS."},
  {id:73, q:"Una VÁLVULA DE RETENCIÓN en un sistema de rociadores contra incendios funciona para:", opts:["Reducir la temperatura del agua","Abrir todos los rociadores","Permitir el flujo de agua en una sola dirección y prevenir el retorno de flujo","Agregar aire al sistema"], re:"Una válvula de retención permite el flujo en una dirección y previene el flujo inverso (p. ej., evitando que el agua del sistema regrese al suministro). Fuente: QRFS 'Guide to Check Valves'; NFPA 13."},
  {id:74, q:"La válvula de control principal del sistema (p. ej., una válvula indicadora OS&Y o de mariposa) debe ser:", opts:["Oculta y sin marcar","Retirada durante un incendio","Una válvula indicadora listada que muestra si está abierta o cerrada, y supervisada/asegurada abierta","Pintada para combinar con la pared"], re:"Las válvulas de control deben ser válvulas indicadoras listadas cuya posición abierta/cerrada sea visible, y deben estar supervisadas o bloqueadas abiertas para que el suministro no se cierre inadvertidamente. Fuente: válvulas de control de la NFPA 13; supervisión de válvulas de la NFPA 25."},
  {id:75, q:"Una alarma de flujo de agua/interruptor de presión en un montante de rociadores se usa para:", opts:["Regular la concentración de anticongelante","Detectar el agua que se mueve en el sistema y enviar una señal eléctrica de alarma","Presurizar la válvula de tubería seca","Reducir la presión de suministro"], re:"Un interruptor de flujo de agua (presión) detecta el flujo en el montante y transmite una señal eléctrica al panel de alarma/campana para indicar la operación del sistema. Fuente: alarma de flujo de agua de la NFPA 13/NFPA 72; componentes del montante."},
  {id:76, q:"Los manómetros del sistema de rociadores en el montante típicamente muestran:", opts:["La temperatura exterior","La cantidad de rociadores instalados","El color del anticongelante","La presión de agua del sistema y del suministro (y la presión de aire en los sistemas secos/de preacción)"], re:"Los manómetros del montante muestran la presión de suministro y del sistema (y en los montantes secos/de preacción, la presión de aire/nitrógeno por encima de la válvula). Fuente: manómetros de la NFPA 13; componentes del conjunto del montante."},
  {id:77, q:"Un rociador COLGANTE se instala de modo que:", opts:["Apunta hacia arriba por encima del ramal","No tiene deflector","Pulveriza lateralmente desde una pared","Cuelga por debajo de la tubería/techo y pulveriza agua hacia abajo en un patrón circular"], re:"Un rociador colgante cuelga por debajo de la tubería/techo con su deflector en la parte inferior, distribuyendo el agua hacia abajo y hacia afuera sobre el área del piso. Fuente: QRFS 'Fire Sprinkler Head Types'; posición del deflector de la NFPA 13."},
  {id:78, q:"Un rociador VERTICAL (upright) se instala de modo que:", opts:["Se asienta por encima del ramal y pulveriza agua hacia arriba a su deflector, que la redirige hacia abajo","Cuelga por debajo de la tubería","Se monta horizontalmente en una pared","Descarga solo hacia arriba"], re:"Un rociador vertical se asienta por encima del ramal; el agua golpea el deflector montado arriba y se redirige hacia abajo en un patrón hemisférico/de abanico (útil donde la tubería está expuesta). Fuente: tipos de cabezales de rociadores de QRFS; NFPA 13."},
  {id:79, q:"Un rociador DE PARED (sidewall) se usa para:", opts:["Descargar solo directamente hacia abajo desde el centro de una habitación","Drenar el sistema","Reemplazar la válvula de tubería seca","Montarse en una pared y arrojar agua horizontalmente a través de una habitación (útil donde la tubería superior es impráctica)"], re:"Los rociadores de pared se montan en una pared/viga y proyectan agua horizontalmente con un deflector asimétrico, usados donde la tubería de techo es impráctica (pasillos, habitaciones pequeñas). Fuente: rociadores de pared de QRFS; NFPA 13."},
  {id:80, q:"El COLOR de un rociador de ampolla de vidrio (p. ej., rojo, naranja, verde) indica principalmente su:", opts:["Temperatura nominal","Fabricante","Tamaño de la rosca de la tubería","Factor K exactamente"], re:"El color del líquido de la ampolla de vidrio indica la temperatura nominal (p. ej., naranja ~135°F, rojo ~155°F, verde ~200°F); los tipos de eslabón fusible usan un código de color en el brazo del marco. Fuente: temperaturas nominales de la NFPA 13; colores de rociadores de NFSA."},
  {id:81, q:"Un rociador con temperatura nominal 'ordinaria' típicamente opera en qué rango aproximado?", opts:["32°F a 60°F","500°F a 650°F","135°F a 170°F","1000°F y superior"], re:"Los rociadores de temperatura nominal ordinaria operan aproximadamente de 135-170°F; la intermedia es de ~175-225°F, con clases superiores para entornos más calientes. Fuente: temperaturas nominales de la NFPA 13; tablas de temperatura de TPMC/Kord."},
  {id:82, q:"La tubería y los componentes del sistema de rociadores instalados sobre el suelo comúnmente están clasificados para una presión de trabajo máxima de al menos:", opts:["175 psi","50 psi","1,000 psi","10 psi"], re:"Los componentes sobre el suelo de la NFPA 13 generalmente están clasificados para una presión de trabajo de 175 psi (se requieren componentes de mayor presión donde las presiones exceden eso). Fuente: clasificación de componentes de la NFPA 13; discusión sobre presión de Eng-Tips/NFPA 13."},
  {id:83, q:"La nueva tubería de rociadores se prueba hidrostáticamente según la NFPA 13 a 200 psi, o a qué nivel si la presión de trabajo es mayor?", opts:["Exactamente a la presión de trabajo","A 500 psi sin importar","A 10 psi por debajo de la presión de trabajo","A 50 psi por encima de la presión de trabajo máxima del sistema"], re:"La NFPA 13 requiere una prueba hidrostática de 2 horas a 200 psi, o a 50 psi por encima de la presión de trabajo máxima cuando esta excede 150 psi, lo que sea mayor. Fuente: prueba hidrostática de la NFPA 13; guía de pruebas de Fire Safety Central."},
  {id:84, q:"Un conjunto de prevención de retorno de flujo se instala en muchos sistemas de rociadores principalmente para:", opts:["Aumentar el flujo del rociador","Proteger el suministro de agua público/potable de la contaminación por el agua del sistema","Acelerar la válvula de tubería seca","Reemplazar la función de alarma de la válvula de retención del montante"], re:"Los preventores de retorno de flujo evitan que el agua del sistema, potencialmente estancada o tratada, regrese al suministro potable, protegiendo la salud pública (requerido por muchas empresas de agua/códigos). Fuente: reglas de conexión cruzada de la NFPA 13 / empresa de agua local."},
  {id:85, q:"¿Cuál es el título y propósito de la NFPA 13?", opts:["Norma para Extintores Portátiles de Incendios","Norma para Sistemas de Alarma contra Incendios","Código Eléctrico Nacional","Norma para la Instalación de Sistemas de Rociadores — que proporciona requisitos mínimos para el diseño y la instalación"], re:"La NFPA 13 es la 'Norma para la Instalación de Sistemas de Rociadores', dando requisitos mínimos de diseño/instalación para proteger la vida y la propiedad. Fuente: alcance/propósito de la NFPA 13; página del producto de la NFPA."},
  {id:86, q:"La NFPA 13 tiene el alcance MÁS AMPLIO de las normas de instalación porque:", opts:["Se aplica solo a casas unifamiliares","Solo cubre edificios de gran altura","Solo cubre almacenes","Puede usarse para instalar rociadores en virtualmente cualquier tipo de edificio/ocupación"], re:"Cualquier edificio puede protegerse bajo la NFPA 13; la NFPA 13R y la 13D son normas residenciales más estrechas. Fuente: NFPA 'Differences Between NFPA 13, 13R, and 13D.'"},
  {id:87, q:"La NFPA 13D es la norma para sistemas de rociadores en:", opts:["Viviendas de una y dos familias y casas prefabricadas","Torres de oficinas de gran altura","Hangares de aviones","Plantas químicas"], re:"La NFPA 13D cubre viviendas de una y dos familias y casas prefabricadas (y ciertas casas adosadas), enfocada en la seguridad de vida/escape. Fuente: alcance de la NFPA 13D; comparación NFPA 13 vs 13R vs 13D."},
  {id:88, q:"La NFPA 13R es la norma para sistemas de rociadores en ocupaciones residenciales de hasta:", opts:["Cuarenta pisos","Cuatro pisos de altura (y no más de 60 pies)","Solo casas unifamiliares","Solo subterráneo"], re:"La NFPA 13R se aplica a ocupaciones residenciales de hasta e incluyendo cuatro pisos (sin exceder 60 pies), p. ej., apartamentos de baja altura. Fuente: alcance de la NFPA 13R; artículo de comparación de la NFPA."},
  {id:89, q:"Un OBJETIVO central de seguridad de vida de un sistema residencial NFPA 13D es:", opts:["Ayudar a prevenir el flashover en la habitación de origen para que los ocupantes puedan escapar","Proteger la estructura durante muchas horas","Descargar de todos los rociadores a la vez","Reemplazar las alarmas de humo"], re:"La NFPA 13D busca controlar un incendio y prevenir el flashover el tiempo suficiente para que los ocupantes escapen, priorizando la seguridad de vida sobre la protección de la propiedad. Fuente: objetivos de la NFPA 13D; artículo de comparación de la NFPA."},
  {id:90, q:"La NFPA 13 clasifica las ocupaciones por peligro. Las tres amplias clases de peligro de ocupación son:", opts:["Húmeda, seca y de preacción","Peligro ligero, peligro ordinario y peligro extra","Clase A, B y C","Residencial, comercial e industrial"], re:"Las clases de peligro de ocupación de la NFPA 13 son Ligero, Ordinario y Extra; Ordinario y Extra cada una se divide en Grupo 1 y Grupo 2. Fuente: NFPA 13 Capítulo 4; NFPA 'Occupancy Classifications in NFPA 13.'"},
  {id:91, q:"¿Qué ocupación es un ejemplo de PELIGRO LIGERO bajo la NFPA 13?", opts:["Una oficina, iglesia o aula escolar","Una operación de pintura/acabado por pulverización","Una planta de fabricación de neumáticos","Una refinería de petróleo"], re:"Peligro ligero = contenidos de baja cantidad/combustibilidad: oficinas, iglesias, escuelas, hospitales, museos, la mayoría de las residencias. Fuente: ejemplos de peligro ligero de la NFPA 13; artículo de ocupación de phcppros."},
  {id:92, q:"Las ocupaciones de Peligro Ordinario (Grupo 1 o 2) se caracterizan por:", opts:["Carga combustible/combustibilidad moderada (p. ej., lavanderías, talleres mecánicos, comercios)","Combustibles insignificantes","Solo líquidos inflamables","Sin contenidos en absoluto"], re:"El peligro ordinario cubre combustibilidad/cantidad moderada: OH-1 (p. ej., estacionamientos, lavanderías, servicio de restaurantes) y OH-2 (p. ej., talleres mecánicos, comercios, carpintería). Fuente: clases de ocupación de la NFPA 13; blog de la NFPA."},
  {id:93, q:"Las ocupaciones de Peligro Extra bajo la NFPA 13 involucran:", opts:["La menor severidad de incendio","Solo áticos vacíos","Alta carga combustible/inflamable o procesos (p. ej., pintura por pulverización, líquidos inflamables, cierta fabricación)","Solo espacios de oficina"], re:"Peligro extra = altas cantidades de combustibles y/o líquidos inflamables: EH-1 (p. ej., impresión, ciertos textiles) y EH-2 (p. ej., pintura por pulverización, manejo de líquidos inflamables). Fuente: ejemplos de peligro extra de la NFPA 13; blog de la NFPA."},
  {id:94, q:"¿Por qué importa clasificar correctamente el peligro de ocupación para el diseño de rociadores?", opts:["Establece el color de pintura de la tubería","No tiene efecto sobre el diseño","Decide el fabricante de la ampolla del rociador","Determina la densidad/área de diseño requerida y la demanda de agua del sistema"], re:"El peligro de ocupación impulsa la densidad de diseño y el área de diseño (y por lo tanto la demanda de agua); un peligro mayor requiere más agua sobre un área mayor. Fuente: enfoques de diseño de la NFPA 13; reglas de diseño de clasificación de peligro."},
  {id:95, q:"Además del peligro de ocupación, la NFPA 13 clasifica separadamente los bienes almacenados usando:", opts:["Códigos de color de rociadores","Clases de montantes","Números de cédula de tubería","Clasificaciones de mercancías (p. ej., Clase I-IV y plásticos)"], re:"La protección de almacenamiento usa clasificaciones de mercancías (Clase I-IV y varios plásticos/caucho) además del peligro de ocupación para establecer los criterios de rociadores de almacenamiento. Fuente: capítulo de clasificación de mercancías de la NFPA 13; guía de mercancías de Koorsen."},
  {id:96, q:"Un rociador ESFR (Supresión Temprana de Respuesta Rápida) está diseñado principalmente para:", opts:["Controlar incendios solamente, nunca suprimir","Proteger solo oficinas de peligro ligero","Suprimir rápidamente incendios de almacenamiento de alto desafío, a menudo evitando rociadores en estanterías","Operar todos los cabezales simultáneamente como un diluvio"], re:"El ESFR usa cabezales de factor K alto y respuesta rápida para SUPRIMIR (no solo controlar) incendios de almacenamiento, a menudo eliminando los rociadores en estanterías. Fuente: diseño ESFR de la NFPA 13; descripción general de ESFR de Precision FP / CA-FIRE."},
  {id:97, q:"Un sistema de montante de incendio (NFPA 14) proporciona principalmente:", opts:["Anticongelante a los rociadores","Tubería y conexiones de manguera para que los bomberos/ocupantes puedan aplicar chorros de manguera dentro de un edificio","Presión de aire a los sistemas secos","Solo prevención de retorno de flujo"], re:"Los montantes de incendio son tuberías verticales/horizontales con conexiones de válvula de manguera que suministran agua para la lucha manual contra incendios dentro de los edificios (especialmente edificios de gran altura). Fuente: sistemas de montantes de la NFPA 14; blog de diseño de montantes de la NFPA."},
  {id:98, q:"Un montante de incendio CLASE I (NFPA 14) proporciona qué conexión de manguera, destinada al cuerpo de bomberos?", opts:["Manguera de jardín de 1 pulgada","Conexiones de manguera de 2½ pulgadas","Sin conexiones de manguera","Conexión de prueba de ½ pulgada"], re:"Los montantes Clase I proporcionan conexiones de 2½ pulg. para uso del cuerpo de bomberos; la Clase II proporciona 1½ pulg. para los ocupantes; la Clase III proporciona ambas. Fuente: NFPA 14; clases de montantes de CA-FIRE / J.F. Ahern."},
  {id:99, q:"Bajo la NFPA 13, el anticongelante usado en los NUEVOS sistemas de rociadores debe ser:", opts:["Cualquier anticongelante automotriz doméstico","Agua salada","Glicerina pura a cualquier concentración","Una solución anticongelante listada, premezclada de fábrica"], re:"La NFPA 13 ahora requiere anticongelante listado, premezclado de fábrica para nuevos sistemas; la glicerina/propilenglicol mezclada en campo a la antigua puede actuar como combustible a altas concentraciones y ya no se permite para nuevas instalaciones. Fuente: anticongelante de la NFPA 13 7.6; orientación sobre anticongelante listado de NFSA."},
  {id:100, q:"En California, ¿qué clasificación de la CSLB cubre el trabajo de protección contra incendios a base de agua (rociadores y montantes)?", opts:["C-10 Eléctrico","C-16 Contratista de Protección contra Incendios","C-36 Plomería","C-20 Climatización (HVAC)"], re:"La clasificación C-16 de Protección contra Incendios cubre el trazado, la fabricación y la instalación de sistemas de protección contra incendios, incluyendo los sistemas de rociadores y montantes a base de agua (el trabajo eléctrico de alarmas corresponde al C-10). Fuente: descripción de la clasificación C-16 de la CSLB; guía de estudio C-16 de la CSLB."},
  {id:101, q:"En un rociador colgante (pendent), ¿dónde se ubica el deflector respecto al conducto de agua y hacia dónde se dirige el rociado?", opts:["Por debajo del orificio, rociado dirigido hacia abajo","Por encima del orificio, rociado dirigido hacia arriba","Al lado del orificio, rociado dirigido lateralmente","Detrás del orificio, rociado dirigido hacia atrás"], re:"Un rociador colgante cuelga hacia abajo desde la tubería con el deflector por debajo del conducto de agua, de modo que el agua descargada lo golpea y forma un patrón en forma de paraguas hacia abajo. Fuente: definiciones de rociadores de NFPA 13; referencias de tipos de rociadores."},
  {id:102, q:"Un rociador de rociado montante (SSU) se instala de modo que el agua se descarga en qué dirección antes de ser dispersada por el deflector?", opts:["Hacia arriba contra el deflector, luego dispersada hacia abajo","Horizontalmente a lo largo del techo primero","Recto hacia abajo sin acción del deflector","Hacia la tubería para acumular presión"], re:"Un rociador montante se ubica por encima de la línea ramal; el agua se lanza hacia arriba contra el deflector, que luego la dispersa hacia abajo sobre el área. Fuente: NFPA 13; referencias de rociador SSU (Standard Spray Upright, rociado montante estándar)."},
  {id:103, q:"Un rociador lateral (sidewall) se usa principalmente en qué situación?", opts:["Donde la tubería no puede recorrer el techo, descargando desde una pared","En congeladores para evitar la congelación de la cabeza","Solo en el montante como conexión de prueba","Exclusivamente en aplicaciones de almacenamiento ESFR"], re:"Los rociadores laterales proyectan el agua hacia afuera desde una pared y se usan en habitaciones (corredores, habitaciones de hotel) donde no es práctico recorrer líneas ramales por el techo. Fuente: disposiciones de rociadores laterales de NFPA 13."},
  {id:104, q:"En un conjunto de rociador oculto (concealed), ¿qué oculta el rociador de la vista y qué le sucede en un incendio?", opts:["Un domo de vidrio que se rompe a 1000°F","Una protección metálica que retira el cuerpo de bomberos","Una placa cubierta que se desprende a una temperatura menor que la del rociador","Una tapa plástica que el ocupante debe retirar manualmente"], re:"Un rociador oculto se esconde mediante una placa cubierta decorativa sostenida por soldadura clasificada para liberarse a una temperatura menor que la del propio rociador, de modo que la placa cae primero y permite que la cabeza funcione. Fuente: NFPA 13; listados de rociador oculto/placa cubierta."},
  {id:105, q:"La placa cubierta de un rociador oculto está listada para liberarse a una temperatura que es cuál de las siguientes en relación con la temperatura de operación del rociador?", opts:["Menor, para que la placa caiga antes de que la cabeza funcione","Mayor, para que la cabeza funcione antes de que caiga la placa","Idéntica, para que funcionen en el mismo instante","Sin relación y elegida al azar por el instalador"], re:"Las placas cubiertas tienen una clasificación menor (comúnmente al menos unos 20°F más fría) que el rociador, para que la placa caiga primero y no bloquee la operación; clasificaciones como 135°F y 165°F son comunes. Fuente: NFPA 13; listados de temperatura de placas cubiertas."},
  {id:106, q:"¿Qué significan las siglas ESFR?", opts:["Early Suppression Fast Response (supresión temprana respuesta rápida)","Extended Spray Fire Response","Enhanced Storage Fire Resistance","Elevated Sidewall Flow Rate"], re:"ESFR = Early Suppression Fast Response (supresión temprana respuesta rápida), un rociador diseñado para suprimir (no solo controlar) incendios de almacenamiento de alto desafío mediante gotas de alto impulso y un elemento de respuesta rápida. Fuente: capítulo de rociadores ESFR de NFPA 13."},
  {id:107, q:"Los rociadores ESFR se aplican más comúnmente en qué tipo de ocupación?", opts:["Oficinas y escuelas de riesgo ligero","Solo estacionamientos abiertos","Almacenamiento de gran altura y ocupaciones de bodega","Solo viviendas unifamiliares residenciales"], re:"Los rociadores ESFR están destinados a incendios de alto desafío, como bodegas de almacenamiento en estiba/estanterías de gran altura, donde pueden suprimir el incendio en el techo sin rociadores en estantería en muchas distribuciones. Fuente: disposiciones de almacenamiento/ESFR de NFPA 13."},
  {id:108, q:"Un rociador colgante seco (de tipo seco, dry-pendent) se usa específicamente en qué aplicación?", opts:["Donde la cabeza se extiende a un espacio no calefaccionado/congelante desde una tubería húmeda calefaccionada","Solo en salas de almacenamiento en estantería ESFR","Como la cabeza estándar para oficinas de riesgo ligero","En la entrada de la conexión del cuerpo de bomberos"], re:"Un rociador colgante seco tiene un tubo de caída sellado que mantiene el agua fuera de la cabeza, permitiendo que un rociador sirva a un congelador o área no calefaccionada mientras está conectado a un sistema húmedo en un espacio calefaccionado. Fuente: NFPA 13; listados de rociadores secos."},
  {id:109, q:"Los rociadores residenciales (según NFPA 13D/13R) deben ser de qué tipo de respuesta?", opts:["Respuesta rápida (quick/fast)","Solo respuesta estándar","Solo de alta temperatura","No listados de cualquier tipo"], re:"Los rociadores residenciales son dispositivos listados de respuesta rápida diseñados para mojar paredes y mejorar la habitabilidad para el escape de los ocupantes; las cabezas de respuesta estándar no cumplen con el listado residencial. Fuente: requisitos de rociadores residenciales de NFPA 13D/13R."},
  {id:110, q:"¿Cuál es el propósito principal del deflector en un rociador de rociado?", opts:["Romper el chorro de agua en un patrón de distribución definido","Sostener la ampolla de vidrio en su lugar durante el envío","Detectar el calor y activar el rociador","Conectar el rociador a la línea ramal"], re:"El deflector es la placa que el chorro descargado golpea; su forma y orientación rompen el agua en el patrón de rociado listado (paraguas, lateral, ESFR, etc.). Fuente: definiciones de rociadores de NFPA 13."},
  {id:111, q:"Un rociador empotrado (recessed) se diferencia de un rociador a ras (flush) u oculto (concealed) en que:", opts:["Se instala con parte del cuerpo en un escudete empotrado pero con el elemento de operación aún expuesto","Se monta completamente por encima del techo sin cabeza expuesta","Es siempre una cabeza montante en un pozo","Es una cabeza sin deflector"], re:"Un rociador empotrado se ubica parcialmente arriba en un escudete empotrado por estética, pero el elemento sensible al calor permanece en la habitación (a diferencia de una cabeza oculta escondida por una placa cubierta). Fuente: NFPA 13; listados de rociador empotrado/escudete."},
  {id:112, q:"¿Por qué se debe usar el escudete o la placa cubierta correctos con un rociador empotrado u oculto?", opts:["Debe ser parte del conjunto listado porque afecta la activación y el rociado","Es puramente decorativo y no tiene efecto en el rendimiento","Cualquier escudete puede sustituirse para ahorrar costo","Solo se requiere para rociadores montantes"], re:"Los escudetes y las placas cubiertas son parte del conjunto de rociador listado; usar una pieza que no coincida puede cambiar la respuesta térmica de la cabeza y la distribución del agua. Fuente: requisitos de accesorios/listado de NFPA 13."},
  {id:113, q:"Un rociador montante generalmente se prefiere sobre uno colgante en qué situación?", opts:["Donde la tubería ramal está expuesta debajo del techo y la acumulación de polvo/obstrucciones es una preocupación","Solo en oficinas terminadas de techo liso","Donde la cabeza debe ocultarse de la vista","Solo en sistemas residenciales"], re:"Los montantes se prefieren en tuberías expuestas (p. ej., salas de máquinas, techos sin terminar) donde se ubican por encima de la tubería y son menos propensos a acumular escombros que una caída colgante podría. Fuente: NFPA 13; orientación de orientación de rociadores."},
  {id:114, q:"Un rociador colgante instalado en posición montante (o viceversa) crea qué problema?", opts:["Ningún problema, la orientación no importa","Cobertura más rápida y mejor","Un patrón de rociado incorrecto y no listado que puede no proteger el área","Conversión automática a una cabeza ESFR"], re:"Los deflectores están diseñados para una orientación específica; instalar un colgante como montante (o al revés) produce un patrón no listado y distorsionado, y no está permitido. Fuente: requisitos de instalación de rociadores de rociado de NFPA 13."},
  {id:115, q:"Las letras 'SSU' estampadas respecto a un rociador indican qué tipo?", opts:["Standard Spray Upright (rociado montante estándar)","Sidewall Storage Unit","Special Suppression Unit","Standard Sidewall Upright"], re:"SSU = Standard Spray Upright (rociado montante estándar); la designación complementaria SSP = Standard Spray Pendent (rociado colgante estándar). Fuente: nomenclatura del fabricante de rociadores/NFPA 13."},
  {id:116, q:"Un rociador abierto (usado en un sistema de diluvio) se diferencia de un rociador automático estándar porque:", opts:["Tiene una ampolla de vidrio más grande","Funciona solo a alta temperatura","No tiene elemento sensible al calor y siempre está abierto","Es siempre de tipo lateral"], re:"Los rociadores abiertos tienen el eslabón fusible/ampolla retirado, de modo que todas las cabezas descargan a la vez cuando se abre la válvula de diluvio; no se activan individualmente por el calor. Fuente: disposiciones de diluvio/rociador abierto de NFPA 13."},
  {id:117, q:"Los rociadores de cobertura extendida están listados para hacer cuál de las siguientes en comparación con los rociadores de rociado estándar?", opts:["Cubrir un área más pequeña solo a mayor presión","Funcionar solo como cabezas montantes","Cubrir un área de piso mayor por rociador cuando se instalan según su listado","Eliminar la necesidad de cualquier cálculo hidráulico"], re:"Los rociadores de cobertura extendida están específicamente listados y probados para proteger un área mayor por cabeza que los rociadores de rociado estándar, dentro de los límites de espaciado/presión de su listado. Fuente: disposiciones de rociadores de cobertura extendida de NFPA 13."},
  {id:118, q:"Según NFPA 13, la clasificación de temperatura ordinaria cubre qué rango de clasificación?", opts:["100°F a 130°F","175°F a 225°F","135°F a 170°F","250°F a 300°F"], re:"Los rociadores de temperatura ordinaria están clasificados de 135°F a 170°F (57°C a 77°C) y se usan en la mayoría de los espacios normalmente ocupados. Fuente: tabla de clasificaciones de temperatura de NFPA 13."},
  {id:119, q:"La clasificación de temperatura intermedia según NFPA 13 cubre qué rango de clasificación?", opts:["135°F a 170°F","250°F a 300°F","175°F a 225°F","325°F a 375°F"], re:"Los rociadores de temperatura intermedia están clasificados de 175°F a 225°F (79°C a 107°C), usados donde el calor ambiente está elevado (cerca de tragaluces, calefactores de unidad, etc.). Fuente: tabla de clasificaciones de temperatura de NFPA 13."},
  {id:120, q:"Una ampolla de vidrio de rociador llena de líquido NARANJA corresponde a qué clasificación de temperatura?", opts:["135°F","155°F","200°F","286°F"], re:"En el código de colores de NFPA para ampollas de vidrio, naranja = 135°F, rojo = 155°F, amarillo = 174°F, verde = 200°F, azul = 286°F, púrpura = 360°F. Fuente: referencias del código de colores de NFPA 13."},
  {id:121, q:"Una ampolla de vidrio de rociador llena de líquido ROJO corresponde a qué clasificación de temperatura?", opts:["135°F","200°F","155°F","360°F"], re:"El líquido rojo de la ampolla de vidrio indica un rociador de 155°F (68°C), la clasificación de temperatura ordinaria más común. Fuente: referencias del código de colores de NFPA 13."},
  {id:122, q:"Un rociador con ampolla de vidrio VERDE está clasificado para aproximadamente qué temperatura?", opts:["135°F","174°F","200°F","286°F"], re:"El líquido de ampolla verde = 200°F (93°C), una clasificación de temperatura intermedia. Fuente: código de colores de ampollas de vidrio de NFPA 13."},
  {id:123, q:"¿Qué representa la clasificación de temperatura de un rociador?", opts:["La altura del techo en pies","La presión de agua en psi","La temperatura nominal a la que opera el elemento sensible al calor","El tamaño de la tubería en pulgadas"], re:"La clasificación de temperatura es la temperatura nominal de operación del eslabón fusible o la ampolla de vidrio, seleccionada con un margen por encima de la temperatura ambiente máxima esperada. Fuente: selección de clasificación de temperatura de NFPA 13."},
  {id:124, q:"Para rociadores de temperatura ordinaria (135–170°F), NFPA 13 limita la temperatura ambiente máxima del techo a aproximadamente:", opts:["100°F","150°F","225°F","300°F"], re:"Las cabezas de clasificación ordinaria están limitadas a una temperatura máxima del techo de 100°F; por encima de eso se requiere una clasificación intermedia o superior para evitar la operación por molestia. Fuente: tabla de temperatura máxima del techo de NFPA 13."},
  {id:125, q:"Para rociadores de temperatura intermedia (175–225°F), la temperatura ambiente máxima permitida del techo es aproximadamente:", opts:["100°F","250°F","150°F","350°F"], re:"Los rociadores de clasificación intermedia se permiten hasta una temperatura máxima del techo de 150°F. Fuente: tabla de temperatura máxima del techo de NFPA 13."},
  {id:126, q:"La diferencia principal entre un rociador con ampolla de vidrio de Respuesta Rápida (QR) y uno de Respuesta Estándar (SR) de la misma temperatura es:", opts:["La ampolla QR es más delgada (unos 3 mm) para una respuesta térmica más rápida","La cabeza QR descarga más agua","La cabeza SR no tiene deflector","La cabeza QR siempre está clasificada para alta temperatura"], re:"QR y SR pueden compartir una clasificación de temperatura; la ampolla QR es de menor diámetro (≈3 mm vs ≈5 mm), por lo que se calienta y opera más rápido (RTI más bajo). Fuente: NFPA 13; referencias de respuesta/sensibilidad térmica de rociadores."},
  {id:127, q:"El RTI (Índice de Tiempo de Respuesta) es una medida de qué del rociador:", opts:["Coeficiente de descarga","Resistencia a la corrosión","Sensibilidad térmica (qué tan rápido responde al calor)","Presión de trabajo máxima"], re:"El RTI cuantifica la sensibilidad térmica del elemento de operación; un RTI más bajo significa una respuesta más rápida. Fuente: NFPA 13; referencias de sensibilidad térmica de rociadores."},
  {id:128, q:"Un rociador generalmente se clasifica como de respuesta rápida (quick/fast) cuando su RTI es aproximadamente:", opts:["50 (m·s)^1/2 o menos","Exactamente 100 (m·s)^1/2","200 (m·s)^1/2 o más","Sin relación con el RTI"], re:"Los rociadores de respuesta rápida tienen un RTI de aproximadamente 50 (m·s)^1/2 o menos; la respuesta estándar es de aproximadamente 80 (m·s)^1/2 o superior. Fuente: NFPA 13; referencias de clasificación de respuesta de rociadores."},
  {id:129, q:"Un rociador de respuesta estándar típicamente tiene un RTI de aproximadamente:", opts:["Menos de 20 (m·s)^1/2","Exactamente 50 (m·s)^1/2","80 (m·s)^1/2 o más","Valores negativos"], re:"Los rociadores de respuesta estándar tienen un RTI de aproximadamente 80 (m·s)^1/2 o mayor (respuesta térmica más lenta que la respuesta rápida). Fuente: NFPA 13; referencias de clasificación de respuesta de rociadores."},
  {id:130, q:"Los rociadores de respuesta rápida se asocian más con qué clasificación de riesgo?", opts:["Solo almacenamiento de gran altura","Solo plantas químicas de riesgo extra","Ocupaciones de riesgo ligero (oficinas, escuelas)","Solo muelles de carga al aire libre"], re:"Los rociadores QR se instalan predominantemente en ocupaciones de riesgo ligero, donde su respuesta más rápida mejora la seguridad de la vida. Fuente: NFPA 13; referencias de aplicación de QR."},
  {id:131, q:"En un rociador de eslabón fusible (de tipo soldadura), la clasificación de temperatura típicamente se indica mediante:", opts:["El color del agua en una ampolla","La forma del deflector","Un código de colores en los brazos del marco o el eslabón","El tamaño del orificio"], re:"Los rociadores de eslabón fusible/soldadura llevan su código de color de temperatura en los brazos del marco (o el eslabón), ya que no tienen ampolla de líquido. Fuente: disposiciones del código de colores de NFPA 13."},
  {id:132, q:"¿Por qué se instalan rociadores de clasificación de mayor temperatura cerca de calefactores de unidad, tragaluces o en áticos?", opts:["Para que operen más rápido en un incendio","Porque descargan menos agua","Para evitar la operación por molestia debido al alto calor ambiente","Porque el código prohíbe las cabezas ordinarias en cualquier edificio comercial"], re:"Donde las temperaturas ambiente son altas, una cabeza de mayor clasificación evita la operación accidental por calor que no es un incendio; la clasificación se ajusta a la temperatura máxima esperada del techo. Fuente: disposiciones de selección de temperatura de NFPA 13."},
  {id:133, q:"Un rociador con ampolla de vidrio AZUL corresponde a qué clasificación de temperatura aproximada?", opts:["155°F","200°F","286°F","360°F"], re:"El líquido de ampolla azul indica un rociador de alta temperatura de 286°F (141°C). Fuente: código de colores de ampollas de vidrio de NFPA 13."},
  {id:134, q:"La clasificación de alta temperatura según NFPA 13 cubre qué rango de clasificación?", opts:["135°F a 170°F","175°F a 225°F","250°F a 300°F","400°F a 475°F"], re:"La clasificación de alta temperatura es de 250°F a 300°F (121°C a 149°C). Fuente: tabla de clasificaciones de temperatura de NFPA 13."},
  {id:135, q:"En la fórmula de descarga del rociador Q = K√P, ¿qué representa Q?", opts:["Caudal en gpm","Presión en psi","Diámetro de tubería en pulgadas","El factor K"], re:"Q es la descarga (caudal) en galones por minuto; K es el coeficiente de descarga y P es la presión en el rociador en psi. Fuente: fórmula hidráulica/de descarga de NFPA 13."},
  {id:136, q:"En Q = K√P, el término P representa:", opts:["El caudal en gpm","La clasificación de temperatura","La longitud de la tubería","La presión en el rociador en psi"], re:"P es la presión en el orificio del rociador en psi; la raíz cuadrada de P se multiplica por el factor K para obtener el caudal Q. Fuente: fórmula de descarga de NFPA 13."},
  {id:137, q:"El factor K de un rociador se describe mejor como:", opts:["El coeficiente de descarga del orificio que relaciona el caudal con la presión","La clasificación de temperatura dividida entre 10","El tamaño de la rosca en milímetros","El espaciado de los soportes en pies"], re:"El factor K es el coeficiente de descarga nominal que vincula el caudal con la raíz cuadrada de la presión (Q = K√P); un K mayor significa un orificio efectivo mayor. Fuente: definición del factor K de NFPA 13."},
  {id:138, q:"El rociador de rociado de orificio estándar más común tiene un factor K nominal de:", opts:["2.8","25.2","14.0","5.6"], re:"K = 5.6 (unidades de EE. UU.) es el rociador de rociado de orificio estándar de 1/2 pulg., el factor K más usado. Fuente: NFPA 13; datos de rociadores de orificio estándar."},
  {id:139, q:"Para una presión dada, un rociador con un factor K MAYOR:", opts:["Descargará menos agua","No descargará en absoluto","Descargará la misma agua","Descargará más agua"], re:"Como Q = K√P, aumentar K a la misma presión aumenta el caudal; los factores K mayores significan orificios mayores y mayor descarga. Fuente: fórmula de descarga de NFPA 13."},
  {id:140, q:"Un rociador K=5.6 que descarga a 7 psi libera aproximadamente cuánta agua? (Q = 5.6 × √7)", opts:["Aproximadamente 8 gpm","Aproximadamente 100 gpm","Aproximadamente 56 gpm","Aproximadamente 15 gpm"], re:"√7 ≈ 2.646, por lo que Q ≈ 5.6 × 2.646 ≈ 14.8 ≈ 15 gpm. Fuente: fórmula de descarga de NFPA 13 (Q = K√P)."},
  {id:141, q:"NFPA 13 establece la presión mínima de operación para la mayoría de los rociadores de rociado estándar en:", opts:["1 psi","50 psi","25 psi","7 psi"], re:"La presión mínima de operación para los rociadores de rociado estándar según NFPA 13 es de 7 psi. Fuente: disposiciones de presión mínima de operación de NFPA 13."},
  {id:142, q:"Los rociadores ESFR están disponibles en qué conjunto de factores K nominales?", opts:["2.8 y 4.2","Solo 5.6 y 8.0","14.0, 16.8 y 25.2","0.5 y 1.0"], re:"Los rociadores ESFR usan orificios grandes con factores K nominales de 14.0, 16.8 y 25.2 (y mayores) para entregar altos caudales para incendios de almacenamiento. Fuente: disposiciones ESFR de NFPA 13."},
  {id:143, q:"Si el factor K de un rociador se duplica mientras la presión permanece igual, el caudal Q:", opts:["Permanece igual","Aumenta cuatro veces","Se reduce a la mitad","Se duplica"], re:"Q es directamente proporcional a K (Q = K√P); duplicar K a P constante duplica el caudal. Fuente: fórmula de descarga de NFPA 13."},
  {id:144, q:"Para DUPLICAR el caudal de un solo rociador aumentando únicamente la presión, la presión debe aumentarse por un factor de:", opts:["2","16","8","4"], re:"Como Q ∝ √P, duplicar Q requiere cuadruplicar P (√4 = 2). Fuente: fórmula de descarga de NFPA 13."},
  {id:145, q:"El rociador de rociado de orificio estándar de 1/2 pulg. corresponde a un tamaño nominal de orificio (rosca) de:", opts:["1/4 pulg.","2 pulg.","1 pulg.","1/2 pulg."], re:"El rociador de rociado de orificio estándar (K=5.6) tiene una conexión nominal de orificio/rosca de 1/2 pulg. Fuente: NFPA 13; datos de rociadores de orificio estándar."},
  {id:146, q:"Un rociador de rociado de orificio grande comúnmente tiene un factor K nominal de:", opts:["2.8","5.6","8.0","0.5"], re:"K = 8.0 es el rociador de rociado de orificio grande común, que descarga más agua que el orificio estándar K=5.6 a la misma presión. Fuente: NFPA 13; datos de rociadores de orificio grande."},
  {id:147, q:"¿Por qué se usan a menudo rociadores de K mayor (orificio mayor) para reducir la presión requerida del sistema?", opts:["Descargan el caudal necesario a una presión menor","Cuestan menos de fabricar","Eliminan la necesidad de un deflector","Reducen la clasificación de temperatura"], re:"Para un caudal objetivo, un K mayor lo entrega a menor presión (P = (Q/K)^2), lo que puede reducir la demanda de la bomba/suministro de agua. Fuente: principios de diseño hidráulico de NFPA 13."},
  {id:148, q:"Un rociador K=8.0 debe descargar 24 gpm. La presión requerida P = (Q/K)^2 es aproximadamente:", opts:["Aproximadamente 3 psi","Aproximadamente 64 psi","Aproximadamente 24 psi","Aproximadamente 9 psi"], re:"(24/8)^2 = 3^2 = 9 psi. Fuente: fórmula de descarga de NFPA 13 reordenada, P = (Q/K)^2."},
  {id:149, q:"En la forma de pulgada-libra (EE. UU.) de Q = K√P, las unidades del factor K son:", opts:["gpm/psi","gpm·psi","psi/gpm","gpm/(psi)^1/2"], re:"K tiene unidades de gpm por raíz cuadrada de psi, es decir, gpm/(psi)^1/2, de modo que K√P da gpm. Fuente: definiciones de la fórmula hidráulica de NFPA 13."},
  {id:150, q:"Dos rociadores idénticos en una línea ramal ven presiones diferentes. En comparación con la cabeza más cercana al suministro, la cabeza más remota:", opts:["Descargará más agua","No descargará en absoluto","Descargará exactamente lo mismo","Descargará menos agua debido a la menor presión disponible"], re:"La pérdida por fricción reduce la presión a lo largo de la línea, por lo que el rociador más remoto usualmente tiene la menor presión y el menor caudal (Q = K√P). Por eso el área remota gobierna el diseño. Fuente: principios de cálculo hidráulico de NFPA 13."},
  {id:151, q:"La tubería de acero Cédula 40 se diferencia de la tubería de acero Cédula 10 principalmente en que la Cédula 40 tiene:", opts:["Una pared más gruesa","Una pared más delgada","Un diámetro exterior mayor para el mismo tamaño nominal","No se permiten roscas"], re:"Para un tamaño nominal dado, el diámetro exterior es el mismo; la Cédula 40 tiene una pared más gruesa (orificio interior más pequeño) que la Cédula 10. Fuente: cédulas de tubería de NFPA 13; normas ASTM de tubería de acero."},
  {id:152, q:"Según NFPA 13, generalmente se permite el roscado en qué tubería de acero?", opts:["Solo Cédula 10","Solo tubo de cobre","Cualquier espesor de pared sin restricción","Cédula 40 (o más pesada), a menos que una pared más liviana esté específicamente listada para roscado"], re:"Las roscas se cortan en la pared, por lo que NFPA 13 permite roscar Cédula 40 o más pesada; la tubería más delgada solo puede roscarse si está específicamente listada. Fuente: disposiciones de métodos de unión de NFPA 13."},
  {id:153, q:"La tubería de acero de pared delgada Cédula 10 típicamente se une mediante:", opts:["Roscas cortadas","Solo manguitos de compresión","Cemento solvente","Acoplamientos ranurados (roll-grooved) o soldadura"], re:"La Cédula 10 es demasiado delgada para roscarse de forma segura, por lo que se ranura (acoplamientos ranurados) o se suelda. Fuente: métodos de unión de NFPA 13; referencias de tubería de acero."},
  {id:154, q:"La tubería de CPVC usada en sistemas de rociadores contra incendios se une mediante:", opts:["Soldadura fuerte (brazing)","Roscado","Soldadura con cemento solvente","Ranurado (roll grooving)"], re:"El CPVC listado (p. ej., BlazeMaster) se une con el cemento solvente del fabricante; no se rosca, ni se suelda con soldadura fuerte, ni se ranura. Fuente: NFPA 13; instrucciones de instalación de CPVC listado."},
  {id:155, q:"La tubería de rociadores de CPVC listada generalmente se limita a qué tipo de sistema?", opts:["Solo sistemas de tubería seca","Sistemas industriales de alta temperatura","Solo sistemas de diluvio","Sistemas de tubería húmeda (con limitaciones de listado)"], re:"El CPVC listado se usa en sistemas de tubería húmeda dentro de su listado; no se usa en sistemas secos/de preacción llenos de aire y debe protegerse de temperaturas excesivas. Fuente: NFPA 13; listados de productos de CPVC."},
  {id:156, q:"Una tubería de rociadores de CPVC listada típica está clasificada para servicio hasta aproximadamente:", opts:["150°F","300°F","500°F","750°F"], re:"El CPVC listado (p. ej., BlazeMaster) está clasificado para servicio de rociadores hasta aproximadamente 150°F (65°C); por encima de eso debe aislarse/ventilarse o usarse otro material. Fuente: clasificaciones de productos de CPVC listados."},
  {id:157, q:"El tubo de cobre usado para tubería de rociadores se une más comúnmente mediante:", opts:["Cemento solvente","Roscas cortadas","Solo ranurado","Soldadura fuerte o blanda (la soldadura blanda se permite en sistemas húmedos de riesgo ligero)"], re:"El tubo de cobre se suelda con soldadura fuerte; NFPA 13 permite juntas con soldadura blanda para sistemas de tubería húmeda de riesgo ligero. No se une con cemento solvente. Fuente: disposiciones de unión de cobre de NFPA 13."},
  {id:158, q:"Para tubo de agua de cobre, ¿qué tipo tiene la pared MÁS GRUESA?", opts:["Tipo M","Tipo L","Tipo K","Tipo DWV"], re:"Entre los tubos de agua de cobre, el Tipo K es la pared más pesada, el Tipo L es intermedio y el Tipo M es el más liviano. Fuente: ASTM B88; tipos de tubo de cobre."},
  {id:159, q:"Un acoplamiento reductor en la tubería de rociadores se usa para:", opts:["Cambiar la dirección de la tubería 90°","Proporcionar una conexión de prueba","Tapar el extremo de una línea","Conectar dos tuberías de diferentes diámetros en línea"], re:"Un reductor/acoplamiento reductor une dos tamaños de tubería diferentes en un tramo recto; los codos cambian de dirección y las tapas cierran extremos. Fuente: nomenclatura estándar de accesorios de tubería."},
  {id:160, q:"Un accesorio en 'te' (tee) en la tubería de rociadores se usa para:", opts:["Cerrar el extremo de una línea ramal","Permitir el flujo en una sola dirección","Unir dos tuberías del mismo tamaño solo en línea recta","Crear una ramificación (derivación a 90°) de un tramo de tubería"], re:"Una te proporciona una salida lateral (ramificación) de un tramo principal; común en mains de rociadores para alimentar líneas ramales. Fuente: nomenclatura estándar de accesorios de tubería."},
  {id:161, q:"En los cálculos hidráulicos de NFPA 13, los accesorios como codos y tes se contabilizan usando:", opts:["Solo su longitud real medida","Su código de colores","Su peso en libras","Longitudes equivalentes de tubería (equivalentes de pérdida por fricción)"], re:"Los accesorios añaden pérdida por fricción representada como 'longitud equivalente' de tubería sumada a la longitud real de tubería en el cálculo de Hazen-Williams. Fuente: tablas de longitud equivalente de NFPA 13."},
  {id:162, q:"La tubería de acero galvanizado a veces se especifica para qué sistema de rociadores para resistir la corrosión?", opts:["Oficinas de riesgo ligero de tubería húmeda","Sistemas de cobre","Sistemas de CPVC","Sistemas de tubería seca y preacción (interior sujeto a condensación)"], re:"El galvanizado se usa a menudo en sistemas de tubería seca/preacción donde el aire atrapado y el condensado aceleran la corrosión interna. Fuente: NFPA 13; práctica de control de corrosión para sistemas secos."},
  {id:163, q:"El factor 'C' de Hazen-Williams en la hidráulica de rociadores representa:", opts:["La rugosidad/lisura interna de la tubería para la pérdida por fricción","La clasificación de temperatura de la tubería","El factor K del rociador","La carga sísmica"], re:"El factor C describe la lisura interior de la tubería; un C mayor (p. ej., cobre/CPVC) significa menor pérdida por fricción que una tubería más rugosa (p. ej., acero más antiguo). Fuente: valores C de Hazen-Williams de NFPA 13."},
  {id:164, q:"En comparación con el acero, la tubería de CPVC listada generalmente tiene un factor C de Hazen-Williams que es:", opts:["Menor (más rugoso)","Negativo","Idéntico al acero","Mayor (más liso), reduciendo la pérdida por fricción"], re:"El CPVC y el cobre tienen valores C mayores (orificio más liso) que el acero, por lo que producen menos pérdida por fricción para el mismo caudal. Fuente: valores C de Hazen-Williams de NFPA 13."},
  {id:165, q:"Un acoplamiento ranurado (roll-grooved) une la tubería de acero mediante:", opts:["Fundir los extremos de la tubería entre sí","Roscar dentro de un acoplamiento","Pegar con cemento solvente","Encajar una ranura laminada o cortada cerca del extremo de la tubería con una carcasa con junta"], re:"Los acoplamientos ranurados sujetan una carcasa de dos piezas en una ranura en cada extremo de la tubería, sellando con una junta; común y rápido para tubería de acero de rociadores. Fuente: NFPA 13; listados de accesorios ranurados."},
  {id:166, q:"Una unión o acoplamiento ranurado cerca de una válvula o dispositivo se proporciona principalmente para:", opts:["Aumentar la presión de agua","Servir como cabeza de rociador","Cambiar el material de la tubería","Permitir que el dispositivo se retire/dé servicio sin cortar la tubería"], re:"Una unión/brida/acoplamiento ranurado proporciona un punto de corte para que las válvulas, dispositivos de alarma, etc., puedan recibir servicio o reemplazarse sin cortar la tubería. Fuente: práctica de instalación estándar; capacidad de servicio de NFPA 13/25."},
  {id:167, q:"NFPA 13 requiere que la tubería, los accesorios, las válvulas y los dispositivos usados en un sistema de rociadores sean:", opts:["Pintados de rojo independientemente del listado","Dimensionados a 6 pulg. mínimo","Hechos solo de cobre","Listados/aprobados para servicio de protección contra incendios o que cumplan con las normas referenciadas"], re:"Los componentes deben estar listados/aprobados o cumplir con las normas referenciadas por NFPA 13; no se permite la sustitución arbitraria de piezas no listadas. Fuente: requisitos de materiales y listado de NFPA 13."},
  {id:168, q:"Una válvula OS&Y obtiene su nombre de qué característica de diseño?", opts:["Outside Screw and Yoke (tornillo y yugo exteriores, vástago ascendente)","Open System and Yield","Orifice Sizing and Yaw","Overhead Sprinkler and Yard"], re:"OS&Y = Outside Screw and Yoke (tornillo y yugo exteriores); el vástago roscado asciende por fuera del cuerpo a través del yugo, indicando visiblemente la posición abierta/cerrada. Fuente: NFPA 13; referencias de válvulas OS&Y."},
  {id:169, q:"En una válvula de compuerta OS&Y, se puede saber que la válvula está ABIERTA porque:", opts:["El volante está retirado","Una luz verde se enciende automáticamente","La válvula zumba","El vástago roscado sobresale (asciende) a través del yugo"], re:"Cuando una válvula OS&Y está abierta, el vástago ascendente se extiende a través del yugo; un vástago retraído significa cerrada. Esta indicación visible es por lo que califica como válvula indicadora. Fuente: NFPA 13; operación OS&Y."},
  {id:170, q:"NFPA 13 requiere que las válvulas de control del sistema de rociadores sean de qué tipo?", opts:["Solo no indicadoras","Solo reductoras de presión","Válvulas de retención con resorte","Tipo indicador (estado abierto/cerrado visible)"], re:"Las válvulas de control deben ser indicadoras para que el personal pueda verificar que el suministro de agua está abierto sin operar la válvula (OS&Y, mariposa con indicador de posición, PIV, PIV de pared). Fuente: requisitos de válvulas de control de NFPA 13."},
  {id:171, q:"Una válvula de mariposa controla el flujo mediante:", opts:["Subir y bajar una compuerta","Rotar un disco 90° dentro de la tubería","Fundir un eslabón fusible","Abrir una clapeta por presión de agua"], re:"Una válvula de mariposa gira un disco 90° para iniciar/detener el flujo; para servicio contra incendios es una válvula indicadora con un indicador de posición y está supervisada. Fuente: NFPA 13; referencias de válvula de mariposa."},
  {id:172, q:"La mayoría de las válvulas de control de mariposa de protección contra incendios incluyen qué característica para el monitoreo?", opts:["Una cabeza de rociador integrada","Un interruptor de manipulación (supervisión) integral","Solo un medidor de flujo","Una cámara de retardo"], re:"Las válvulas de mariposa de servicio contra incendios típicamente vienen con un interruptor de manipulación/supervisión que señala al panel si la válvula se mueve de la posición totalmente abierta. Fuente: NFPA 13/NFPA 72; supervisión de válvulas."},
  {id:173, q:"El propósito principal de una válvula de retención en un sistema de rociadores es:", opts:["Indicar la posición abierta/cerrada","Permitir el flujo en una dirección y evitar el contraflujo","Reducir la clasificación de temperatura","Estrangular el flujo a una presión establecida"], re:"Una válvula de retención permite que el agua fluya solo hacia el sistema y evita el flujo inverso (p. ej., de regreso al suministro). Fuente: NFPA 13; función de la válvula de retención."},
  {id:174, q:"Una válvula de retención de alarma cumple qué función en un sistema de tubería húmeda?", opts:["Retiene el aire en un sistema seco","Permite el flujo al sistema y acciona una alarma de flujo de agua","Reduce la presión entrante a 7 psi","Drena el sistema después del uso"], re:"La válvula de retención de alarma es una clapeta unidireccional en el montante; cuando el agua fluye, un puerto de alarma dirige el agua a un interruptor de presión y/o gong hidráulico para señalar el flujo. Fuente: NFPA 13; operación de la válvula de retención de alarma."},
  {id:175, q:"La cámara de retardo asociada con una válvula de retención de alarma se proporciona para:", opts:["Almacenar agua adicional para los rociadores","Evitar falsas alarmas por breves picos de presión","Aumentar el factor K de descarga","Retener el aire en un sistema seco"], re:"La cámara de retardo se llena y drena lentamente, de modo que los picos momentáneos de presión del suministro no disparan la alarma de flujo de agua; el flujo sostenido la llena y dispara el interruptor. Fuente: NFPA 13; función de la cámara de retardo."},
  {id:176, q:"Un gong hidráulico (alarma de motor de agua) es accionado por:", opts:["Solo un motor eléctrico","Agua desviada por la válvula de alarma que golpea una rueda con aletas","Aire comprimido de la válvula seca","La bomba de la conexión del cuerpo de bomberos"], re:"Cuando la válvula de alarma opera, el agua se dirige al gong donde hace girar una rueda con aletas que mueve un martillo para sonar la campana, una alarma local puramente hidráulica. Fuente: NFPA 13; operación del gong hidráulico."},
  {id:177, q:"Una válvula de tubería seca en un sistema seco retiene el agua usando:", opts:["Un vástago OS&Y bloqueado","Presión de aire o nitrógeno en el lado del sistema","Cemento solvente","Solo una cámara de retardo"], re:"Una válvula de tubería seca usa aire/nitrógeno presurizado en el lado del sistema para contener la mayor fuerza del lado del agua; cuando un rociador se abre, el aire se purga y la válvula se dispara para admitir agua. Fuente: disposiciones de tubería seca de NFPA 13."},
  {id:178, q:"Una válvula de diluvio se usa con qué disposición de rociadores?", opts:["Rociadores estándar cerrados en un sistema húmedo","Rociadores abiertos, que descargan todas las cabezas a la vez cuando se acciona","Una sola cabeza lateral residencial","Solo ESFR en estantería"], re:"Una válvula de diluvio admite agua a un sistema de rociadores ABIERTOS cuando un sistema accionador (de detección) se dispara, mojando toda el área simultáneamente. Fuente: disposiciones de diluvio de NFPA 13."},
  {id:179, q:"NFPA requiere que las válvulas de control que no están supervisadas eléctricamente estén:", opts:["Pintadas de verde","Bloqueadas en la posición abierta e inspeccionadas según un programa establecido","Retiradas durante la ocupación","Reemplazadas anualmente"], re:"Donde no están monitoreadas por un interruptor de manipulación, las válvulas de control deben bloquearse/sellarse abiertas e inspeccionarse físicamente (comúnmente cada semana) para confirmar que permanecen abiertas. Fuente: supervisión de válvulas de NFPA 13/NFPA 25."},
  {id:180, q:"Una Válvula Indicadora de Poste (PIV) es una válvula de control que:", opts:["Está enterrada sin forma de saber su posición","Tiene un poste sobre el nivel del suelo con una ventana indicadora ABIERTO/CERRADO para una válvula subterránea","Es lo mismo que una válvula de retención","Solo funciona en tubería de CPVC"], re:"Una PIV lleva la tuerca de operación y un indicador ABIERTO/CERRADO sobre el nivel del suelo para una válvula principal enterrada, satisfaciendo el requisito de válvula indicadora. Fuente: NFPA 13/24; referencias de PIV."},
  {id:181, q:"Un preventor de contraflujo se instala en una toma de servicio contra incendios principalmente para:", opts:["Aumentar la presión de descarga del rociador","Evitar que el agua potencialmente contaminada del sistema fluya de regreso al suministro público","Detectar el calor y disparar el sistema","Reemplazar la válvula de retención de alarma"], re:"Los preventores de contraflujo protegen el suministro potable de la contaminación cruzada por agua de rociadores estancada o tratada; requerido por las autoridades de plomería/agua, no por la propia NFPA. Fuente: referencias de prevención de contraflujo/conexión cruzada; contexto de NFPA 13/25."},
  {id:182, q:"Un conjunto de contraflujo de Zona de Presión Reducida (RPZ) se diferencia de un conjunto de Doble Retención (DCVA) al añadir:", opts:["Una tercera válvula de retención","Una válvula de alivio diferencial que descarga agua si una retención falla","Una cámara de retardo","Una segunda válvula OS&Y"], re:"Un RPZ añade una válvula de alivio operada hidráulicamente entre dos retenciones; si una retención tiene fuga, el alivio descarga al drenaje, dando mayor protección para conexiones de mayor riesgo. Fuente: referencias de conjuntos de contraflujo (AWWA M14)."},
  {id:183, q:"Una válvula reductora de presión (PRV) se usa en un sistema alto de columna seca/rociadores para:", opts:["Aumentar la presión en los pisos superiores","Limitar la presión excesiva en los pisos inferiores/conexiones de manguera","Detectar el flujo de agua","Retener el aire en un sistema seco"], re:"En sistemas de gran altura, la presión estática en los niveles inferiores puede ser excesiva; las PRV la reducen a valores seguros en las válvulas de manguera y la tubería de la zona inferior. Fuente: disposiciones de regulación de presión de NFPA 14/NFPA 13."},
  {id:184, q:"La válvula de drenaje principal en el montante se usa para:", opts:["Suministrar agua a los rociadores","Drenar el sistema y realizar una prueba de drenaje principal (suministro de agua)","Reducir la presión entrante","Retener el aire"], re:"El drenaje principal permite que el sistema se drene y se usa para la prueba de drenaje principal, que verifica obstrucciones del lado del suministro comparando la presión estática y residual. Fuente: prueba de drenaje principal de NFPA 13/25."},
  {id:185, q:"Los soportes usados para sostener la tubería del sistema de rociadores deben ser, según NFPA 13:", opts:["Listados para el servicio","Cualquier alambre disponible en el sitio","Hechos solo de cobre","Espaciados a 50 pies como máximo"], re:"NFPA 13 requiere componentes de soporte que sostienen la tubería del sistema que estén listados (con excepciones limitadas para ciertas piezas fabricadas en campo que cumplan los criterios de MSS). Fuente: disposiciones de colgado/soporte de NFPA 13."},
  {id:186, q:"Para tubería de acero de rociadores de 1 pulg., la distancia máxima entre soportes según NFPA 13 es:", opts:["6 pies","12 pies","20 pies","30 pies"], re:"NFPA 13 limita el espaciado de soportes en tubería de acero de 1 pulg. (y 1-1/4 pulg.) a un máximo de 12 pies; los tamaños de acero más grandes (2 pulg. y más) permiten hasta 15 pies. Fuente: tabla de distancia máxima entre soportes de NFPA 13."},
  {id:187, q:"Para tubería de acero de rociadores de 2 pulg. y más grande, el espaciado máximo de soportes según NFPA 13 es generalmente:", opts:["8 pies","10 pies","15 pies","25 pies"], re:"La tubería de acero de 2 pulg. y más grande puede sostenerse a un espaciado máximo de soportes de hasta 15 pies según NFPA 13. Fuente: tabla de distancia máxima entre soportes de NFPA 13."},
  {id:188, q:"La tubería de rociadores de CPVC requiere un espaciado de soportes más cercano que el acero porque el CPVC:", opts:["Es más pesado que el acero","Es más flexible y se flexiona más, especialmente cuando está caliente","No puede contener agua","Conduce mejor el calor"], re:"El CPVC es más flexible y pierde rigidez al calentarse, por lo que necesita soporte más frecuente que el acero para evitar la flexión; siga el espaciado listado del fabricante. Fuente: NFPA 13; orientación de soportes de CPVC listado."},
  {id:189, q:"El propósito del arriostramiento sísmico contra balanceo en la tubería de rociadores es:", opts:["Aumentar la presión de agua","Resistir el movimiento diferencial y mantener la tubería intacta durante un terremoto","Reducir la pérdida por fricción","Aislar la tubería del calor"], re:"El arriostramiento contra balanceo restringe la tubería contra el movimiento lateral/longitudinal inducido por terremotos para que no se rompa ni se separe; requerido en áreas de diseño sísmico. Fuente: disposiciones de protección contra terremotos de NFPA 13."},
  {id:190, q:"Los arriostramientos laterales contra balanceo en mains de alimentación y cruzados se espacian a un máximo de:", opts:["20 pies al centro","40 pies al centro","80 pies al centro","120 pies al centro"], re:"NFPA 13 limita los arriostramientos laterales contra balanceo a un máximo de 40 pies al centro en mains de alimentación/cruzados (y líneas ramales que califiquen). Fuente: espaciado de arriostramiento lateral de NFPA 13."},
  {id:191, q:"Los arriostramientos longitudinales contra balanceo en mains de alimentación y cruzados se espacian a un máximo de:", opts:["40 pies al centro","60 pies al centro","80 pies al centro","160 pies al centro"], re:"NFPA 13 limita los arriostramientos longitudinales contra balanceo a un máximo de 80 pies al centro en mains de alimentación y cruzados. Fuente: espaciado de arriostramiento longitudinal de NFPA 13."},
  {id:192, q:"Los acoplamientos flexibles usados en el diseño sísmico permiten que la tubería:", opts:["Transporte más agua","Se flexione en las juntas para que el movimiento no rompa las conexiones rígidas","Elimine la necesidad de cualquier arriostramiento","Reduzca la clasificación de temperatura"], re:"Los acoplamientos flexibles listados proporcionan articulación controlada para que el movimiento sísmico se acomode en la junta en lugar de sobreesforzar la tubería; su colocación se coordina con el arriostramiento. Fuente: disposiciones de flexibilidad sísmica de NFPA 13."},
  {id:193, q:"Una Conexión del Cuerpo de Bomberos (FDC) permite que el cuerpo de bomberos:", opts:["Apague el sistema de rociadores","Bombee agua/presión adicional al sistema de rociadores o columna seca","Drene el sistema","Solo pruebe la campana de alarma"], re:"La FDC es una toma donde el aparato del cuerpo de bomberos puede impulsar agua y presión al sistema para complementar el suministro durante un incendio. Fuente: NFPA 13/14; propósito de la FDC."},
  {id:194, q:"Una toma de FDC estándar usa más comúnmente qué tamaño de conexión de rosca de manguera?", opts:["1 pulg.","1-1/2 pulg.","2-1/2 pulg.","6 pulg."], re:"La FDC predeterminada proporciona tomas giratorias roscadas de Manguera Nacional (NH) de 2-1/2 pulg. (a menudo dos, una conexión 'Siamesa'), a menos que la jurisdicción local especifique una conexión de gran diámetro (Storz). Fuente: requisitos de toma de FDC de NFPA 13/14."},
  {id:195, q:"NFPA requiere que una FDC se ubique a qué altura sobre el nivel del suelo adyacente?", opts:["No menos de 18 pulg. y no más de 48 pulg.","Exactamente 6 pulg.","No menos de 8 pies","Bajo tierra en un pozo"], re:"Las FDC deben ubicarse entre 18 pulg. y 48 pulg. sobre el nivel del suelo/piso terminado adyacente para que se puedan conectar las mangueras. Fuente: NFPA 14 (6.4.6) / NFPA 13 ubicación de FDC."},
  {id:196, q:"Una válvula de retención se instala en la línea de la FDC para:", opts:["Reducir la presión de entrada","Evitar que el agua del sistema salga por la FDC durante la operación normal","Detectar el calor","Indicar la posición de la válvula"], re:"La FDC tiene una válvula de retención para que el agua normalmente fluya solo hacia adentro; evita que el agua del sistema (y cualquier presión impulsada) se descargue por las tomas de la FDC. Fuente: NFPA 13/14; requisito de válvula de retención de la FDC."},
  {id:197, q:"Cada toma de FDC debe estar provista de cuál de las siguientes para mantener fuera los escombros?", opts:["Un manómetro","Un tapón, tapa o cubierta rompible","Una cabeza de rociador","Una cámara de retardo"], re:"Las tomas de FDC están equipadas con tapas/tapones (o cubiertas rompibles) para mantener fuera los escombros y el vandalismo, sin dejar de ser rápidamente removibles por el cuerpo de bomberos. Fuente: disposiciones de FDC de NFPA 13/14."},
  {id:198, q:"Un goteo de bola automático (válvula de goteo) en la FDC se proporciona para:", opts:["Impulsar la presión del sistema","Drenar el agua residual de la tubería de la FDC para evitar la congelación","Detectar el flujo de agua","Retener el aire en un sistema seco"], re:"El goteo automático/goteo de bola permite que el agua atrapada en la tubería de la FDC se drene para que no se congele y reviente la conexión en clima frío. Fuente: disposiciones de drenaje de FDC de NFPA 13/14."},
  {id:199, q:"Un soporte en una línea ramal debe ubicarse dentro de una distancia limitada de cada rociador principalmente para:", opts:["Aumentar la presión de agua en la cabeza","Sostener la cabeza y evitar que la tubería se flexione o azote","Cambiar la clasificación de temperatura","Servir como arriostramiento sísmico"], re:"NFPA 13 requiere un soporte dentro de una distancia establecida de cada rociador para que la cabeza esté debidamente sostenida y la tubería no se flexione, caiga ni se mueva en exceso. Fuente: disposiciones de ubicación de soportes en líneas ramales de NFPA 13."},
  {id:200, q:"Una FDC que sirve a un sistema combinado típicamente se identifica mediante:", opts:["Una luz verde","Un letrero que indica el sistema/área que sirve (p. ej., 'AUTOSPKR' o 'STANDPIPE')","Ninguna marca","Un código de colores de temperatura"], re:"Las FDC deben identificarse mediante un letrero o letras en relieve que muestren el servicio que suministran (rociador, columna seca o combinado) y cualquier información de presión, para que los respondedores se conecten a la toma correcta. Fuente: requisitos de señalización de FDC de NFPA 13/14."},
  {id:201, q:"Una columna vertical de agua ejerce una presión estática de aproximadamente:", opts:["5.0 psi por pie de altura","1.0 psi por pie de altura","2.31 psi por pie de altura","0.433 psi por pie de altura"], re:"El agua ejerce unos 0.433 psi por cada pie vertical de altura; de forma equivalente, se necesitan 2.31 pies de agua para producir 1 psi. Hidráulica estándar de protección contra incendios (cálculos de elevación de NFPA 13)."},
  {id:202, q:"¿Cuántos pies de columna de agua se requieren para producir una presión de 1 psi?", opts:["0.433 ft","1.0 ft","4.33 ft","2.31 ft"], re:"Dado que el agua ejerce 0.433 psi/ft, el inverso (1 ÷ 0.433) es aproximadamente 2.31 ft de agua por psi. Constante hidráulica estándar usada en los cálculos de NFPA 13."},
  {id:203, q:"La 'presión residual' en una prueba de suministro o de caudal de agua es la presión que permanece:", opts:["Mientras fluye la cantidad de agua requerida","Después de apagar la bomba","Antes de abrir cualquier válvula","Solo en el rociador más alto"], re:"La presión residual es la presión que permanece en el sistema mientras el agua está fluyendo; la caída de estática a residual refleja la fricción y la demanda. Terminología de pruebas de hidrante de NFPA 291."},
  {id:204, q:"Las tres formas de energía que se equilibran en un cálculo hidráulico de protección contra incendios (Bernoulli) son presión (carga), elevación y:", opts:["Magnetismo","Temperatura","Tensión superficial","Velocidad (presión de velocidad)"], re:"El principio de Bernoulli equilibra la carga de presión, la carga de elevación y la carga de velocidad; la hidráulica de protección contra incendios usa una forma modificada para los cálculos de flujo en tuberías. Teoría hidráulica de Canute / NFPA 13."},
  {id:205, q:"A medida que el agua se bombea HACIA ARRIBA a un piso superior, el cambio de elevación hace que la presión:", opts:["Aumente unos 0.433 psi por pie de ascenso","Disminuya unos 0.433 psi por pie de ascenso","Permanezca exactamente igual","Se duplique en cada piso"], re:"Cada pie de ascenso cuesta unos 0.433 psi de presión que el suministro debe vencer, por lo que la presión disminuye al ganar elevación. Pérdida de presión por elevación de NFPA 13."},
  {id:206, q:"La descarga de un rociador o boquilla se determina con la fórmula:", opts:["Q = P + K","Q = P²","Q = K ÷ P","Q = K√P"], re:"El caudal es igual al factor K por la raíz cuadrada de la presión: Q = K√P, donde Q está en gpm, K es el coeficiente de descarga y P está en psi. Fundamentos hidráulicos de NFPA 13."},
  {id:207, q:"En la fórmula Q = K√P, el símbolo 'K' representa el:", opts:["Largo de la tubería","Coeficiente de descarga (factor K) del orificio","Número de rociadores","Caballos de fuerza de la bomba"], re:"K es el coeficiente nominal de descarga (factor K) del orificio del rociador o boquilla, en unidades de gpm/√psi. Definición del factor K de NFPA 13."},
  {id:208, q:"Un rociador de pulverización con orificio estándar de 1/2 pulg. tiene un factor K nominal de aproximadamente:", opts:["1.4","5.6","2.8","11.2"], re:"El rociador de pulverización estándar de 1/2 pulg. (DN15) usado en la mayoría de los trabajos comerciales de riesgo ligero tiene un factor K nominal de unos 5.6 (gpm/√psi). Factores K nominales de NFPA 13."},
  {id:209, q:"Un rociador con K=5.6 que opera a 25 psi descarga aproximadamente cuántos gpm? (Q = K√P)", opts:["14 gpm","56 gpm","28 gpm","112 gpm"], re:"Q = 5.6 × √25 = 5.6 × 5 = 28 gpm. Aplicación directa de Q = K√P (NFPA 13)."},
  {id:210, q:"Un rociador con K=5.6 debe entregar un caudal de 22.4 gpm. ¿Qué presión se requiere? (P = (Q/K)²)", opts:["4 psi","16 psi","8 psi","32 psi"], re:"P = (Q/K)² = (22.4/5.6)² = (4)² = 16 psi. Forma reordenada de Q = K√P (NFPA 13)."},
  {id:211, q:"NFPA 13 establece la presión mínima de operación para un rociador de pulverización estándar en no menos de:", opts:["3 psi","15 psi","7 psi","25 psi"], re:"NFPA 13 requiere un mínimo de 7 psi en un rociador de pulverización estándar (a menos que el listado exija un valor mayor); por debajo de eso, el patrón de pulverización no es confiable. Presión mínima de operación de NFPA 13."},
  {id:212, q:"Si la presión en un rociador con K=5.6 se cuadruplica (×4), la descarga (caudal) será:", opts:["Igual","El doble (×2)","El triple (×3)","El cuádruple (×4)"], re:"Como el caudal varía con la raíz cuadrada de la presión (Q = K√P), cuadruplicar la presión solo duplica el caudal (√4 = 2). Relación del factor K de NFPA 13."},
  {id:213, q:"El 'área de diseño' en un sistema de rociadores calculado hidráulicamente es:", opts:["El área total de piso del edificio","El área cubierta por un rociador","El área hidráulicamente más exigente que se asume opera en un incendio","El área del cuarto del montante"], re:"El área de diseño (remota) es el grupo de rociadores hidráulicamente más exigente que se asume opera; el sistema se calcula para entregar la densidad requerida sobre esa área. Método de densidad/área de NFPA 13."},
  {id:214, q:"En los cálculos hidráulicos, la 'densidad' se expresa en unidades de:", opts:["gpm por pie cuadrado","psi por pie","solo galones por minuto","pies por segundo"], re:"La densidad de diseño es la tasa de aplicación de agua sobre un área, expresada en gpm/ft² (galones por minuto por pie cuadrado). Diseño de densidad/área de NFPA 13."},
  {id:215, q:"Para hallar el caudal mínimo de un rociador que protege 130 ft² a una densidad de 0.10 gpm/ft², usted debería:", opts:["Sumar densidad + área","Multiplicar densidad × área = 13 gpm","Dividir el área por la densidad","Restar la densidad del área"], re:"Caudal mínimo = densidad × área de cobertura = 0.10 gpm/ft² × 130 ft² = 13 gpm para ese rociador. Base de densidad × área de NFPA 13."},
  {id:216, q:"En un cálculo hidráulico, la pérdida por fricción en la tubería se trata como:", opts:["Una ganancia de presión","Una pérdida de presión que el suministro debe vencer","Irrelevante para el diseño","Igual a la ganancia por elevación"], re:"La pérdida por fricción (flujo) es una penalización de presión que el suministro de agua debe vencer junto con la elevación y la presión mínima del rociador. Cálculo hidráulico de NFPA 13."},
  {id:217, q:"En una gráfica hidráulica (papel semilogarítmico N1.85), el suministro de agua se traza como una línea y la demanda del sistema como un punto; el diseño es adecuado cuando el punto de demanda cae:", opts:["Por encima y a la derecha de la línea de suministro","Sobre o por debajo (a la izquierda de) la línea de suministro","Exactamente sobre el eje horizontal","Completamente fuera de la gráfica"], re:"Si el punto de demanda queda sobre o por debajo/a la izquierda de la curva de suministro disponible, el suministro puede satisfacer la demanda. Análisis hidráulico gráfico de NFPA 13."},
  {id:218, q:"Para un edificio de OFICINAS clasificado como Riesgo Ligero, la densidad de diseño clásica de NFPA 13 es de aproximadamente:", opts:["0.05 gpm/ft²","0.20 gpm/ft²","0.10 gpm/ft²","0.40 gpm/ft²"], re:"Las ocupaciones de Riesgo Ligero (oficinas, escuelas, iglesias) usan una densidad de diseño clásica cercana a 0.10 gpm/ft². Densidad/área de NFPA 13 (Riesgo Ligero)."},
  {id:219, q:"La densidad de diseño clásica de NFPA 13 para Riesgo Ordinario Grupo 1 es de aproximadamente:", opts:["0.10 gpm/ft²","0.30 gpm/ft²","0.15 gpm/ft²","0.60 gpm/ft²"], re:"El Riesgo Ordinario Grupo 1 usa una densidad clásica de unos 0.15 gpm/ft². Densidad/área de NFPA 13 (OH-1)."},
  {id:220, q:"La densidad de diseño clásica de NFPA 13 para Riesgo Ordinario Grupo 2 es de aproximadamente:", opts:["0.10 gpm/ft²","0.20 gpm/ft²","0.15 gpm/ft²","0.50 gpm/ft²"], re:"El Riesgo Ordinario Grupo 2 usa una densidad clásica de unos 0.20 gpm/ft². Densidad/área de NFPA 13 (OH-2)."},
  {id:221, q:"En el método de densidad/área, ¿cuáles dos cantidades definen el 'punto' de diseño para una clasificación de riesgo?", opts:["Densidad (gpm/ft²) y área de operación (ft²)","Voltaje y amperaje","Temperatura y humedad","Tamaño y largo de la tubería"], re:"El método combina una densidad de aplicación de agua (gpm/ft²) con un área de operación de diseño (ft²) seleccionada según la clasificación de riesgo. Diseño de densidad/área de NFPA 13."},
  {id:222, q:"Un ÁREA de operación de diseño comúnmente usada para el diseño de densidad/área de Riesgo Ordinario y Ligero es:", opts:["1,500 ft²","500 ft²","100 ft²","25,000 ft²"], re:"Un área de operación de diseño de 1,500 ft² es la línea base clásica para el diseño de densidad/área de Riesgo Ligero y Ordinario. Densidad/área de NFPA 13 (área de diseño)."},
  {id:223, q:"En las curvas clásicas de densidad/área, a medida que el ÁREA DE DISEÑO asumida aumenta, la DENSIDAD requerida generalmente:", opts:["Aumenta","Cae a cero","Permanece constante","Disminuye"], re:"Las curvas clásicas permiten al diseñador intercambiar un área de diseño mayor por una densidad requerida menor (o un área menor por mayor densidad). Compensación de la curva de densidad/área de NFPA 13."},
  {id:224, q:"Una clasificación de riesgo más alta (contenidos más combustibles) generalmente requiere:", opts:["Una densidad de aplicación de agua más alta","Una densidad menor y un área menor","Ningún rociador en absoluto","Solo detección de humo"], re:"Una mayor carga de combustible y una liberación de calor más rápida requieren una densidad de aplicación de agua más alta para controlar el incendio. Base de la clasificación de riesgo de NFPA 13."},
  {id:225, q:"¿Cuál de estas se clasifica normalmente como ocupación de Riesgo Ordinario (Grupo 2)?", opts:["Una oficina privada","Un taller mecánico o comercio con combustibles moderados","El santuario de una iglesia","Una plataforma de estacionamiento abierta sin almacenamiento"], re:"Las ocupaciones con contenidos combustibles de moderados a altos (talleres mecánicos, muchos usos comerciales/manufactureros) caen en Riesgo Ordinario Grupo 2. Clasificación de ocupación de NFPA 13."},
  {id:226, q:"En el método de densidad/área, la demanda mínima total de agua para los rociadores se determina mediante:", opts:["Sumar los factores K","Densidad ÷ área","Área ÷ densidad","Densidad × área de diseño (más la asignación para mangueras)"], re:"La demanda de los rociadores ≈ densidad × área de diseño; luego se agregan una asignación para chorros de manguera y la fricción/elevación para dimensionar el suministro. Demanda de densidad/área de NFPA 13."},
  {id:227, q:"Una asignación para chorros de manguera (manguera interior/exterior) se AGREGA a la demanda de los rociadores en el punto de:", opts:["La base del montante / punto de conexión al suministro","Cada rociador individual","Solo el rociador más remoto","El ático"], re:"Las asignaciones de manguera interior y exterior se agregan a la demanda del sistema en la base del montante o en la conexión de suministro, no en cada rociador. Asignación para chorros de manguera de NFPA 13."},
  {id:228, q:"La duración del suministro de agua (minutos) requerida generalmente AUMENTA a medida que la clasificación de riesgo:", opts:["Se vuelve más ligera","Es irrelevante","No tiene efecto en la duración","Se vuelve más alta (más peligrosa)"], re:"Los riesgos más altos requieren tanto una densidad más alta COMO duraciones de suministro más largas (p. ej., Ligero ~30 min frente a Ordinario/Extra más largo). Duración del suministro de agua de NFPA 13."},
  {id:229, q:"Cuando el rociador hidráulicamente más remoto se calcula primero, el cálculo luego procede:", opts:["De regreso hacia el suministro de agua, acumulando pérdidas","Solo hacia el extremo cerrado","En orden aleatorio","Solo en la bomba"], re:"Los cálculos comienzan en el rociador más remoto y avanzan de regreso hacia el suministro, sumando los caudales y acumulando las pérdidas por fricción y elevación. Procedimiento de cálculo hidráulico de NFPA 13."},
  {id:230, q:"Las ediciones de NFPA 13 a partir de alrededor de 2022 cambiaron el enfoque de densidad/área al:", opts:["Limitar las curvas de densidad/área de múltiples puntos a los sistemas existentes y hacer de la densidad de un solo punto el valor predeterminado para el trabajo nuevo","Eliminar los rociadores por completo","Duplicar cada valor de densidad","Prohibir los cálculos hidráulicos"], re:"NFPA 13 (2022) limitó las curvas clásicas de densidad/área a la evaluación de sistemas existentes e hizo de la densidad de un solo punto (de la tabla de riesgos) el valor predeterminado para el diseño nuevo. NFPA 13 (2022) Cap. 19."},
  {id:231, q:"En el enfoque de densidad de 'un solo punto', el diseñador usa:", opts:["Cualquier punto de una curva que elija","Una densidad y un área fijas definidas por la tabla de clasificación de riesgo","Solo la placa de datos de la bomba","Solo el esquema de tubería"], re:"El diseño de un solo punto fija la densidad y el área de diseño según la clasificación de riesgo (sin selección libre a lo largo de una curva). Densidad de un solo punto de NFPA 13 (2022)."},
  {id:232, q:"En comparación con el Riesgo Ligero, un área de Riesgo Ordinario generalmente necesita rociadores que entreguen:", opts:["Menos agua","Nada de agua","Más agua (mayor densidad)","Lo mismo sin importar el riesgo"], re:"El Riesgo Ordinario requiere una densidad de aplicación más alta que el Riesgo Ligero, por lo que cada rociador en operación debe entregar más agua. Comparación de densidad de NFPA 13."},
  {id:233, q:"El caudal mínimo que cada rociador debe entregar en un sistema calculado depende de su:", opts:["Solo el color","Solo el tamaño de la rosca","El logotipo del fabricante","Área de cobertura × densidad requerida"], re:"El caudal mínimo de cada rociador = su área de cobertura protegida × la densidad de diseño requerida. Cálculo de densidad/área de NFPA 13."},
  {id:234, q:"Seleccionar un ÁREA de diseño MAYOR (más rociadores en operación) de la requerida generalmente hará que la demanda de agua calculada sea:", opts:["Mayor / más conservadora","Sin cambios","Menor","Cero"], re:"Más rociadores en operación significa más caudal total y fricción, lo que aumenta la demanda — un diseño más conservador (y más costoso). Selección de densidad/área de NFPA 13."},
  {id:235, q:"La fórmula empírica adoptada por NFPA 13 para calcular la pérdida por fricción (flujo) en la tubería de rociadores es la:", opts:["Ley de Boyle","Ley de Ohm","Fórmula de Hazen-Williams","Ley de Charles"], re:"NFPA 13 usa la fórmula de Hazen-Williams para calcular la pérdida por fricción en tuberías de protección contra incendios llenas de agua. Método de cálculo hidráulico de NFPA 13."},
  {id:236, q:"En la fórmula de Hazen-Williams, el valor 'C' representa la:", opts:["Costo","Rugosidad / lisura interna de la tubería","Código de color","Largo en pies"], re:"El factor C (coeficiente) describe la rugosidad interior de la tubería — un C mayor significa una tubería más lisa y menor pérdida por fricción. Hazen-Williams (NFPA 13)."},
  {id:237, q:"Un valor C de Hazen-Williams MÁS ALTO indica una tubería que produce:", opts:["Más pérdida por fricción","Ningún flujo","Menos pérdida por fricción (interior más liso)","Mayor elevación"], re:"Un C mayor = interior más liso = menor pérdida por fricción para un caudal dado. Significado del factor C de Hazen-Williams (NFPA 13)."},
  {id:238, q:"El valor C de Hazen-Williams típicamente usado para tubería de hierro fundido / hierro dúctil SIN REVESTIMIENTO es:", opts:["150","120","130","100"], re:"Al hierro fundido/dúctil sin revestimiento se le asigna C = 100 en la tabla de pérdida por fricción de NFPA 13 (considera el envejecimiento/tuberculación). Tabla de valores C de NFPA 13."},
  {id:239, q:"El valor C de Hazen-Williams usado para tubería de acero negro o galvanizado en sistemas de rociadores HÚMEDOS es:", opts:["80","100","150","120"], re:"A la tubería de acero en sistemas húmedos (y de diluvio) se le asigna C = 120; el acero en sistemas secos/de preacción usa C = 100. Tabla de valores C de NFPA 13."},
  {id:240, q:"El valor C de Hazen-Williams usado para tubo de cobre y la mayoría de las tuberías plásticas listadas (CPVC) es:", opts:["100","120","150","140"], re:"Al tubo de cobre y al plástico listado (CPVC) se les asigna C = 150 — los materiales comunes más lisos, que dan la menor pérdida por fricción. Tabla de valores C de NFPA 13."},
  {id:241, q:"A la tubería de acero en un sistema SECO o de PREACCIÓN se le asigna un valor C de Hazen-Williams de:", opts:["120","100","130","150"], re:"Como la corrosión interna es mayor en los sistemas secos/de preacción, la tubería de acero en ellos usa C = 100 (frente a 120 para el acero húmedo). Tabla de valores C de NFPA 13."},
  {id:242, q:"Para un caudal y un tamaño de tubería dados, la pérdida por fricción es MAYOR en la tubería con qué valor C?", opts:["C = 150","C = 120","C = 140","C = 100"], re:"El C más bajo (tubería más rugosa) produce la mayor pérdida por fricción; C = 100 (p. ej., hierro sin revestimiento, acero de sistema seco) es el peor de los listados. Hazen-Williams (NFPA 13)."},
  {id:243, q:"En la fórmula de Hazen-Williams, la pérdida por fricción es más sensible a (aumenta más pronunciadamente con) el:", opts:["La rosca del rociador","El color de la tubería","La temperatura ambiente","Caudal Q"], re:"La pérdida por fricción aumenta con el caudal elevado a aproximadamente la potencia 1.85, por lo que duplicar el caudal casi cuadruplica la pérdida. Exponente de Q en Hazen-Williams (NFPA 13)."},
  {id:244, q:"En la relación de fricción de tubería de Hazen-Williams, la pérdida por fricción varía inversamente con el DIÁMETRO de la tubería elevado a una potencia cercana a:", opts:["4.87","1.85","1.0","10"], re:"El diámetro aparece elevado a aproximadamente la potencia 4.87 en el denominador, por lo que un pequeño aumento en el diámetro de la tubería reduce notablemente la pérdida por fricción. Hazen-Williams (NFPA 13)."},
  {id:245, q:"Si el caudal en una tubería se duplica aproximadamente (y el tamaño de la tubería no cambia), la pérdida por fricción de Hazen-Williams aumentará en aproximadamente:", opts:["Sin cambio","Unas 2 veces","Unas 4 veces (≈3.6×)","Unas 10 veces"], re:"Como Q se eleva a ~1.85, duplicar el caudal multiplica la pérdida por fricción por unas 2^1.85 ≈ 3.6, es decir, casi 4×. Hazen-Williams (NFPA 13)."},
  {id:246, q:"Los accesorios y válvulas (codos, tes, válvulas de retención) se contabilizan en los cálculos hidráulicos usando:", opts:["El número de pernos","Su peso en libras","El color de su pintura","Longitudes equivalentes de tubería"], re:"NFPA 13 convierte cada accesorio/válvula en una 'longitud equivalente' de tubería que se agrega a la longitud real de tubería antes de calcular la pérdida por fricción. Método de longitud equivalente de NFPA 13."},
  {id:247, q:"Cuando el valor C de una tubería difiere de la base C = 120 usada para tabular las longitudes equivalentes de los accesorios, las longitudes equivalentes deben:", opts:["Ignorarse","Ponerse a cero","Duplicarse siempre","Ajustarse (multiplicarse) por una corrección del factor C"], re:"Las longitudes equivalentes de los accesorios se tabulan para C = 120 y deben multiplicarse por un factor de corrección cuando el valor C real de la tubería difiere. Ajuste de longitud equivalente de accesorios de NFPA 13."},
  {id:248, q:"La forma más eficaz de REDUCIR la pérdida por fricción en un tramo largo de tubería de rociadores es:", opts:["Usar una tubería más rugosa","Agregar más codos","Aumentar el diámetro de la tubería","Bajar el valor C"], re:"Como la pérdida varía inversamente con el diámetro elevado a ~4.87, aumentar el tamaño de la tubería es por mucho la forma más eficaz de reducir la pérdida por fricción. Sensibilidad al diámetro de Hazen-Williams (NFPA 13)."},
  {id:249, q:"La fórmula de Hazen-Williams está destinada específicamente al flujo de:", opts:["Agua (flujo turbulento) en tuberías","Aire comprimido","Vapor","Electricidad"], re:"Hazen-Williams es una ecuación empírica para el agua que fluye en tuberías en condiciones turbulentas — exactamente el caso en la protección contra incendios a base de agua. Alcance de Hazen-Williams (NFPA 13)."},
  {id:250, q:"En comparación con el acero nuevo y limpio, una tubería de acero VIEJA con tuberculación (corroída) se comporta efectivamente como si tuviera un valor C que es:", opts:["Mayor","Exactamente 150","Menor","Sin cambios"], re:"La corrosión interna y la tuberculación dan rugosidad al interior y reducen el valor C efectivo, aumentando la pérdida por fricción a lo largo de la vida de la tubería. Envejecimiento del factor C de Hazen-Williams (base de NFPA 13)."},
  {id:251, q:"Dos tuberías idénticas conducen el mismo caudal; la tubería A es de cobre (C=150) y la tubería B es de acero de sistema seco (C=100). ¿Cuál tiene la MENOR pérdida por fricción?", opts:["Tubería A (cobre, C=150)","Tubería B (acero, C=100)","Son idénticas","No se puede determinar"], re:"El valor C más alto (cobre, C=150) es más liso y produce una menor pérdida por fricción para el mismo caudal. Comparación de C de Hazen-Williams (NFPA 13)."},
  {id:252, q:"En una prueba de caudal de hidrante, la 'presión estática' se lee en el hidrante residual:", opts:["Solo después de que termina la prueba","Mientras el hidrante de prueba está completamente abierto","Sin ningún hidrante fluyendo","Dentro de la bomba"], re:"La presión estática se toma en el hidrante residual (de manómetro de prueba) antes de abrir cualquier hidrante para que fluya. Procedimiento de prueba de caudal de hidrante de NFPA 291."},
  {id:253, q:"Durante una prueba de caudal de hidrante, la 'presión residual' se lee en el hidrante residual:", opts:["Antes de que comience el flujo","Mientras el agua fluye del/de los hidrante(s) de flujo","Con todos los hidrantes cerrados","En el embalse de la ciudad"], re:"La presión residual es la lectura del manómetro en el hidrante residual mientras el/los hidrante(s) de flujo descargan agua; la caída de estática a residual revela la fuerza del suministro. NFPA 291."},
  {id:254, q:"Un manómetro de pitot sostenido en el chorro de una salida de hidrante que fluye mide la:", opts:["Presión estática","Carga de elevación","Presión de velocidad del chorro que descarga (para calcular el caudal)","Presión de aire"], re:"El pitot lee la presión de velocidad del chorro, que se convierte en caudal (gpm) usando el tamaño de la salida y el coeficiente de descarga. Método de pitot de NFPA 291."},
  {id:255, q:"La fórmula general para el caudal de un hidrante/boquilla usando una lectura de pitot es Q = 29.83 × c × d² × √P, donde 'd' es el:", opts:["Distancia al incendio","Número de salidas","Profundidad de la tubería principal","Diámetro de la salida (orificio) en pulgadas"], re:"En Q = 29.83·c·d²·√P, d es el diámetro de la salida de descarga (pulg.), c es el coeficiente y P es la presión de pitot (psi). Fórmula de caudal de hidrante de NFPA 291 / IFSTA."},
  {id:256, q:"Una prueba de caudal de suministro de agua se usa típicamente para establecer el agua disponible a una presión residual de:", opts:["0 psi","20 psi","100 psi","175 psi"], re:"Los resultados comúnmente se proyectan al caudal disponible a 20 psi residual, el valor usado para la codificación por colores de los hidrantes y el diseño. NFPA 291 (20 psi residual)."},
  {id:257, q:"Para obtener resultados confiables en la prueba de hidrante, NFPA 291 recomienda dejar fluir suficiente agua para reducir la presión residual en al menos:", opts:["5%","10%","25%","75%"], re:"Una caída de presión de al menos 25% respecto a la estática mejora la exactitud al proyectar el caudal disponible a otras presiones. Caída recomendada por NFPA 291."},
  {id:258, q:"En la escala de codificación por colores de hidrantes de NFPA 291, un hidrante que entrega 1,500 gpm o más a 20 psi se pinta (con tapas) con qué color de CLASE?", opts:["Rojo","Azul claro","Verde","Naranja"], re:"NFPA 291 marca los hidrantes Clase AA (≥1,500 gpm a 20 psi) de azul claro; verde = 1,000–1,499, naranja = 500–999, rojo = menos de 500 gpm. Clases de color de NFPA 291."},
  {id:259, q:"En la escala de NFPA 291, una cúpula/tapa de hidrante ROJA indica un caudal disponible a 20 psi de:", opts:["1,500 gpm o más","500–999 gpm","1,000–1,499 gpm","Menos de 500 gpm"], re:"El rojo marca los hidrantes más débiles — menos de 500 gpm disponibles a 20 psi residual. Clases de color de NFPA 291."},
  {id:260, q:"Una tubería principal de agua municipal (de la ciudad) suministrada a un edificio es un ejemplo de:", opts:["Fuente de suministro de agua pública","Bomba contra incendios privada","Tanque por gravedad","Tanque a presión"], re:"La tubería principal municipal/de la ciudad es un suministro de agua público; los tanques, embalses y bombas privados lo complementan cuando es inadecuado. Fuentes de suministro de agua de NFPA 13."},
  {id:261, q:"Un tanque de almacenamiento por gravedad (elevado) suministra presión de protección contra incendios principalmente a través de:", opts:["Aire comprimido sobre el agua","Su elevación/altura por encima del sistema (carga)","Un calentador eléctrico","Un motor diésel"], re:"Un tanque por gravedad desarrolla presión a partir de su altura — cada pie de elevación agrega unos 0.433 psi en la base. Principio del tanque por gravedad de NFPA 22."},
  {id:262, q:"Un tanque a presión proporciona agua bajo presión manteniendo un colchón de:", opts:["Vapor","Aire comprimido sobre el agua almacenada","Vacío","Arena"], re:"Un tanque a presión se llena parcialmente con agua y se presuriza con aire comprimido para que el agua descargue de inmediato a demanda. Tanque a presión de NFPA 22."},
  {id:263, q:"La norma que rige el diseño y la construcción de tanques de almacenamiento de agua para protección privada contra incendios es:", opts:["NFPA 13","NFPA 14","NFPA 20","NFPA 22"], re:"NFPA 22 cubre los tanques de agua (por gravedad, de succión, a presión, de terraplén) usados para la protección privada contra incendios. Alcance de NFPA 22."},
  {id:264, q:"La norma que cubre la instalación de TUBERÍAS PRINCIPALES PRIVADAS DEL SERVICIO CONTRA INCENDIOS y sus accesorios (suministro subterráneo a un sitio) es:", opts:["NFPA 24","NFPA 13D","NFPA 25","NFPA 72"], re:"NFPA 24 rige las tuberías principales privadas del servicio contra incendios — la tubería subterránea, válvulas e hidrantes que suministran agua a una propiedad. Alcance de NFPA 24."},
  {id:265, q:"La CAPACIDAD (volumen) requerida de un tanque de almacenamiento para protección contra incendios se determina por:", opts:["El color del tanque","La demanda de caudal de incendio (gpm) multiplicada por la duración requerida (minutos)","El número de pernos","Solo los caballos de fuerza de la bomba"], re:"Volumen del tanque = caudal de incendio requerido (gpm) × duración del suministro requerida (minutos), establecidos por la demanda del sistema y el riesgo. Dimensionamiento del suministro de NFPA 22 / NFPA 13."},
  {id:266, q:"Un tanque de SUCCIÓN a nivel del suelo se diferencia de un tanque por gravedad en que:", opts:["Desarrolla toda la presión del sistema solo por elevación","No necesita bomba ni elevación","Usa solo aire comprimido","Alimenta una bomba contra incendios que aumenta la presión"], re:"Un tanque de succión (a nivel del suelo) almacena agua a baja elevación y alimenta una bomba contra incendios que proporciona la presión necesaria. Tanque de succión de NFPA 22 / NFPA 20."},
  {id:267, q:"Cuando la tubería principal pública no puede suministrar el caudal Y la presión de incendio requeridos, el remedio habitual es agregar un(a):", opts:["Capa de pintura más grande","Segundo drenaje de techo","Tubería más pequeña","Bomba contra incendios y/o tanque de almacenamiento"], re:"Un suministro público inadecuado se complementa con una fuente de agua almacenada (tanque/embalse) y/o una bomba contra incendios para satisfacer la demanda. Disposiciones de suministro de agua de NFPA 13 / NFPA 20."},
  {id:268, q:"En las pruebas de hidrantes, si la caída de presión de estática a residual es muy PEQUEÑA mientras fluye una gran cantidad, el suministro de agua es:", opts:["Muy débil","Fuerte (abundante)","Congelado","Desconectado"], re:"Una caída de presión pequeña bajo flujo intenso indica un suministro fuerte y abundante; una caída grande indica un suministro débil. Interpretación de resultados de prueba de NFPA 291."},
  {id:269, q:"La norma para la instalación de bombas estacionarias para protección contra incendios es:", opts:["NFPA 20","NFPA 14","NFPA 13","NFPA 25"], re:"NFPA 20 rige la selección e instalación de bombas contra incendios estacionarias y sus impulsores, controladores y accesorios. Alcance de NFPA 20."},
  {id:270, q:"El tipo de bomba contra incendios más común usado para la protección contra incendios a base de agua es la:", opts:["Bomba centrífuga horizontal de carcasa partida","Bomba de pistón de desplazamiento positivo","Bomba manual","Bomba peristáltica"], re:"Las bombas centrífugas (comúnmente horizontales de carcasa partida) son el tipo estándar de bomba contra incendios; las bombas de desplazamiento positivo se limitan a usos especiales como espuma/agua nebulizada. Tipos de bombas de NFPA 20."},
  {id:271, q:"En la curva de rendimiento de una bomba contra incendios, el 'churn' (cierre o caudal cero) es la condición en la que la bomba opera a:", opts:["Caudal cero (sin descarga)","100% del caudal nominal","150% del caudal nominal","Sobrecarga máxima"], re:"El churn (cierre) es la operación a caudal cero; la bomba recircula internamente y produce su carga máxima. Curva de la bomba de NFPA 20 (punto de churn)."},
  {id:272, q:"En el CHURN (caudal cero), NFPA 20 limita la carga (presión) total a no más de qué porcentaje de la presión nominal?", opts:["100%","121%","140%","175%"], re:"La presión de churn (cierre) no debe exceder el 140% de la presión nominal para una bomba contra incendios listada. Límite de presión de churn de NFPA 20."},
  {id:273, q:"Al 150% del caudal nominal (el punto de sobrecarga), una bomba contra incendios aún debe producir una carga total de al menos:", opts:["50% de la carga nominal","65% de la carga nominal","100% de la carga nominal","140% de la carga nominal"], re:"Al 150% de la capacidad nominal, la bomba debe entregar no menos del 65% de su carga total nominal. Requisito del punto de sobrecarga de NFPA 20."},
  {id:274, q:"El punto 'nominal' de una bomba contra incendios es donde entrega:", opts:["Caudal cero a carga máxima","Presión de churn","150% de caudal al 65% de carga","100% de la capacidad nominal al 100% de la carga nominal"], re:"El punto nominal (100%) es el caudal y la presión listados que la bomba se selecciona para proporcionar. Punto nominal de NFPA 20."},
  {id:275, q:"Los tres puntos verificados durante una prueba de caudal de aceptación de una bomba contra incendios son el churn (caudal cero), el 100% del caudal nominal y:", opts:["50% del caudal nominal","125% del caudal nominal","150% del caudal nominal","200% del caudal nominal"], re:"NFPA 20 requiere pruebas en el churn, el 100% y el 150% de la capacidad nominal para verificar la curva de rendimiento de la bomba. Puntos de caudal de la prueba de aceptación de NFPA 20."},
  {id:276, q:"Una bomba pequeña que mantiene la presión del sistema entre límites preestablecidos cuando no fluye agua se llama:", opts:["Bomba jockey (de mantenimiento de presión)","Bomba de alivio de refuerzo","Bomba de sumidero","Bomba de cebado"], re:"La bomba jockey (de mantenimiento de presión) compensa fugas menores para que la bomba contra incendios principal no cicle ante pequeñas caídas de presión. Bomba jockey de NFPA 20."},
  {id:277, q:"Una bomba jockey debe dimensionarse para entregar un caudal que sea:", opts:["Mayor que el de la bomba contra incendios","Al menos el 150% del caudal nominal","Exactamente igual al de la bomba contra incendios","Menor que el caudal de un solo rociador"], re:"La bomba jockey se dimensiona para compensar la fuga permitida — menos que el caudal de un rociador — de modo que la operación real de un rociador obligue a la bomba principal a arrancar. Guía de dimensionamiento de la bomba jockey de NFPA 20."},
  {id:278, q:"Los ajustes típicos del presostato se disponen de modo que la bomba JOCKEY arranque y se detenga:", opts:["A presiones más altas que la bomba contra incendios (por encima del punto de arranque de la bomba contra incendios)","A presiones más bajas que la bomba contra incendios","Solo cuando funciona la bomba contra incendios","Nunca automáticamente"], re:"Los ajustes de arranque/parada de la bomba jockey están por encima del punto de arranque de la bomba contra incendios para que la jockey maneje las fugas pequeñas y la bomba contra incendios solo arranque ante una demanda real. Jerarquía de ajustes de presión de NFPA 20."},
  {id:279, q:"Una vez que una bomba contra incendios accionada ELÉCTRICAMENTE arranca automáticamente, generalmente se requiere que su controlador:", opts:["La detenga después de 10 segundos","Requiera apagado manual (no se detenga automáticamente) a menos que esté dispuesta para parada automática con un temporizador de tiempo mínimo de funcionamiento","La haga funcionar durante exactamente 1 minuto","La encienda y apague rápidamente"], re:"NFPA 20 generalmente requiere el apagado manual de la bomba contra incendios después del arranque automático; cuando se permite la parada automática, aplica un temporizador de tiempo mínimo de funcionamiento. Requisitos de controlador/parada de NFPA 20."},
  {id:280, q:"Una bomba contra incendios accionada por un motor DIÉSEL debe contar con un suministro de combustible dimensionado para al menos el tiempo de funcionamiento de diseño, y el controlador del motor debe incluir:", opts:["Solo una batería","Ninguna batería","Dos bancos de baterías de almacenamiento (baterías duales)","Un arrancador solo de CA"], re:"Los controladores de bombas contra incendios diésel requieren dos unidades de batería de almacenamiento separadas para que el arranque del motor sea confiable si falla un banco. Baterías del controlador diésel de NFPA 20."},
  {id:281, q:"Una válvula de alivio de circulación (de carcasa) en una bomba contra incendios se proporciona principalmente para:", opts:["Aumentar la presión de descarga","Aliviar la acumulación de calor permitiendo un pequeño flujo durante la operación de churn (caudal cero)","Cebar la bomba","Reemplazar la válvula de retención"], re:"La pequeña válvula de alivio de carcasa/circulación descarga un poco de agua durante el churn para evitar que la bomba se sobrecaliente al funcionar a caudal cero. Válvula de alivio de circulación de NFPA 20."},
  {id:282, q:"Se requiere una válvula de alivio PRINCIPAL en una bomba contra incendios cuando el sistema podría exponerse a presiones que:", opts:["Podrían exceder la presión nominal de los componentes del sistema (p. ej., sobrevelocidad del diésel)","Siempre son seguras","Nunca ocurren","Igualan la presión atmosférica"], re:"Una válvula de alivio de presión principal protege los componentes cuando es posible una sobrepresión (p. ej., el motor diésel funcionando por encima de la velocidad nominal, o presiones superiores a la nominal del sistema). Válvula de alivio principal de NFPA 20."},
  {id:283, q:"Para evitar que la bomba contra incendios cicle (arranque/parada rápidos) ante fugas menores, el sistema depende de la:", opts:["Drenaje principal","Válvula de prueba del inspector","Bomba jockey y los ajustes de presión adecuados","Detector de humo"], re:"La bomba jockey maneja las fugas pequeñas para que la bomba contra incendios principal no arranque ante caídas de presión menores, evitando ciclos cortos dañinos. Función de mantenimiento de presión de NFPA 20."},
  {id:284, q:"Una bomba contra incendios debe ser capaz de proporcionar su caudal requerido incluso cuando la presión de suministro en la succión sea tan baja como el valor mínimo permitido por la AHJ, y NFPA 20 requiere que la presión de succión al 150% del caudal permanezca al menos en:", opts:["100 psi","50 psi","0 psi (no negativa)","175 psi"], re:"NFPA 20 generalmente requiere que la presión del manómetro de succión permanezca en 0 psi o más alta cuando la bomba funciona al 150% del caudal nominal (solo se permite un pequeño valor negativo para arreglos listados de tanque de succión a nivel del suelo). Requisito de presión de succión de NFPA 20."},
  {id:285, q:"Una bomba contra incendios se instala principalmente para:", opts:["Enfriar el edificio","Detectar humo","Almacenar agua durante meses","Aumentar la presión y/o el caudal de agua para satisfacer la demanda del sistema"], re:"Una bomba contra incendios aumenta la presión (y proporciona caudal) cuando el suministro disponible no puede satisfacer la demanda de los rociadores/tubos verticales. Propósito de las bombas contra incendios de NFPA 20."},
  {id:286, q:"La norma para la instalación de sistemas de tubos verticales y mangueras es:", opts:["NFPA 14","NFPA 13","NFPA 20","NFPA 24"], re:"NFPA 14 rige el diseño y la instalación de sistemas de tubos verticales y mangueras en edificios. Alcance de NFPA 14."},
  {id:287, q:"Un sistema de tubo vertical Clase I proporciona qué tamaño de conexión de manguera, destinada al uso del cuerpo de bomberos?", opts:["1 pulgada","2½ pulgadas","1½ pulgadas","4 pulgadas"], re:"La Clase I proporciona conexiones de manguera de 2½ pulg. para bomberos capacitados / uso del cuerpo de bomberos. Clase I de NFPA 14."},
  {id:288, q:"Un sistema de tubo vertical Clase II proporciona estaciones de manguera de 1½ pulgadas destinadas principalmente al uso por:", opts:["Solo el cuerpo de bomberos","Plomeros","Ocupantes capacitados del edificio / combate inicial de incendios","Técnicos de ascensores"], re:"La Clase II suministra manguera de 1½ pulg. (a menudo en un estante/carrete) para el combate inicial de incendios por los ocupantes. Clase II de NFPA 14."},
  {id:289, q:"Un sistema de tubo vertical Clase III proporciona:", opts:["Solo conexiones de 1 pulgada","Conexiones de manguera de 2½ pulgadas y de 1½ pulgadas (funciones Clase I + Clase II)","Ninguna conexión de manguera","Solo rociadores"], re:"La Clase III combina las funciones de la Clase I (2½ pulg.) y la Clase II (1½ pulg.), sirviendo tanto al uso del cuerpo de bomberos como al de los ocupantes. Clase III de NFPA 14."},
  {id:290, q:"Para un tubo vertical Clase I o Clase III, NFPA 14 requiere una presión RESIDUAL mínima en la salida de 2½ pulgadas más alta (más remota) de al menos:", opts:["100 psi","65 psi","150 psi","175 psi"], re:"NFPA 14 requiere 100 psi residuales en la salida de 2½ pulg. hidráulicamente más remota (para el caudal requerido). Presión Clase I/III de NFPA 14."},
  {id:291, q:"Para un tubo vertical Clase II, NFPA 14 requiere una presión residual mínima en la salida de 1½ pulgadas más remota de al menos:", opts:["25 psi","100 psi","65 psi","175 psi"], re:"NFPA 14 requiere 65 psi residuales en la conexión de manguera de 1½ pulg. más remota para el caudal Clase II requerido. Presión Clase II de NFPA 14."},
  {id:292, q:"El caudal mínimo usado para dimensionar el tubo vertical Clase I más remoto (primer montante/el más remoto) es:", opts:["500 gpm","250 gpm","100 gpm","1,000 gpm"], re:"El tubo vertical Clase I más remoto se dimensiona para 500 gpm (a través de las dos salidas de 2½ pulg. más remotas). Caudal Clase I de NFPA 14."},
  {id:293, q:"Por cada tubo vertical ADICIONAL más allá del más remoto, NFPA 14 generalmente agrega una asignación de caudal de:", opts:["50 gpm","100 gpm","500 gpm","250 gpm"], re:"Cada tubo vertical adicional agrega 250 gpm a la demanda (para áreas de piso que no excedan el umbral). Caudal de tubo vertical adicional de NFPA 14."},
  {id:294, q:"El caudal mínimo para una estación de manguera de tubo vertical Clase II es:", opts:["50 gpm","500 gpm","250 gpm","100 gpm"], re:"Una estación de manguera Clase II se dimensiona para 100 gpm en la conexión de 1½ pulg. más remota. Caudal Clase II de NFPA 14."},
  {id:295, q:"NFPA 14 limita la demanda total requerida del sistema de tubos verticales para un edificio totalmente rociado a:", opts:["1,000 gpm","500 gpm","1,250 gpm","2,000 gpm"], re:"La demanda total Clase I no necesita exceder 1,000 gpm en un edificio protegido en su totalidad por rociadores (1,250 gpm donde no está totalmente rociado). Demanda máxima de NFPA 14."},
  {id:296, q:"NFPA 14 limita la demanda total requerida de tubos verticales para un edificio que NO está totalmente rociado a:", opts:["750 gpm","1,000 gpm","1,250 gpm","2,500 gpm"], re:"Para edificios no protegidos en su totalidad por rociadores, la demanda total del tubo vertical Clase I no necesita exceder 1,250 gpm. Demanda máxima de NFPA 14."},
  {id:297, q:"Donde la presión estática en una conexión de manguera EXCEDERÍA los 175 psi, NFPA 14 requiere el uso de:", opts:["Un rociador más grande","Ningún dispositivo especial","Solo una válvula de retención","Una válvula reductora de presión (PRV) o dispositivo regulador de presión"], re:"Para mantener las presiones de las conexiones de manguera utilizables y dentro de los límites, se requieren dispositivos reguladores/reductores de presión donde la presión estática excede unos 175 psi. Requisito de regulación de presión de NFPA 14."},
  {id:298, q:"Un sistema de tubo vertical 'húmedo' se diferencia de uno 'seco' (o automático-seco) en que el sistema húmedo:", opts:["No tiene fuente de agua","Usa solo la autobomba del cuerpo de bomberos para el agua","Está lleno de agua en todo momento","No tiene conexiones de manguera"], re:"Un tubo vertical húmedo contiene agua en todo momento de modo que el flujo es inmediato; un tubo vertical seco normalmente está vacío y se llena cuando se necesita (manual o automáticamente). Tubo vertical húmedo vs. seco de NFPA 14."},
  {id:299, q:"Una conexión del cuerpo de bomberos (FDC) en un sistema de tubo vertical le permite al cuerpo de bomberos:", opts:["Bombear agua/presión adicional al tubo vertical desde una autobomba","Drenar el sistema","Apagar los rociadores","Probar las alarmas de humo"], re:"La FDC permite que el equipo que responde aumente el agua y la presión en el sistema de tubo vertical/rociadores para apoyar el combate del incendio. Conexión del cuerpo de bomberos de NFPA 14."},
  {id:300, q:"En un edificio de gran altura, generalmente se requiere que las conexiones de manguera de tubo vertical se ubiquen:", opts:["Solo en el vestíbulo","Solo en el techo","En las escaleras de salida (y según se requiera en cada nivel de piso)","En la cabina del ascensor"], re:"Las conexiones de manguera de tubo vertical se ubican en las escaleras de salida (y otros puntos requeridos) para que los bomberos puedan conectarse en cada piso en una ubicación protegida. Ubicación de la conexión de manguera de NFPA 14."},
  {id:301, q:"NFPA 25 es la norma para la inspección, prueba y mantenimiento (ITM) de:", opts:["Sistemas de protección contra incendios a base de agua","Extintores portátiles de incendios","Solo sistemas de alarma contra incendios","Iluminación de emergencia"], re:"NFPA 25 se titula Norma para la Inspección, Prueba y Mantenimiento de Sistemas de Protección contra Incendios a Base de Agua, y abarca rociadores, tuberías verticales (standpipe), bombas contra incendios y sistemas relacionados (NFPA 25 Cap. 1)."},
  {id:302, q:"Según NFPA 25, la parte responsable en última instancia de conservar los registros de ITM y ponerlos a disposición de la AHJ es:", opts:["El contratista de rociadores","El propietario de la propiedad o su representante designado","El departamento de bomberos","La compañía de seguros"], re:"NFPA 25 Cap. 4 (Responsabilidades del Propietario) asigna la responsabilidad de la ITM, el mantenimiento de registros y la entrega de registros a la AHJ al propietario de la propiedad o su representante designado."},
  {id:303, q:"NFPA 25 define una frecuencia 'anual' como aquella que ocurre una vez al año dentro de un rango de:", opts:["Exactamente 12 meses solamente","Mínimo 6 meses, máximo 18 meses","Mínimo 9 meses, máximo 15 meses","Mínimo 11 meses, máximo 13 meses"], re:"NFPA 25 define anual como una vez al año con un mínimo de 9 meses y un máximo de 15 meses entre actividades (definiciones de frecuencia de NFPA 25, Cap. 3)."},
  {id:304, q:"Según NFPA 25, la prueba de drenaje principal en cada montante (riser) del sistema se realiza al menos:", opts:["Semanalmente","Mensualmente","Cada 5 años","Anualmente"], re:"NFPA 25 (Cap. 13) exige una prueba de drenaje principal al menos anualmente en cada montante del sistema a base de agua para detectar un cambio en el suministro de agua o en las válvulas de control."},
  {id:305, q:"¿Con qué frecuencia debe realizarse una prueba de flujo directo (forward flow) de un preventor de reflujo en un sistema de protección contra incendios según NFPA 25?", opts:["Anualmente","Trimestralmente","Cada 3 años","Cada 5 años"], re:"NFPA 25 (Cap. 13) exige que los conjuntos de prevención de reflujo en la tubería de protección contra incendios se sometan a una prueba de flujo directo anualmente a la tasa de flujo de demanda del sistema."},
  {id:306, q:"Una prueba de disparo a flujo total (full-flow trip test) de una válvula de tubería seca debe realizarse al menos cada:", opts:["Año","3 años","2 años","5 años"], re:"NFPA 25 (Cap. 13) exige una prueba de disparo a flujo total de las válvulas de tubería seca al menos cada 3 años, además de la prueba de disparo parcial anual (por la línea de cebado)."},
  {id:307, q:"Según NFPA 25, los manómetros de presión del sistema deben reemplazarse o probarse por comparación con un manómetro calibrado al menos cada:", opts:["Año","3 años","5 años","10 años"], re:"NFPA 25 (Cap. 13) exige que los manómetros se reemplacen o se prueben contra un manómetro calibrado cada 5 años; los manómetros con un error superior al 3% de la escala completa se recalibran o reemplazan."},
  {id:308, q:"¿Con qué frecuencia mínima se prueban funcionalmente los dispositivos de alarma de flujo de agua en sistemas de tubería húmeda según NFPA 25?", opts:["Semanalmente","Mensualmente","Anualmente","Trimestralmente"], re:"NFPA 25 (Cap. 5) exige que los dispositivos de alarma de flujo de agua en sistemas de rociadores de tubería húmeda se prueben trimestralmente mediante la conexión de prueba del inspector."},
  {id:309, q:"Las soluciones anticongelantes en un sistema de rociadores deben probarse para verificar su concentración al menos:", opts:["Anualmente","Trimestralmente","Mensualmente","Cada 5 años"], re:"NFPA 25 (Cap. 5) exige que las soluciones anticongelantes se prueben al menos anualmente, antes del inicio del clima de congelación, para confirmar la protección adecuada contra el congelamiento."},
  {id:310, q:"Según NFPA 25, el examen interno de la tubería en busca de obstrucciones (la inspección interna de los 5 años) se realiza cada:", opts:["Año","5 años","3 años","10 años"], re:"NFPA 25 (Cap. 14) exige una inspección interna de la tubería en busca de material obstructor cada 5 años para detectar materia extraña, tuberculación, sedimentos o MIC."},
  {id:311, q:"¿Con qué frecuencia se prueban los interruptores de supervisión de válvula (interruptores antimanipulación, tamper) para verificar la señal correcta según NFPA 25?", opts:["Trimestralmente","Anualmente","Semestralmente","Cada 5 años"], re:"NFPA 25 (Cap. 13) exige que los interruptores de supervisión de válvula se prueben semestralmente (cada 6 meses) para verificar que se genere una señal cuando la válvula se mueve de su posición normal."},
  {id:312, q:"Los rociadores de respuesta estándar (fabricados en 1920 o después) requieren por primera vez la prueba de una muestra representativa a qué edad, y luego cada 10 años de allí en adelante?", opts:["20 años","100 años","75 años","50 años"], re:"NFPA 25 (Cap. 5) exige que los rociadores de respuesta estándar se prueben por muestra a los 50 años y cada 10 años de allí en adelante; a los 75 años el intervalo se reduce a cada 5 años (o reemplazar)."},
  {id:313, q:"Los rociadores de tipo seco (con un barril seco extendido) requieren la prueba de una muestra representativa comenzando a qué edad?", opts:["20 años","10 años","50 años","75 años"], re:"NFPA 25 (Cap. 5) exige que los rociadores de tipo seco se prueben por muestra 10 años después de la fabricación en ediciones más antiguas; el intervalo ampliamente citado es 20 años después de la instalación y luego cada 10 años (NFPA 25 2023)."},
  {id:314, q:"Según NFPA 25, los registros de ITM deben conservarse durante al menos:", opts:["30 días","1 año después de la siguiente inspección de ese tipo","6 meses","Para siempre"], re:"NFPA 25 Cap. 4 exige que los registros se conserven durante 1 año después de la siguiente actividad de ITM del mismo tipo (más tiempo si el código local, p. ej. IFC, exige más)."},
  {id:315, q:"En un sistema de tubería húmeda, el manómetro cercano a la válvula de alarma se inspecciona (se lee) con qué frecuencia mínima según NFPA 25?", opts:["Diariamente","Semanalmente","Mensualmente","Anualmente"], re:"NFPA 25 (Cap. 5/13) exige que los manómetros en sistemas de tubería húmeda se inspeccionen mensualmente para confirmar la presión normal del agua; los sistemas secos/de preacción se revisan semanalmente."},
  {id:316, q:"Un gong de motor de agua (alarma mecánica de flujo de agua) se prueba con qué frecuencia mínima según NFPA 25?", opts:["Cada 5 años","Semestralmente","Anualmente","Trimestralmente"], re:"NFPA 25 (Cap. 5) exige que los dispositivos mecánicos de flujo de agua, como un gong de motor de agua, se prueben trimestralmente; los dispositivos de interruptor de presión y de tipo paleta (vane) se prueban semestralmente."},
  {id:317, q:"¿Quién, según NFPA 25, debe estar calificado y ser competente para realizar la ITM en sistemas de protección contra incendios a base de agua?", opts:["Personal que ha desarrollado competencia mediante capacitación y experiencia","Cualquier ocupante del edificio","Solo un arquitecto registrado","Solo el jefe de bomberos"], re:"NFPA 25 Cap. 4 exige que la ITM sea realizada por personal calificado que ha desarrollado competencia mediante capacitación y experiencia; muchas jurisdicciones, incluida California, también exigen licencia/certificación."},
  {id:318, q:"La nueva tubería de rociadores debe someterse a una prueba hidrostática a qué presión mínima durante 2 horas según NFPA 13?", opts:["100 psi","200 psi","150 psi","300 psi"], re:"NFPA 13 exige que los sistemas nuevos de rociadores se sometan a una prueba hidrostática a no menos de 200 psi durante 2 horas (o 50 psi por encima de la presión estática máxima cuando esta supera los 150 psi)."},
  {id:319, q:"Cuando la presión estática normal supera los 150 psi, la presión de la prueba hidrostática de aceptación debe ser de al menos:", opts:["200 psi","El doble de la presión estática","50 psi por encima de la presión estática máxima","La misma que la presión estática"], re:"NFPA 13 exige que la presión de prueba sea 50 psi por encima de la presión estática (del sistema) máxima cuando ese máximo supera los 150 psi; de lo contrario se usan 200 psi."},
  {id:320, q:"La prueba hidrostática de aceptación debe mantener la presión requerida durante una duración mínima de:", opts:["30 minutos","1 hora","24 horas","2 horas"], re:"NFPA 13 exige que la presión de la prueba hidrostática se mantenga durante 2 horas sin fugas visibles y con una pérdida de presión aceptable."},
  {id:321, q:"Una prueba hidrostática en una nueva tubería metálica de rociadores se considera exitosa cuando, después de 2 horas, hay:", opts:["Ninguna fuga visible (y la pérdida de presión no supera los 5 psi donde se mide)","No más de una caída de 10 psi","Cualquier caída inferior a 50 psi","Un aumento de presión"], re:"Los criterios de aceptación de NFPA 13 exigen que no haya fugas visibles; donde se aplican criterios de pérdida de presión, la pérdida se limita a unos 5 psi durante 2 horas para que la prueba sea aprobada."},
  {id:322, q:"Las pruebas hidrostáticas de aceptación de la tubería de rociadores contra incendios normalmente se realizan usando:", opts:["Solo aire comprimido","Agua","Nitrógeno","Vapor"], re:"NFPA 13 exige que las pruebas hidrostáticas se realicen con agua; una prueba de fuga de aire (neumática) es solo una verificación adicional en sistemas secos/de preacción, no un sustituto de la prueba hidrostática."},
  {id:323, q:"Los sistemas de tubería seca y de preacción, además de la prueba hidrostática, también reciben una prueba de fuga a presión de aire de:", opts:["200 psi durante 2 horas","100 psi durante 1 hora","40 psi durante 24 horas","No se permite ninguna prueba de aire"], re:"NFPA 13 exige que los sistemas secos/de preacción también se prueben con aire a 40 psi durante 24 horas, con una pérdida máxima permitida de 1.5 psi durante ese período."},
  {id:324, q:"Al probar neumáticamente un sistema seco/de preacción a 40 psi durante 24 horas, la pérdida de presión máxima permitida es:", opts:["20 psi","5 psi","10 psi","1.5 psi"], re:"NFPA 13 limita la pérdida de la prueba de aire de 24 horas a 40 psi a 1.5 psi; una pérdida mayor indica fugas que deben localizarse y corregirse."},
  {id:325, q:"Los sistemas de tubería vertical (standpipe) seca manuales y semiautomáticos se vuelven a probar hidrostáticamente según NFPA 25 a qué intervalo?", opts:["Cada 5 años","Cada 3 años","Anualmente","Cada 10 años"], re:"NFPA 25 (Cap. 6) exige que los sistemas de tubería vertical seca manuales y semiautomáticos se sometan a una prueba hidrostática a 200 psi (o 50 psi por encima de la presión máxima) durante 2 horas cada 5 años."},
  {id:326, q:"Durante la aceptación, la tubería principal de suministro subterránea que alimenta un sistema de rociadores debe purgarse (flush) antes de la conexión principalmente para:", opts:["Aumentar la presión del agua","Eliminar escombros, piedras y materia extraña que podrían obstruir los rociadores","Probar el preventor de reflujo","Clorar el agua"], re:"NFPA 24/13 exigen que la entrada subterránea se purgue a alta velocidad antes de conectar el sistema para que las piedras, el lodo y los escombros no puedan entrar y taponar los rociadores o las válvulas."},
  {id:327, q:"El certificado de materiales y pruebas del contratista para un sistema de rociadores sobre el nivel del suelo se completa y se firma:", opts:["Antes de instalar cualquier tubería","Solo si la AHJ lo solicita","Después de la prueba de aceptación, documentando los resultados de la prueba","Cada año durante la ITM"], re:"NFPA 13 exige que el Certificado de Materiales y Pruebas del Contratista para Tubería Sobre el Nivel del Suelo se complete después de la prueba de aceptación para documentar la prueba hidrostática, la purga y otros resultados, y se entregue al propietario/AHJ."},
  {id:328, q:"Durante la prueba hidrostática de aceptación, los manómetros, dispositivos de alarma y otros equipos no clasificados para la presión de prueba deben:", opts:["Dejarse en su lugar para probarlos también","Pintarse","Ajustarse al máximo","Aislarse o retirarse para que no se dañen"], re:"El equipo no clasificado para la presión de prueba elevada (p. ej., ciertos manómetros, accesorios de válvula seca, dispositivos de alarma) se aísla o se retira durante la prueba hidrostática para evitar daños, según la práctica de NFPA 13."},
  {id:329, q:"Una prueba hidrostática debe realizarse usando una bomba de prueba, liberando la presión del sistema antes de desconectar, porque:", opts:["La alta presión atrapada puede causar lesiones o daños a los componentes si se libera repentinamente","El agua es reutilizable","Acelera la prueba","El código prohíbe los manómetros"], re:"La energía hidrostática almacenada es peligrosa; liberar la presión antes de romper las conexiones previene lesiones y daños al equipo. Esta es una práctica segura estándar en las pruebas de NFPA 13/25."},
  {id:330, q:"Después de una adición o modificación de más de 20 rociadores a un sistema existente, NFPA 13 normalmente exige:", opts:["Ninguna prueba","Una prueba hidrostática de aceptación del trabajo nuevo","Una investigación de obstrucción de 5 años","Solo una verificación visual"], re:"NFPA 13 exige la prueba de aceptación (hidrostática) de la tubería nueva o modificada; las modificaciones que afectan a más de 20 rociadores generalmente activan la prueba de aceptación completa del trabajo afectado y la notificación a la AHJ."},
  {id:331, q:"Antes de realizar una prueba hidrostática en condiciones de congelación, el evaluador debe asegurarse de que el agua de prueba:", opts:["Esté calentada hasta hervir","Contenga concentrado de espuma","No se congele en la tubería durante o después de la prueba","Sea agua salada"], re:"El agua de prueba debe protegerse del congelamiento; el hielo puede dañar la tubería e invalidar los resultados. NFPA 13 advierte contra la prueba hidrostática donde el agua pueda congelarse antes de drenarse."},
  {id:332, q:"La prueba de aceptación de la función operativa (de alarma) de un sistema de rociadores durante la puesta en servicio verifica que:", opts:["El color de la tubería sea correcto","El propietario tenga seguro","Los rociadores estén pintados","El flujo de agua a través del sistema active la alarma de flujo de agua"], re:"La prueba de aceptación incluye una prueba operativa que confirma que el flujo activa la alarma de flujo de agua (gong de motor de agua/interruptor de presión) dentro del tiempo requerido, demostrando que la ruta de alarma funciona."},
  {id:333, q:"Una investigación de purga/prueba de flujo de la conexión subterránea y de entrada en la aceptación se realiza a una velocidad suficiente para:", opts:["Expulsar el material obstructor (una velocidad mínima de purga reconocida)","Reventar la tubería","Llenar un tanque de almacenamiento","Probar los rociadores"], re:"NFPA 24 especifica los flujos mínimos de purga según el tamaño de la tubería para lograr una velocidad (de unos 10 ft/s) que arrastre los escombros de la tubería principal antes de que puedan entrar al sistema."},
  {id:334, q:"Para la tubería de rociadores de CPVC y otra tubería no metálica, deben seguirse las instrucciones del fabricante para la prueba hidrostática porque:", opts:["El plástico no se puede probar","El tiempo de curado y los límites de presión difieren de los del acero y deben respetarse","Está exenta de NFPA 13","La prueba de aire reemplaza a la prueba de agua"], re:"La tubería no metálica listada (p. ej., CPVC) requiere tiempo de curado del cemento solvente antes de presurizar y tiene parámetros de prueba específicos; NFPA 13 exige seguir el listado y las instrucciones del fabricante."},
  {id:335, q:"El propósito principal de la prueba de drenaje principal es:", opts:["Drenar el sistema para el invierno","Probar los rociadores","Detectar un cambio en la condición del suministro de agua y la válvula de control principal","Purgar el anticongelante"], re:"NFPA 25 (Cap. 13) establece que la prueba de drenaje principal detecta un cambio en la tubería de suministro de agua y en la válvula de control principal (p. ej., una válvula parcialmente cerrada o el deterioro del suministro)."},
  {id:336, q:"Durante una prueba de drenaje principal se registra la presión estática, luego se abre completamente el drenaje principal y se registra la:", opts:["Presión de aire","Diámetro de la tubería","Temperatura del rociador","Presión residual (de flujo)"], re:"La prueba compara la presión estática con la presión residual con el drenaje completamente abierto; la lectura residual se compara con las pruebas anteriores y el valor de aceptación original (NFPA 25 Cap. 13)."},
  {id:337, q:"Según NFPA 25, ¿qué reducción en la presión de drenaje principal a flujo total en comparación con los resultados anteriores requiere investigación?", opts:["10% o más","Cualquier reducción en absoluto","25% o más","50% o más"], re:"NFPA 25 (Cap. 13) exige una investigación cuando hay una reducción del 10% o más en la presión a flujo total (residual) en comparación con la prueba de aceptación original o los resultados anteriores."},
  {id:338, q:"Una presión residual marcadamente reducida en una prueba de drenaje principal indica con mayor frecuencia:", opts:["Demasiados rociadores","Una válvula parcialmente cerrada o un suministro obstruido","Una bomba nueva","Clima frío"], re:"Una caída grande o una baja presión residual normalmente apunta a una válvula de control parcialmente cerrada, una obstrucción o un suministro deteriorado, todo lo cual debe investigarse y corregirse (NFPA 25 Cap. 13)."},
  {id:339, q:"Cuando el único suministro de agua a un sistema es a través de un preventor de reflujo o una válvula reductora de presión, NFPA 25 exige que la prueba de drenaje principal se realice:", opts:["Nunca","Solo a los 5 años","Trimestralmente (en un sistema aguas abajo)","Solo en la aceptación"], re:"NFPA 25 (Cap. 13) exige una prueba de drenaje principal trimestral en un sistema aguas abajo donde el suministro pasa a través de un preventor de reflujo o PRV, para confirmar que el dispositivo y la válvula no están impidiendo el flujo."},
  {id:340, q:"Una prueba de flujo directo de un preventor de reflujo verifica que el dispositivo pueda pasar:", opts:["Cero flujo","Flujo inverso","Solo 50 gpm","La demanda total del sistema, incluida cualquier asignación para chorro de manguera"], re:"NFPA 25 (Cap. 13) exige que la prueba de flujo directo demuestre que el conjunto de reflujo puede entregar la demanda del sistema (más la asignación para manguera cuando es parte de la demanda) sin una pérdida de presión excesiva."},
  {id:341, q:"Cuando no se puede realizar una prueba de flujo directo medida o a demanda total, NFPA 25 permite que la prueba de flujo directo se realice mediante:", opts:["El flujo de agua a través del drenaje principal del sistema u otra conexión a la tasa máxima alcanzable","Omitiéndola","Cerrando la válvula de suministro","Usando aire comprimido"], re:"NFPA 25 permite la prueba de flujo directo a través del drenaje principal del sistema o una conexión dimensionada para fluir la demanda del sistema cuando no se dispone de una conexión medida, logrando el máximo flujo posible."},
  {id:342, q:"La válvula de drenaje principal utilizada para la prueba se ubica típicamente:", opts:["En el punto más alto del sistema","En el montante (riser) del sistema, aguas abajo de la válvula de control principal","Solo en la conexión del departamento de bomberos","En el ático"], re:"La conexión de drenaje principal está en el montante aguas abajo de la válvula de control principal para que la prueba refleje el suministro a través de esa válvula; abrirla hace fluir agua para evaluar el suministro (NFPA 25 Cap. 13)."},
  {id:343, q:"Antes de cerrar el drenaje principal al final de la prueba, la válvula debe cerrarse:", opts:["Lo más rápido posible","Solo a la mitad","Lentamente, para evitar una sobrepresión por golpe de ariete","Nunca cerrarse"], re:"Cerrar el drenaje principal lentamente previene el golpe de ariete (sobrepresión) que podría dañar la tubería, los manómetros o los accesorios; la operación gradual es una práctica segura estándar."},
  {id:344, q:"Después de una prueba de drenaje principal en un sistema de tubería seca o de preacción, el técnico debe recordar:", opts:["Dejar la válvula abierta","Retirar los manómetros","Drenar el anticongelante","Restaurar el sistema al servicio (reestablecer la válvula seca, restaurar la presión de aire) y confirmar el estado armado"], re:"En los sistemas secos/de preacción, la prueba de drenaje principal puede disparar u operar parcialmente los accesorios de válvula; el sistema debe restaurarse a su condición armada normal y confirmarse en servicio después."},
  {id:345, q:"Los resultados de la prueba de drenaje principal son más útiles cuando se comparan con:", opts:["Los datos de la prueba de aceptación original y los resultados anuales anteriores","Un edificio vecino","El manómetro de presión de aire","El termómetro"], re:"NFPA 25 enfatiza el seguimiento de tendencias: comparar las lecturas actuales estáticas/residuales con la aceptación y las pruebas anteriores revela el deterioro gradual del suministro o el cierre progresivo de una válvula (Cap. 13)."},
  {id:346, q:"Una prueba de flujo directo que no puede alcanzar la demanda total del sistema debe, como mínimo, confirmar:", opts:["Que la tubería es roja","Que se puede establecer el flujo y que el dispositivo no está obstruido, con los resultados registrados","Que el edificio está ocupado","Que la bomba está apagada"], re:"Cuando no se puede alcanzar la demanda total, NFPA 25 aún exige establecer el flujo para verificar que el conjunto no está atascado/obstruido; el flujo alcanzable y las presiones se documentan para el seguimiento de tendencias."},
  {id:347, q:"Durante la prueba de drenaje principal, una presión residual SIN cambios o normal indica:", opts:["Que los rociadores han operado","Que el sistema ha fallado","Que la tubería principal de suministro probablemente está despejada y la válvula de control abierta","Que la bomba ha fallado"], re:"Una presión residual cercana a los valores históricos indica que el suministro de agua y la válvula de control están en su condición esperada; una desviación significativa activa una investigación (NFPA 25 Cap. 13)."},
  {id:348, q:"La descarga del drenaje principal durante la prueba debe dirigirse a:", opts:["La sala eléctrica","Los rociadores","El techo","Un drenaje o lugar aprobado donde no cause daños"], re:"La descarga del drenaje principal debe ir a un punto seguro y aprobado para que el gran flujo no inunde el espacio ocupado ni dañe la propiedad; planificar la ruta de descarga es parte del procedimiento de prueba."},
  {id:349, q:"También se realiza una prueba de drenaje principal cada vez que la válvula de control principal ha sido:", opts:["Cerrada y reabierta (para verificar que se restauró el suministro)","Pintada","Inspeccionada visualmente","Etiquetada"], re:"Siempre que la válvula de control principal se opere/cierre y se reabra, una prueba de drenaje principal confirma que se restauró el suministro completo de agua (que la válvula está verdaderamente abierta por completo), según la práctica de NFPA 25."},
  {id:350, q:"La tasa de flujo durante una prueba de flujo directo de un conjunto de reflujo debe ser:", opts:["El flujo más bajo posible","La demanda del sistema (el flujo de diseño que el conjunto debe pasar)","El doble de la demanda del sistema","Cero"], re:"NFPA 25 (Cap. 13) establece la tasa de la prueba de flujo directo en la demanda del sistema para que la prueba demuestre que el preventor de reflujo no estrangulará el flujo de diseño en un incendio."},
  {id:351, q:"Un preventor de reflujo se instala en un servicio de rociadores contra incendios principalmente para:", opts:["Aumentar la presión","Filtrar el agua","Prevenir que el agua del sistema potencialmente contaminada regrese al suministro potable","Medir el flujo"], re:"Un preventor de reflujo protege el sistema público de agua potable de la contaminación cruzada por el agua estancada/tratada de los rociadores que fluye hacia atrás; es un dispositivo de control de conexión cruzada."},
  {id:352, q:"Según NFPA 25, ¿con qué frecuencia se somete a una prueba de flujo directo un preventor de reflujo?", opts:["Trimestralmente","Semestralmente","Cada 5 años","Anualmente"], re:"NFPA 25 (Cap. 13) exige una prueba de flujo directo anual de los conjuntos de prevención de reflujo a la tasa de flujo de demanda del sistema."},
  {id:353, q:"Una inspección interna de las válvulas de retención (check) y componentes de un preventor de reflujo es exigida por NFPA 25 cada:", opts:["5 años","2 años","Año","10 años"], re:"NFPA 25 (Cap. 13) exige una inspección interna de los conjuntos de reflujo cada 5 años para confirmar que los componentes se mueven libremente y que los asientos/sellos están en buenas condiciones (en consonancia con el fabricante/AHJ)."},
  {id:354, q:"Además de la prueba de flujo directo de NFPA 25, la mayoría de las jurisdicciones exigen una prueba operativa/de presión diferencial de un conjunto de reflujo por parte de un evaluador de reflujo certificado:", opts:["Nunca","Anualmente","Solo en la instalación","Cada 10 años"], re:"Los programas de control de conexión cruzada (y las reglas de California/del proveedor de agua) típicamente exigen una prueba de reflujo certificada anual de las válvulas diferencial y de retención, separada de la prueba de flujo directo de NFPA 25."},
  {id:355, q:"Un conjunto de doble válvula de retención (DCVA) proporciona protección contra el reflujo usando:", opts:["Una sola válvula de retención","Solo un espacio de aire (air gap)","Dos válvulas de retención que operan independientemente en serie","Un manómetro de presión"], re:"Un DCVA usa dos válvulas de retención accionadas por resorte en serie con grifos de prueba y cierres; es común donde el agua de los rociadores no representa un peligro para la salud (sin aditivos)."},
  {id:356, q:"Un conjunto de reflujo de presión reducida (RP/RPZ) generalmente se exige cuando el sistema de rociadores contiene:", opts:["Solo agua pura","Solo aire","Sin agua","Anticongelante, espuma u otros aditivos (una conexión cruzada de peligro para la salud)"], re:"Donde los aditivos como el anticongelante o la espuma crean un peligro para la salud, se requiere un conjunto de principio de presión reducida (con una válvula de alivio que ventila a la atmósfera) para una mayor protección."},
  {id:357, q:"El puerto de alivio (descarga) de un conjunto RPZ que ventila agua durante el modo de espera normal puede indicar:", opts:["Una válvula de retención ensuciada o con fugas que necesita servicio","Flujo alto normal","Operación correcta siempre","Que la bomba está funcionando"], re:"La descarga continua de la válvula de alivio del RPZ generalmente indica válvulas de retención ensuciadas o un asiento de válvula de alivio defectuoso y debe investigarse; una breve descarga ante una fluctuación de presión puede ser normal."},
  {id:358, q:"Agregar un preventor de reflujo a un servicio de rociadores contra incendios existente puede reducir la presión disponible, por lo que NFPA 13/25 exigen:", opts:["Ignorar la pérdida","Tener en cuenta la pérdida de presión del dispositivo en el diseño hidráulico/la verificación de flujo directo","Retirar rociadores","Duplicar siempre el tamaño de la tubería"], re:"Un conjunto de reflujo añade pérdida por fricción; la demanda del sistema aún debe satisfacerse a través de él, lo cual verifican la prueba de flujo directo y los cálculos hidráulicos."},
  {id:359, q:"Después de inspeccionar internamente o reparar un preventor de reflujo, el conjunto debe:", opts:["Dejarse abierto para drenar","Pintarse de rojo","Volver a ponerse en servicio y realizarse una prueba de flujo directo/prueba operativa para confirmar su función","Retirarse permanentemente"], re:"Tras la inspección interna o la reparación, NFPA 25 exige que el conjunto se vuelva a poner en servicio y se pruebe (flujo directo más la prueba diferencial certificada) para confirmar que funciona y pasa el flujo de diseño."},
  {id:360, q:"Cuando un preventor de reflujo o PRV es la única ruta de suministro, la prueba de drenaje principal trimestral sirve principalmente para:", opts:["Probar los rociadores","Llenar el tanque","Drenar el sistema","Ejercitar el dispositivo y confirmar que no está impidiendo el suministro de agua"], re:"La prueba de drenaje principal trimestral en un sistema alimentado únicamente a través de un reflujo/PRV ejercita esos componentes y verifica que no estén atascados o ensuciados, estrangulando el suministro (NFPA 25 Cap. 13)."},
  {id:361, q:"Las válvulas de cierre de un conjunto de reflujo típicamente deben estar:", opts:["Supervisadas (con candado/sello o monitoreadas eléctricamente) para que no se dejen cerradas","Sin supervisión y libres de cerrarse","Retiradas","Soldadas cerradas"], re:"Debido a que un cierre de reflujo cerrado deshabilita todo el sistema, esas válvulas deben supervisarse por los mismos medios que otras válvulas de control (requisitos de válvulas de control de NFPA 25 Cap. 13)."},
  {id:362, q:"Una prueba de flujo directo a través de un preventor de reflujo se documenta con cuáles datos clave?", opts:["Solo la fecha","La tasa de flujo alcanzada y las presiones de entrada/salida (y la pérdida de presión a través del dispositivo)","El color de la tubería","La hora del almuerzo del técnico"], re:"El registro de la prueba de flujo directo debe capturar el flujo alcanzado y las presiones para que la pérdida a través del dispositivo y la capacidad de satisfacer la demanda puedan seguirse a lo largo del tiempo (NFPA 25 Cap. 13)."},
  {id:363, q:"Un conjunto de reflujo que falla su prueba de presión diferencial certificada debe:", opts:["Ignorarse hasta el próximo año","Pintarse","Repararse o reemplazarse y volver a probarse antes de confiar en él","Dejarse en servicio"], re:"Una prueba de reflujo fallida significa que el dispositivo no está proporcionando protección o puede estar restringiendo el flujo; debe repararse/reemplazarse y volver a probarse antes de considerar protegido el sistema."},
  {id:364, q:"Ubicar un conjunto RPZ de modo que su descarga de alivio drene correctamente es importante porque el conjunto:", opts:["Nunca descarga","Solo descarga aire","Está sellado","Puede descargar una cantidad significativa de agua y debe drenar a un punto aprobado sin inundar"], re:"Un RPZ puede expulsar un gran volumen desde el puerto de alivio durante una falla de retención o una sobrepresión; un espacio de aire adecuado y un desagüe de piso previenen inundaciones y contrapresión en la válvula de alivio."},
  {id:365, q:"Los grifos de prueba de un conjunto de reflujo se usan para:", opts:["Conectar manómetros de prueba para verificar las válvulas de retención y el diferencial de la válvula de alivio","Drenar el edificio","Agregar anticongelante","Ventilar el aire de los rociadores"], re:"Los grifos de prueba son los puntos de conexión de manómetros que un evaluador certificado usa para medir el diferencial a través de cada válvula de retención y el punto de apertura de la válvula de alivio durante la prueba operativa anual."},
  {id:366, q:"En comparación con un DCVA, un conjunto RPZ típicamente causa:", opts:["Ninguna pérdida de presión","Mayor pérdida de presión, que debe considerarse en la demanda del sistema","Pérdida de presión negativa","Un aumento de presión"], re:"El mecanismo de alivio y los componentes internos adicionales de un RPZ usualmente crean más pérdida por fricción que un DCVA; esta pérdida añadida debe tenerse en cuenta para que el sistema aún satisfaga la demanda."},
  {id:367, q:"Una prueba de alarma de flujo de agua en un sistema de tubería húmeda se realiza abriendo la:", opts:["Válvula de control principal","Conexión del departamento de bomberos","Conexión de prueba del inspector","Circuito de anticongelante"], re:"La conexión de prueba del inspector tiene un orificio equivalente a un rociador; abrirla hace fluir agua para activar la alarma de flujo de agua, simulando la operación de un solo rociador (NFPA 25 Cap. 5)."},
  {id:368, q:"Después de abrir la conexión de prueba del inspector, una alarma de flujo de agua debe activarse dentro de un máximo de:", opts:["10 segundos","30 segundos","5 minutos","90 segundos"], re:"NFPA 13/25 exigen que la alarma de flujo de agua opere dentro de los 90 segundos de un flujo igual a un rociador en la conexión de prueba del inspector."},
  {id:369, q:"El orificio de la conexión de prueba del inspector está dimensionado para descargar el equivalente de:", opts:["Un rociador (el orificio más pequeño del sistema)","Una manguera contra incendios de 2.5 pulgadas","Todo el sistema a la vez","Sin flujo"], re:"NFPA 13 exige que la conexión de prueba del inspector tenga un orificio equivalente al rociador más pequeño del sistema, de modo que la prueba de alarma simule la operación de un rociador."},
  {id:370, q:"Un interruptor de flujo de agua de tipo paleta (vane) NO está permitido en cuál sistema porque el flujo de disparo podría romper la paleta?", opts:["Tubería húmeda","Tubería seca","Húmeda en cuadrícula (gridded)","Húmeda en bucle (looped)"], re:"NFPA 13/25 prohíben los dispositivos de flujo de agua de tipo paleta en sistemas de tubería seca; la sobrepresión cuando la válvula seca se dispara podría cortar la paleta y enviarla a la tubería. En su lugar se usan interruptores de tipo presión."},
  {id:371, q:"Los dispositivos de alarma de flujo de agua de tipo interruptor de presión y de tipo paleta (vane) se prueban funcionalmente según NFPA 25 con qué frecuencia mínima?", opts:["Trimestralmente","Anualmente","Semestralmente","Cada 5 años"], re:"NFPA 25 (Cap. 5) exige que los dispositivos de alarma de flujo de agua de tipo paleta y de interruptor de presión se prueben semestralmente, mientras que los gong de motor de agua mecánicos se prueban trimestralmente."},
  {id:372, q:"En un sistema de tubería seca, abrir la conexión de prueba del inspector para una prueba de alarma:", opts:["No hace nada","Cierra la válvula principal","Agrega anticongelante","Reduce la presión de aire y dispara la válvula seca, enviando agua (una prueba de disparo parcial/total)"], re:"Debido a que los sistemas secos retienen aire, hacer fluir la conexión de prueba del inspector purga el aire y puede disparar la válvula seca; la prueba de alarma/disparo en sistemas secos debe planificarse para evitar un disparo total no intencionado cuando solo se pretende una prueba de alarma."},
  {id:373, q:"Un dispositivo de supervisión en un sistema de rociadores monitorea condiciones tales como:", opts:["La posición de la válvula de control, la baja presión de aire o la baja temperatura","La temperatura ambiente para el confort","Los niveles de iluminación","Las cerraduras de las puertas"], re:"Las señales de supervisión indican condiciones anormales (válvula cerrada, presión de aire baja/alta, baja temperatura del edificio/recinto, bajo nivel de agua) que podrían impedir el funcionamiento del sistema (NFPA 25/72)."},
  {id:374, q:"Las alarmas de supervisión de baja presión de aire en sistemas secos/de preacción se prueban según NFPA 25:", opts:["Nunca","Anualmente (o según el fabricante)","Cada 10 años","Solo en la aceptación"], re:"NFPA 25 (Cap. 5/13) exige que los dispositivos de señal de supervisión de aire bajo (y de baja temperatura, bajo nivel de agua) se prueben al menos anualmente, o de acuerdo con las instrucciones del fabricante."},
  {id:375, q:"Cuando una alarma de flujo de agua está interconectada con un panel de control de alarma contra incendios, la transmisión de la señal de alarma al panel se verifica según cuál norma complementaria?", opts:["Solo NFPA 13","NFPA 10","NFPA 72","NFPA 30"], re:"NFPA 72 (Código Nacional de Alarmas y Señalización contra Incendios) rige el circuito del dispositivo iniciador y la verificación de la señal cuando los dispositivos de flujo de agua/supervisión de rociadores se conectan al sistema de alarma contra incendios."},
  {id:376, q:"Una cámara de retardo instalada antes de un interruptor de presión de flujo de agua de tubería húmeda se usa para:", opts:["Aumentar la presión","Drenar el sistema","Filtrar agua","Absorber sobrepresiones/fluctuaciones de presión breves para prevenir falsas alarmas"], re:"La cámara de retardo retrasa la activación de la alarma a través de sobrepresiones momentáneas (p. ej., golpe de ariete) para que solo el flujo sostenido active la alarma, reduciendo las alarmas molestas; aún debe permitir la alarma dentro de los 90 segundos de un flujo real."},
  {id:377, q:"Durante una prueba de alarma de flujo de agua, el técnico debe notificar primero a:", opts:["La estación de monitoreo/los ocupantes para que la alarma no se confunda con un incendio real","El limpiador de ventanas","El departamento de facturación de la empresa de agua","El contratista de techos"], re:"Debido a que la prueba activa señales de alarma reales, la estación central de monitoreo y los ocupantes del edificio deben ser notificados de antemano y el sistema debe ponerse en modo de prueba para evitar un despacho falso (práctica de NFPA 25/72)."},
  {id:378, q:"Un gong de motor de agua (alarma mecánica) es impulsado por:", opts:["Un motor eléctrico","El flujo de agua a través de un pequeño motor de agua que golpea el gong","Aire comprimido","Un reloj de resorte"], re:"El gong de motor de agua usa un pequeño motor de agua tipo Pelton energizado por el flujo de la línea de alarma para golpear mecánicamente el gong; no requiere electricidad y se prueba trimestralmente (NFPA 25 Cap. 5)."},
  {id:379, q:"Los dispositivos iniciadores de flujo de agua y de supervisión se inspeccionan (visualmente, en busca de daño físico) con qué frecuencia según NFPA 25?", opts:["Diariamente","Cada 3 años","Trimestralmente","Cada 5 años"], re:"NFPA 25 (Cap. 5) exige la inspección trimestral de los dispositivos iniciadores de señal de flujo de agua y de supervisión para confirmar que están libres de daño físico, además de la prueba funcional."},
  {id:380, q:"Después de completar la prueba de alarma/flujo de agua, el técnico debe confirmar que:", opts:["La alarma se deje sonando","Los manómetros se retiren","La válvula se deje cerrada","Todos los dispositivos se reinicien, el sistema vuelva a estar en servicio y el monitoreo se saque del modo de prueba"], re:"Restaurar el servicio significa verificar que los dispositivos se reinicien, que las válvulas estén abiertas y supervisadas, que las presiones de aire/agua sean normales y que la estación de monitoreo se saque del modo de prueba y se rearme."},
  {id:381, q:"Un interruptor de flujo de agua de tipo presión opera al detectar:", opts:["Un aumento de presión en la línea de alarma/del sistema causado por el flujo","La deflexión de la paleta","La temperatura","El humo"], re:"Un interruptor de flujo de agua accionado por presión cierra sus contactos cuando la presión de la línea de alarma aumenta debido al flujo; a diferencia de un interruptor de paleta, no tiene una paleta móvil en el conducto de agua, por lo que es adecuado para sistemas secos."},
  {id:382, q:"Si una alarma de flujo de agua no opera dentro de los 90 segundos durante la prueba, el técnico debe:", opts:["Aprobarla de todos modos","Investigar y corregir la causa (p. ej., obstrucción, interruptor defectuoso, válvula de alarma cerrada)","Retirar el dispositivo","Esperar una semana"], re:"No activar la alarma dentro del tiempo requerido es una deficiencia; la causa (puerto de alarma bloqueado, cámara de retardo atascada, interruptor defectuoso o válvula de alarma cerrada) debe localizarse y corregirse, y el dispositivo volverse a probar."},
  {id:383, q:"La conexión de prueba del inspector normalmente se ubica:", opts:["En la válvula principal","En la sala de la bomba contra incendios","En el punto hidráulicamente más remoto del sistema","En la FDC"], re:"La conexión de prueba del inspector se coloca en o cerca del punto más remoto para que su flujo equivalente a un solo rociador represente el peor caso para activar la alarma y verificar la ruta de flujo (NFPA 13)."},
  {id:384, q:"En los términos de NFPA 25, un 'deterioro/impedimento' (impairment) es una condición en la que:", opts:["Un rociador está polvoriento","Un manómetro lee ligeramente desviado","La pintura está descolorida","Un sistema de protección contra incendios a base de agua (o una parte) está fuera de servicio/incapaz de funcionar según lo previsto"], re:"NFPA 25 (Cap. 15) define un deterioro como una condición en la que un sistema de protección contra incendios o una porción está fuera de servicio, lo que resulta en que el sistema no funcione si ocurre un incendio."},
  {id:385, q:"Una interrupción planificada de un sistema de rociadores para trabajo programado se clasifica como un(a):", opts:["Deterioro preplanificado","Deterioro de emergencia","Cierre permanente","Prueba de aceptación"], re:"NFPA 25 (Cap. 15) distingue los deterioros preplanificados (programados, p. ej., para mantenimiento/modificación) de los deterioros de emergencia (inesperados, p. ej., una rotura o daño por incendio)."},
  {id:386, q:"Según NFPA 25, la persona responsable de gestionar un deterioro es el/la:", opts:["Limpiador de ventanas","Coordinador de deterioros","Arquitecto","Inquilino"], re:"NFPA 25 (Cap. 15) exige que el propietario asigne un coordinador de deterioros que supervise los pasos antes, durante y en la restauración de cualquier deterioro."},
  {id:387, q:"Una rotura o un cierre accidental que deja un sistema fuera de servicio inesperadamente es un(a):", opts:["Deterioro preplanificado","Investigación de obstrucción de 5 años","Deterioro de emergencia","Prueba de flujo directo"], re:"NFPA 25 (Cap. 15) clasifica las pérdidas inesperadas de protección (rotura de tubería, tubería congelada/reventada, válvula encontrada cerrada, daño por incendio/agua) como deterioros de emergencia que requieren acción inmediata."},
  {id:388, q:"Cuando un sistema está deteriorado, NFPA 25 exige que se coloque una etiqueta que indique el deterioro:", opts:["Solo en el archivo de la oficina","En cada rociador","En el techo","En cada conexión del departamento de bomberos y válvula de control del sistema (y otros puntos designados por la AHJ)"], re:"NFPA 25 (Cap. 15) exige la etiqueta de deterioro en cada FDC, la válvula de control principal y otros puntos que la AHJ designe para que los respondedores y el personal sepan que el sistema está fuera de servicio."},
  {id:389, q:"Antes de que comience un deterioro preplanificado, el coordinador de deterioros debe determinar el alcance y la duración esperada y:", opts:["Inspeccionar las áreas afectadas en busca de mayor riesgo y notificar al departamento de bomberos, la compañía de alarmas y los ocupantes","No hacer nada más","Apagar la electricidad","Retirar los rociadores"], re:"NFPA 25 (Cap. 15) enumera los pasos previos al deterioro: evaluar el alcance/duración, inspeccionar en busca de mayores peligros, notificar al departamento de bomberos/monitoreo de alarmas/aseguradora/ocupantes y prepararse para mitigar (p. ej., vigilancia contra incendios)."},
  {id:390, q:"NFPA 25 exige mitigación, como una vigilancia contra incendios (fire watch), cuando el deterioro de un sistema a base de agua supera qué duración en un período de 24 horas?", opts:["1 hora","10 horas","4 horas","48 horas"], re:"NFPA 25 (Cap. 15) exige la evacuación o una vigilancia contra incendios aprobada (o protección temporal) cuando un sistema a base de agua está deteriorado más de 10 horas en cualquier período de 24 horas."},
  {id:391, q:"Una vigilancia contra incendios (fire watch) realizada durante un deterioro consiste en:", opts:["Una cámara automática","Una puerta cerrada con llave","Personal capacitado que patrulla el área afectada para detectar incendios y notificar al departamento de bomberos","Un rociador adicional"], re:"Una vigilancia contra incendios consiste en una o más personas capacitadas que patrullan continuamente el área deteriorada, equipadas para llamar al departamento de bomberos y alertar/evacuar a los ocupantes si se detecta un incendio (NFPA 25 Cap. 15)."},
  {id:392, q:"Cuando se restaura el sistema deteriorado, el coordinador de deterioros debe verificar, antes de retirar la etiqueta, que:", opts:["La etiqueta esté laminada","El edificio esté repintado","Las luces estén encendidas","Se hayan realizado las inspecciones/pruebas necesarias y que el sistema esté completamente operativo"], re:"NFPA 25 (Cap. 15) exige confirmar que el suministro esté restaurado (prueba de drenaje principal), que no haya fugas y que todas las válvulas estén abiertas/supervisadas; solo entonces se retira la etiqueta de deterioro y se notifica a las partes interesadas."},
  {id:393, q:"Restaurar un sistema de rociadores al servicio después de un deterioro debe incluir una prueba de drenaje principal para confirmar:", opts:["Que el suministro de agua se restauró completamente (válvula de control completamente abierta)","La concentración de anticongelante","El color de la pintura","La marca del manómetro"], re:"Una prueba de drenaje principal después de la restauración verifica que la válvula de control está completamente abierta y que hay suministro completo disponible; una baja presión residual revelaría una válvula que quedó parcialmente cerrada (NFPA 25 Cap. 13/15)."},
  {id:394, q:"Una investigación de obstrucción según NFPA 25 se activa cuando se encuentran condiciones tales como cuáles?", opts:["Tubería limpia y despejada","Material extraño, tuberculación, sedimentos o evidencia de MIC en la tubería","Pintura fresca","Un manómetro nuevo"], re:"NFPA 25 (Cap. 14) enumera las condiciones (rociadores taponados, materia extraña en el drenaje, tubérculos, MIC, color/olor inusual) que requieren una investigación de obstrucción para localizar y eliminar el bloqueo."},
  {id:395, q:"MIC, una preocupación de corrosión que puede obstruir la tubería de rociadores, significa:", opts:["Código de inspección mecánica","Capacidad máxima de entrada de flujo","Corrosión influenciada microbiológicamente","Conexión de entrada principal"], re:"La corrosión influenciada microbiológicamente (MIC) es una corrosión impulsada por bacterias que forma nódulos/tubérculos y fugas por agujeros de alfiler, restringiendo el flujo; encontrarla activa una investigación de obstrucción según NFPA 25 Cap. 14."},
  {id:396, q:"El examen interno de la tubería de los 5 años en busca de obstrucciones se realiza típicamente:", opts:["Escuchando la tubería","Agregando anticongelante","Pintando la tubería","Abriendo una conexión de purga y retirando un rociador cerca del extremo de una línea ramal para inspeccionar el interior"], re:"NFPA 25 (Cap. 14) indica examinar el interior en puntos representativos (p. ej., una conexión de purga de la tubería principal cruzada y un rociador retirado del extremo de una línea ramal) en busca de material extraño, tuberculación o MIC."},
  {id:397, q:"Si una investigación de obstrucción encuentra material en la tubería, la acción correctiva requerida es:", opts:["Purgar/limpiar el sistema para eliminar la obstrucción y determinar/corregir la fuente","Ignorarlo","Pintar sobre ello","Aumentar la presión de aire"], re:"NFPA 25 (Cap. 14) exige que el sistema se purgue/limpie para eliminar el material obstructor y que la fuente (p. ej., escombros de la tubería principal, MIC) se identifique y corrija para prevenir la recurrencia."},
  {id:398, q:"Durante un deterioro de emergencia, el coordinador de deterioros debe implementar la mitigación y:", opts:["Esperar hasta el siguiente día hábil","Tomar acción correctiva inmediata y notificar al departamento de bomberos, los ocupantes y otras partes afectadas","Retirar toda la señalización","Deshabilitar las alarmas"], re:"NFPA 25 (Cap. 15) exige que los deterioros de emergencia se aborden de inmediato, con pasos correctivos rápidos y la notificación al departamento de bomberos, los ocupantes, la compañía de alarmas y otros, más una vigilancia contra incendios si es necesario."},
  {id:399, q:"Los registros de un deterioro (hora de inicio, causa, mitigación, restauración) deben:", opts:["Descartarse de inmediato","Publicarse públicamente en línea","Documentarse y conservarse como parte de los registros del sistema","Mantenerse solo verbalmente"], re:"NFPA 25 (Cap. 4/15) exige que los deterioros se documenten (fechas, alcance, mitigación, confirmación de restauración) y se conserven con los registros del sistema para la AHJ y para el seguimiento de tendencias."},
  {id:400, q:"Después de completar la inspección interna de obstrucción de los 5 años sin encontrar obstrucción, el técnico debe:", opts:["Comenzar una investigación de obstrucción completa de todos modos","Drenar el anticongelante permanentemente","Dejar la tubería abierta","Documentar los resultados de la inspección y restaurar el sistema al servicio"], re:"Si el examen interno de los 5 años encuentra la tubería despejada, no se activa una investigación de obstrucción; los hallazgos se documentan y el sistema se restaura al servicio normal (NFPA 25 Cap. 14)."},
  {id:401, q:"En California, ¿qué parte del Título 24 es el Código de Incendios de California (CFC)?", opts:["Parte 6","Parte 2","Parte 9","Parte 11"], re:"El Código de Incendios de California es el Título 24, Parte 9 del Código de Regulaciones de California. El Código de Construcción de California es la Parte 2. Fuente: California Building Standards Code / DGS BSC, CFC 2022, Título 24 Parte 9."},
  {id:402, q:"¿En qué código modelo se basa el Código de Incendios de California, con enmiendas específicas de California?", opts:["El International Fire Code (IFC)","El Uniform Plumbing Code","El International Residential Code","El National Electrical Code"], re:"El CFC se ensambla a partir del International Fire Code con las enmiendas de California necesarias. Fuente: California Fire Code 2022, Título 24 Parte 9, Prefacio."},
  {id:403, q:"¿Qué título del Código de Regulaciones de California contiene las regulaciones del State Fire Marshal para el servicio, las pruebas y el mantenimiento de los sistemas automáticos de extinción de incendios (rociadores)?", opts:["Título 8","Título 16","Título 19","Título 22"], re:"El CCR Título 19 (Seguridad Pública) contiene las regulaciones del State Fire Marshal para el servicio, las pruebas y el mantenimiento de los sistemas automáticos de extinción de incendios. Fuente: CCR Título 19, División 1; Código H&S 13195."},
  {id:404, q:"¿Qué norma NFPA adopta por referencia el CCR Título 19 para la inspección, prueba y mantenimiento de los sistemas de protección contra incendios basados en agua?", opts:["NFPA 13","NFPA 14","NFPA 72","NFPA 25"], re:"El CCR Título 19, Sección 904 incorpora por referencia la NFPA 25 (la norma para la ITM de los sistemas de protección contra incendios basados en agua). Fuente: CCR Título 19 §904; NFPA 25."},
  {id:405, q:"¿Qué norma NFPA es la referencia principal para el diseño y la instalación de sistemas automáticos de rociadores adoptada por el Código de Incendios de California?", opts:["NFPA 20","NFPA 13","NFPA 24","NFPA 291"], re:"La NFPA 13, Norma para la Instalación de Sistemas de Rociadores, es la referencia principal de diseño/instalación adoptada por el CFC (Capítulo 9). Fuente: California Fire Code Capítulo 9 / Capítulo 80; NFPA 13."},
  {id:406, q:"Según la Sección 903 del Código de Incendios de California, generalmente se requiere un sistema automático de rociadores en toda un área de incendio del Grupo A-1 donde el área de incendio supera:", opts:["5,000 pies²","8,000 pies²","12,000 pies²","20,000 pies²"], re:"El CFC §903.2.1.1 requiere rociadores para el Grupo A-1 donde el área de incendio supera 12,000 pies² (entre otros factores como la carga de ocupantes). Fuente: California Fire Code §903.2.1."},
  {id:407, q:"En California, la agencia que adopta las regulaciones del State Fire Marshal en el CCR Título 19 forma parte de ¿qué departamento?", opts:["Cal/OSHA","La División del Arquitecto del Estado","El Departamento de Asuntos del Consumidor","La Oficina del State Fire Marshal (CAL FIRE)"], re:"La Oficina del State Fire Marshal, dentro de CAL FIRE, adopta las regulaciones de prevención de incendios del Título 19. Fuente: Office of the State Fire Marshal; CCR Título 19."},
  {id:408, q:"¿Qué documento de diseño debe preparar y presentar normalmente un contratista de rociadores para la revisión de planos antes de instalar un sistema de rociadores contra incendios?", opts:["Planos de trabajo (planos de taller) y cálculos hidráulicos","Solo un cálculo de carga","Un diagrama unifilar eléctrico","Un plano de nivelación de terreno"], re:"La NFPA 13 y el CFC requieren que se presenten planos de trabajo (planos de taller) más cálculos hidráulicos a la autoridad competente para su revisión antes de la instalación. Fuente: capítulo de planos/cálculos de NFPA 13; CFC §901.2."},
  {id:409, q:"El organismo de una jurisdicción con autoridad legal para aprobar los planos de rociadores contra incendios e inspeccionar las instalaciones se denomina en los códigos como:", opts:["El contratista general","El profesional de diseño registrado","El laboratorio de certificación","La autoridad competente (AHJ)"], re:"La 'autoridad competente' (AHJ) es el término de los códigos para la oficina/individuo responsable de aprobar el equipo, la instalación y los procedimientos. Fuente: definiciones de NFPA 13; California Fire Code Capítulo 2."},
  {id:410, q:"¿Qué documento es la fuente de la autoridad legal del State Fire Marshal sobre el servicio y las pruebas de los sistemas automáticos de extinción?", opts:["El Código de Vehículos","El Código de Negocios y Profesiones","El Código de Salud y Seguridad de California","El Código Penal"], re:"El Código de Salud y Seguridad de California §13195 ordena al State Fire Marshal adoptar las regulaciones del Título 19 que rigen el servicio y las pruebas de los sistemas automáticos de extinción. Fuente: Código H&S §13195."},
  {id:411, q:"Según el CCR Título 19, las placas/formularios estándar utilizados para documentar la inspección de los sistemas automáticos de extinción son desarrollados por:", opts:["La empresa local de agua","La compañía de seguros","El fabricante de tuberías","La Oficina del State Fire Marshal (formularios AES)"], re:"El CCR Título 19 exige el uso de los formularios AES (Automatic Extinguishing Systems) de la Oficina del State Fire Marshal para documentar la inspección/prueba. Fuente: CCR Título 19 §906.4."},
  {id:412, q:"Cuando una jurisdicción local adopta el Código de Incendios de California, puede:", opts:["Eliminar todos los requisitos de rociadores","Eliminar la AHJ","Ignorar por completo al State Fire Marshal","Adoptar enmiendas locales más restrictivas según las condiciones locales"], re:"Las jurisdicciones locales pueden adoptar enmiendas más restrictivas que el código modelo estatal según las condiciones climáticas, geológicas o topográficas locales. Fuente: California Health & Safety Code §17958.7; proceso de adopción del California Fire Code."},
  {id:413, q:"¿Qué parte del California Building Standards Code contiene los requisitos generales de construcción de seguridad humana y contra incendios (p. ej., tipo de ocupación y de construcción) referenciados junto con el Código de Incendios?", opts:["Parte 9 (Código de Incendios)","Parte 4 (Código Mecánico)","Parte 2 (Código de Construcción)","Parte 5 (Código de Plomería)"], re:"El Código de Construcción de California es el Título 24, Parte 2, que contiene la clasificación de ocupación y los requisitos del tipo de construcción que el Código de Incendios referencia. Fuente: California Building Standards Code, Título 24, Parte 2."},
  {id:414, q:"Una presentación completa de planos de rociadores contra incendios para la revisión de la AHJ generalmente debe incluir todo lo siguiente EXCEPTO:", opts:["Cálculos hidráulicos","La declaración de impuestos personal del contratista","Hojas de datos/certificaciones del equipo","Una base de suministro de agua (prueba de flujo)"], re:"Los planos de trabajo, los cálculos hidráulicos, la base del suministro de agua y los datos del equipo certificado son requeridos para la revisión; la declaración de impuestos del contratista no forma parte de la presentación de planos de rociadores. Fuente: capítulo de planos/cálculos de NFPA 13; CFC §901.2."},
  {id:415, q:"¿Con qué ciclo general se actualiza el Código de Incendios de California como parte del proceso de adopción del código del Título 24?", opts:["Cada 6 meses","Cada 3 años (trienal)","Cada 10 años","Solo cuando ocurre un terremoto"], re:"Los California Building Standards (Título 24), incluido el Código de Incendios, se adoptan en un ciclo trienal (3 años). Fuente: California Building Standards Commission / DGS BSC ciclo de adopción del código."},
  {id:416, q:"La NFPA 25, adoptada por el CCR Título 19, rige principalmente:", opts:["La inspección, prueba y mantenimiento de los sistemas instalados basados en agua","El diseño de nuevos sistemas de rociadores","La fabricación de cabezas de rociadores","El cableado de alarmas contra incendios"], re:"La NFPA 25 es la Norma para la Inspección, Prueba y Mantenimiento de los Sistemas de Protección contra Incendios Basados en Agua; el diseño de nuevos sistemas se rige por la NFPA 13. Fuente: alcance de NFPA 25; CCR Título 19 §904."},
  {id:417, q:"Cuando el Código de Incendios de California y una norma NFPA adoptada difieren, el instalador debe:", opts:["Siempre ignorar la norma NFPA","Usar la que sea más barata","Promediar los dos valores","Seguir el requisito más restrictivo, en concordancia con la AHJ"], re:"Cuando el código que adopta (CFC) y una norma referenciada difieren, generalmente rige la disposición más restrictiva, sujeto a la dirección de la AHJ. Fuente: California Fire Code Capítulo 1 administración; autoridad de la AHJ."},
  {id:418, q:"Las clasificaciones de riesgo por ocupación de la NFPA 13 se basan principalmente en:", opts:["La cantidad y combustibilidad del contenido","El número de ocupantes del edificio","La altura del edificio","La antigüedad de la estructura"], re:"La NFPA 13 clasifica el riesgo por ocupación según la cantidad y combustibilidad del contenido (y la liberación de calor esperada), a diferencia de los códigos de seguridad humana que se centran en las necesidades de los ocupantes. Fuente: NFPA 13 Capítulo 4, Clasificación de ocupación."},
  {id:419, q:"Una ocupación donde la cantidad y combustibilidad del contenido es baja y se espera que los incendios tengan una tasa relativamente baja de liberación de calor se clasifica como:", opts:["Riesgo ordinario Grupo 2","Riesgo leve","Riesgo extra Grupo 1","Riesgo extra Grupo 2"], re:"Las ocupaciones de riesgo leve tienen baja cantidad y combustibilidad del contenido y una baja tasa esperada de liberación de calor. Fuente: definición de riesgo leve de NFPA 13 (Capítulo 4)."},
  {id:420, q:"Un edificio de oficinas, iglesia o aula escolar típica generalmente se clasifica por la NFPA 13 como ¿qué riesgo por ocupación?", opts:["Riesgo extra Grupo 1","Riesgo ordinario Grupo 1","Riesgo leve","Almacenamiento"], re:"Las oficinas, iglesias, escuelas y ocupaciones similares se enumeran como riesgo leve en la NFPA 13. Fuente: ejemplos de riesgo leve del Anexo/Capítulo 4 de NFPA 13."},
  {id:421, q:"La NFPA 13 divide las ocupaciones de riesgo ordinario en:", opts:["Una sola clase únicamente","Alta y baja únicamente","Grupos A a D","Grupo 1 y Grupo 2"], re:"El riesgo ordinario se divide en Grupo 1 y Grupo 2, donde el Grupo 2 representa mayor cantidad y combustibilidad del contenido. Fuente: NFPA 13 Capítulo 4 riesgo ordinario."},
  {id:422, q:"En el riesgo ordinario Grupo 1, la altura de apilamiento (almacenamiento) del contenido generalmente se limita a un máximo de aproximadamente:", opts:["8 pies","4 pies","16 pies","20 pies"], re:"El riesgo ordinario Grupo 1 incluye una limitación de altura de apilamiento de aproximadamente 8 pies (2.4 m). Fuente: definición de riesgo ordinario Grupo 1 de NFPA 13."},
  {id:423, q:"En el riesgo ordinario Grupo 2, la altura de apilamiento para contenido moderadamente combustible puede extenderse hasta aproximadamente:", opts:["8 pies","12 pies","10 pies","30 pies"], re:"El riesgo ordinario Grupo 2 permite un apilamiento más alto, de hasta aproximadamente 12 pies (3.7 m) para la misma combustibilidad, reflejando una mayor cantidad que el Grupo 1. Fuente: definición de riesgo ordinario Grupo 2 de NFPA 13."},
  {id:424, q:"Una ocupación con una cantidad muy alta de combustibles, incluidas áreas donde hay presencia de polvo o pelusa y pueden ocurrir incendios de rápida propagación, se clasifica como:", opts:["Riesgo extra Grupo 1","Riesgo ordinario Grupo 1","Riesgo leve","Riesgo leve, sala pequeña"], re:"El riesgo extra Grupo 1 cubre espacios con cantidad muy alta de combustibles y potencial de incendios de rápida propagación, como áreas con polvo o pelusa, pero con poco o ningún líquido inflamable/combustible. Fuente: definición de riesgo extra Grupo 1 de NFPA 13."},
  {id:425, q:"Una ocupación que contiene cantidades sustanciales de líquidos inflamables o combustibles, o un extenso ocultamiento de combustibles, se clasifica como:", opts:["Riesgo leve","Riesgo extra Grupo 2","Riesgo ordinario Grupo 2","Riesgo ordinario Grupo 1"], re:"El riesgo extra Grupo 2 es la clase más alta de ocupación de rociado, incluidos líquidos inflamables/combustibles sustanciales y un extenso ocultamiento de combustibles. Fuente: definición de riesgo extra Grupo 2 de NFPA 13."},
  {id:426, q:"¿Cuál de las siguientes ocupaciones se clasificaría más probablemente como riesgo ordinario Grupo 2?", opts:["Un taller mecánico o área de trabajo de metales","Una sala de lectura de biblioteca","Una habitación de paciente de hospital","Una habitación de huéspedes de hotel"], re:"Los talleres mecánicos/trabajo de metales son ejemplos enumerados de riesgo ordinario Grupo 2; las bibliotecas (salas de lectura), las habitaciones de hospital y de hotel son riesgo leve. Fuente: ejemplos de ocupación del Anexo de NFPA 13."},
  {id:427, q:"Las clasificaciones de productos básicos (commodities) de la NFPA 13 para el almacenamiento se designan como:", opts:["Clase A a F","Grado A a D","Tipo 1 a 5","Clase I a IV (más grupos de plásticos)"], re:"Los productos básicos de almacenamiento se clasifican de Clase I a Clase IV (con agrupaciones separadas de plásticos/elastómeros), presentando la Clase IV el mayor riesgo de las cuatro clases numeradas. Fuente: capítulo de clasificación de productos básicos de NFPA 13."},
  {id:428, q:"De las clases numeradas de productos básicos de almacenamiento, ¿cuál presenta el mayor riesgo de incendio?", opts:["Clase I","Clase II","Clase III","Clase IV"], re:"La Clase IV contiene mayores niveles de plásticos/combustibles que la Clase III y presenta el mayor riesgo de las clases numeradas (sin grupo de plásticos). Fuente: capítulo de clasificación de productos básicos de NFPA 13."},
  {id:429, q:"Un producto básico de Clase I en la NFPA 13 se describe mejor como:", opts:["Líquidos inflamables de flujo libre","Productos esencialmente no combustibles sobre tarimas combustibles o en cartones ordinarios","Plásticos no expandidos expuestos","Aerosoles, Nivel 3"], re:"Los productos básicos de Clase I son productos esencialmente no combustibles que pueden almacenarse sobre tarimas de madera o en cartones corrugados de una sola capa. Fuente: clasificación de productos básicos de NFPA 13, Clase I."},
  {id:430, q:"¿Por qué es crítica la clasificación correcta del riesgo por ocupación para el diseño de rociadores?", opts:["Establece el color de la pintura de la tubería","Selecciona el tamaño de la campana de alarma","Determina la densidad de diseño, el área de diseño y la demanda de agua","No tiene efecto en la hidráulica"], re:"La clasificación de riesgo determina la densidad de diseño (gpm/pies²), el área de diseño y, en última instancia, la demanda de agua del sistema. Una clasificación errónea puede dejar un sistema subdimensionado. Fuente: enfoques de diseño de NFPA 13; método de densidad/área."},
  {id:431, q:"Una planta de impresión que utiliza grandes cantidades de tintas y solventes combustibles se clasificaría más probablemente como:", opts:["Riesgo extra","Riesgo leve","Riesgo ordinario Grupo 1 únicamente","Siempre riesgo leve"], re:"Las áreas de proceso con grandes cantidades de líquidos inflamables/combustibles como tintas y solventes caen bajo riesgo extra. Fuente: ejemplos de riesgo extra de NFPA 13 (impresión, talleres de pintura, uso de solventes)."},
  {id:432, q:"Cuando una ocupación contiene almacenamiento por encima de las alturas/cantidades cubiertas por los criterios de rociado de riesgo ordinario o extra, el diseño generalmente cambia a:", opts:["Criterios de diseño de protección de almacenamiento","Criterios de riesgo leve","No se requieren rociadores","Criterios residenciales"], re:"El almacenamiento apilado en altura y a granel más allá de los límites de ocupación de rociado se diseña usando los criterios de protección de almacenamiento de NFPA 13 (producto básico, altura de almacenamiento, disposición). Fuente: capítulos de almacenamiento de NFPA 13."},
  {id:433, q:"En comparación con el riesgo leve, las ocupaciones de riesgo ordinario y extra generalmente requieren:", opts:["Mayor densidad de agua y menor área máxima de protección por rociador","Menor densidad de agua y mayor espaciamiento de rociadores","Ningún cambio en el diseño","Menos rociadores"], re:"Las clases de mayor riesgo exigen una mayor densidad de diseño y una menor área máxima de protección por rociador (más rociadores, espaciamiento más cerrado). Fuente: tablas de espaciamiento/cobertura y densidad de NFPA 13."},
  {id:434, q:"Una unidad de vivienda residencial protegida conforme a las normas de rociadores residenciales se asocia más con ¿qué familia de diseño?", opts:["Riesgo extra Grupo 2","Criterios de almacenamiento","Criterios residenciales NFPA 13D/13R (enfoque de seguridad humana)","Riesgo ordinario Grupo 2"], re:"Las unidades de vivienda comúnmente se protegen bajo la NFPA 13D (una y dos familias) o la 13R (residencial hasta cuatro pisos), que se centran en la seguridad humana con rociadores residenciales. Fuente: alcance de NFPA 13D / 13R."},
  {id:435, q:"Para rociadores estándar de rociado (spray) en ocupación de riesgo leve, el área máxima de protección por rociador generalmente es:", opts:["100 pies²","130 pies²","200 pies²","225 pies²"], re:"Los rociadores estándar de rociado de riesgo leve tienen un área máxima de protección de 225 pies² por rociador. Fuente: tabla de área de protección de cobertura de NFPA 13 (riesgo leve)."},
  {id:436, q:"Para rociadores estándar de rociado en ocupación de riesgo ordinario, el área máxima de protección por rociador generalmente es:", opts:["225 pies²","130 pies²","90 pies²","400 pies²"], re:"Los rociadores estándar de rociado de riesgo ordinario tienen un área máxima de protección de 130 pies² por rociador. Fuente: tabla de área de protección de cobertura de NFPA 13 (riesgo ordinario)."},
  {id:437, q:"Para rociadores estándar de rociado en riesgo leve (techo liso, no combustible/combustibilidad limitada), la distancia máxima entre rociadores generalmente es:", opts:["15 pies","12 pies","18 pies","20 pies"], re:"El espaciamiento máximo entre rociadores estándar de rociado en riesgo leve es de 15 pies. Fuente: requisitos de espaciamiento de NFPA 13 (riesgo leve)."},
  {id:438, q:"Para rociadores estándar de rociado, la distancia mínima entre dos rociadores (a menos que se use un deflector/bafle certificado) generalmente es:", opts:["3 pies","4 pies","8 pies","6 pies"], re:"El espaciamiento mínimo de centro a centro entre rociadores estándar de rociado es de 6 pies, a menos que se instale un bafle calificado, para evitar la soldadura en frío. Fuente: espaciamiento mínimo / bafles de NFPA 13."},
  {id:439, q:"El espaciamiento mínimo de 6 pies entre rociadores estándar de rociado está destinado principalmente a evitar:", opts:["La corrosión de la tubería","La soldadura en frío (la descarga de un rociador enfría/omite el siguiente)","El uso excesivo de pintura","La alta presión de agua"], re:"El mínimo de 6 pies evita la soldadura en frío, donde el rociado de un rociador en funcionamiento moja/enfría un rociador adyacente y retrasa o impide su funcionamiento. Fuente: justificación del espaciamiento mínimo de NFPA 13."},
  {id:440, q:"Para rociadores estándar de rociado, la distancia máxima de un rociador a una pared generalmente es:", opts:["Igual a la distancia completa entre rociadores","La mitad de la distancia permitida entre rociadores","Siempre 10 pies","Siempre 2 pies"], re:"La distancia máxima de un rociador a una pared es la mitad del espaciamiento máximo permitido entre rociadores (p. ej., 7.5 pies para una distribución de 15 pies). Fuente: distancia a las paredes de NFPA 13."},
  {id:441, q:"Para una distribución de riesgo ordinario con un espaciamiento máximo de 15 pies entre rociadores, la distancia máxima de un rociador a una pared es:", opts:["7.5 pies","5 pies","10 pies","15 pies"], re:"La mitad de 15 pies es 7.5 pies, la distancia máxima a la pared para esa distribución. Fuente: distancia a las paredes de NFPA 13 (regla de la mitad del espaciamiento)."},
  {id:442, q:"Para rociadores estándar de rociado en ocupación de riesgo extra, el área máxima de protección por rociador generalmente es:", opts:["100 pies²","130 pies²","225 pies²","300 pies²"], re:"Los rociadores estándar de rociado de riesgo extra tienen un área máxima de protección de 100 pies² por rociador (90 pies² para algunos diseños de alta densidad calculados hidráulicamente). Fuente: área de protección de cobertura de NFPA 13 (riesgo extra)."},
  {id:443, q:"Para rociadores estándar de rociado de riesgo extra (y de alta densidad calculados hidráulicamente), la distancia máxima entre rociadores generalmente es:", opts:["15 pies","12 pies","20 pies","18 pies"], re:"Las distribuciones de riesgo extra limitan el espaciamiento máximo a 12 pies entre rociadores estándar de rociado. Fuente: espaciamiento de NFPA 13 (riesgo extra)."},
  {id:444, q:"El área de protección de cobertura de un rociador estándar de rociado se determina multiplicando:", opts:["El diámetro de la tubería por la longitud","El factor K del rociador por la presión","La altura del techo por el ancho de la sala","La distancia a lo largo de la línea ramal (S) por la distancia entre líneas ramales (L)"], re:"Área de protección = S x L, donde S es la dimensión a lo largo de la línea ramal y L es la dimensión entre líneas ramales, y no debe exceder el máximo de la tabla para el riesgo. Fuente: método de área de protección de cobertura de NFPA 13."},
  {id:445, q:"La 'regla de la sala pequeña' de la NFPA 13 se aplica a un compartimento que es de riesgo leve, de construcción sin obstrucciones, y no mayor de:", opts:["400 pies²","800 pies²","600 pies²","1,200 pies²"], re:"Una 'sala pequeña' es un compartimento de riesgo leve con construcción sin obstrucciones y un área de piso que no excede 800 pies². Fuente: definición de sala pequeña de NFPA 13."},
  {id:446, q:"Cuando se aplica la regla de la sala pequeña, ¿hasta qué distancia de cualquier pared individual se permite ubicar un rociador?", opts:["6 pies","9 pies","7.5 pies","12 pies"], re:"Bajo la regla de la sala pequeña, los rociadores pueden ubicarse hasta 9 pies de cualquier pared individual, más permisivo que la distancia estándar de 7.5 pies a la pared para riesgo leve. Fuente: regla de la sala pequeña de NFPA 13."},
  {id:447, q:"Los rociadores de cobertura extendida (EC) se diferencian de los rociadores estándar de rociado en que:", opts:["No pueden usarse en interiores","Siempre usan menos agua","No tienen requisitos de certificación","Están certificados para proteger áreas de piso más grandes a espaciamientos especificados"], re:"Los rociadores de cobertura extendida están especialmente certificados para cubrir áreas más grandes (p. ej., hasta 400 pies² en riesgo leve) a los espaciamientos indicados en su certificación. Fuente: rociadores de cobertura extendida de NFPA 13."},
  {id:448, q:"Para los rociadores de cobertura extendida, el espaciamiento y la cobertura que pueden usarse se rigen por:", opts:["Solo las tablas estándar de rociado","El programa de tubería","La preferencia del contratista","La certificación individual del rociador"], re:"El espaciamiento/cobertura del rociador EC debe seguir la certificación específica de ese rociador, que puede exceder los máximos estándar de rociado. Fuente: cobertura extendida / requisitos de certificación de NFPA 13."},
  {id:449, q:"En una distribución de riesgo leve, el área máxima de protección por rociador y el espaciamiento máximo se combinan para limitar la cobertura a aproximadamente:", opts:["Cualquier área que el diseñador elija","Un área de 20 pies x 20 pies","Un área de 25 pies x 25 pies","Un área de 15 pies x 15 pies que no exceda 225 pies²"], re:"Los rociadores estándar de rociado de riesgo leve están limitados por un espaciamiento máximo de 15 pies Y un área máxima de protección de 225 pies², por lo que una cuadrícula de 15x15 (225 pies²) está en el límite. Fuente: espaciamiento y cobertura de NFPA 13 (riesgo leve)."},
  {id:450, q:"Si el área de protección calculada (S x L) para una cabeza excede el máximo de la tabla para la ocupación, el diseñador debe:", opts:["Aumentar aún más el espaciamiento","Ignorar la tabla","Agregar rociadores / reducir el espaciamiento para que cada cabeza se mantenga dentro del área máxima","Usar un drenaje más grande"], re:"Cada rociador debe proteger no más que su área máxima de tabla; si S x L es demasiado grande, debe reducirse el espaciamiento (agregar más rociadores). Fuente: límites de área de protección de cobertura de NFPA 13."},
  {id:451, q:"Los rociadores deben posicionarse de modo que su cobertura real esté dentro tanto del área máxima COMO del espaciamiento máximo porque:", opts:["Solo importa el área","Cualquiera de los límites por sí solo puede dejar un vacío en la cobertura o sobreextender una cabeza","Solo importa el espaciamiento","Ninguno de los límites aplica en interiores"], re:"Ambos límites aplican simultáneamente; satisfacer el área pero exceder el espaciamiento (o viceversa) puede dejar vacíos sin protección, por lo que controla el más restrictivo. Fuente: espaciamiento y área de protección de cobertura de NFPA 13."},
  {id:452, q:"La NFPA 13 requiere una separación mínima entre la parte superior del almacenamiento y los deflectores de los rociadores de al menos:", opts:["6 in","12 in","36 in","18 in"], re:"Se requiere una separación mínima de 18 in (457 mm) entre la parte superior del almacenamiento y los deflectores de los rociadores para que los patrones de rociado puedan desarrollarse y superponerse. Fuente: separación al almacenamiento de NFPA 13."},
  {id:453, q:"La separación de 18 in por debajo del deflector hasta la parte superior del almacenamiento existe principalmente para:", opts:["Permitir que el patrón de descarga de rociado se desarrolle y superponga para prehumedecer los combustibles","Ahorrar costo de material","Hacer espacio para la iluminación","Reducir el tamaño de la tubería"], re:"El espacio libre permite que la descarga del rociador se abra en abanico y se superponga para que los combustibles se prehumedezcan; el almacenamiento demasiado cercano bloquea el desarrollo del patrón. Fuente: justificación de la separación al almacenamiento de NFPA 13."},
  {id:454, q:"Para el almacenamiento de neumáticos de caucho, la NFPA 13 generalmente requiere una separación a los deflectores de al menos:", opts:["18 in","24 in","12 in","36 in"], re:"El almacenamiento de neumáticos de caucho requiere una separación mayor de al menos 36 in (900 mm) a los deflectores de los rociadores. Fuente: separación al almacenamiento de NFPA 13 (neumáticos de caucho)."},
  {id:455, q:"Para rociadores estándar de rociado bajo construcción sin obstrucciones, el deflector debe ubicarse por debajo del techo dentro de un rango de:", opts:["6 in a 24 in","0 in a 4 in","1 in a 12 in","12 in a 36 in"], re:"Bajo construcción sin obstrucciones, los deflectores de rociado colgante/montante estándar deben estar de 1 in a 12 in por debajo del techo (los tipos ocultos/empotrados según su certificación). Fuente: distancia por debajo de los techos / posición del deflector de NFPA 13."},
  {id:456, q:"La 'regla de tres veces' de la NFPA 13 para rociadores estándar de rociado requiere que un rociador se ubique alejado de una obstrucción una distancia de al menos:", opts:["Dos veces la dimensión de la obstrucción","La mitad de la dimensión de la obstrucción","Tres veces la dimensión máxima de la obstrucción","Diez pies sin importar el tamaño"], re:"La regla de tres veces posiciona el rociador al menos a 3 veces la dimensión máxima de la obstrucción (con un tope de 24 in) para que el rociado pueda pasar por ambos lados. Fuente: obstrucciones a la descarga de NFPA 13 (posicionamiento alejado de obstrucciones)."},
  {id:457, q:"Bajo la regla de tres veces para rociadores estándar de rociado, la separación horizontal requerida de la obstrucción tiene un tope máximo de:", opts:["12 in","18 in","24 in","48 in"], re:"La regla de tres veces no necesita exceder 24 in de separación horizontal para rociadores estándar de rociado. Fuente: obstrucciones de NFPA 13 (regla de 3x, máximo 24 in)."},
  {id:458, q:"Para obstrucciones continuas de más de 4 pies de ancho (p. ej., ductos anchos) ubicadas debajo de los rociadores, la NFPA 13 generalmente requiere:", opts:["Nada adicional","Rociadores instalados debajo de la obstrucción","Retirar los rociadores del techo","Duplicar el tamaño de la tubería"], re:"Las obstrucciones de más de 4 pies de ancho generalmente requieren rociadores adicionales instalados debajo de ellas, con los deflectores posicionados según la norma. Fuente: obstrucciones de NFPA 13 (rociadores requeridos debajo de obstrucciones anchas)."},
  {id:459, q:"Cuando se instalan rociadores debajo de una obstrucción ancha, la NFPA 13 generalmente requiere que el deflector se ubique por debajo de la parte inferior de la obstrucción dentro de:", opts:["12 in","24 in","36 in","48 in"], re:"Los rociadores colocados debajo de una obstrucción ancha deben tener los deflectores ubicados a menos de 12 in por debajo de la parte inferior de la obstrucción. Fuente: obstrucciones de NFPA 13 (deflector debajo de obstrucción ancha)."},
  {id:460, q:"La 'regla de cuatro veces' en la NFPA 13 es una extensión de la regla de obstrucción que se aplica a:", opts:["Solo rociadores estándar de rociado","Rociadores de cobertura extendida","Solo rociadores colgantes secos","Solo rociadores en estanterías (in-rack)"], re:"La regla de cuatro veces extiende el concepto de posicionamiento ante obstrucciones a los rociadores de cobertura extendida, con una separación máxima mayor (hasta 36 in). Fuente: obstrucciones de NFPA 13 (cobertura extendida, regla de 4x)."},
  {id:461, q:"Una obstrucción ubicada a 18 in o más por debajo del deflector y no más ancha de 4 pies generalmente puede ser:", opts:["Nunca permitida","Requerida a tener su propio montante (riser)","Despreciada para fines de obstrucción","Causa para retirar todos los rociadores del techo"], re:"Una obstrucción a 18 in o más por debajo del deflector y de hasta 4 pies de ancho generalmente puede ignorarse, ya que el patrón de rociado se ha desarrollado por encima de ella. Fuente: obstrucciones de NFPA 13 (tolerancia por debajo del deflector)."},
  {id:462, q:"Las obstrucciones que impiden que la descarga del rociador llegue al riesgo protegido (como obstrucciones anchas superiores) son abordadas por la NFPA 13 porque:", opts:["Mejoran la cobertura","Reducen la fricción de la tubería","Crean áreas de sombra sin protección debajo de ellas","No tienen efecto"], re:"Tales obstrucciones crean áreas de 'sombra' que los rociadores del techo no pueden alcanzar, requiriendo rociadores adicionales o reposicionamiento. Fuente: obstrucciones de NFPA 13 al desarrollo del patrón de descarga."},
  {id:463, q:"El espacio libre mínimo de 18 in por debajo de los deflectores en un área de almacenamiento se entiende mejor como:", opts:["Solo en un rociador","Una línea vertical en la pared","Un plano horizontal por debajo del cual todo el almacenamiento debe permanecer","Opcional en todos los casos"], re:"La separación de 18 in se trata como un plano horizontal en toda el área de almacenamiento; todos los materiales almacenados deben permanecer por debajo de ese plano. Fuente: separación al almacenamiento de NFPA 13 (plano horizontal)."},
  {id:464, q:"Los materiales almacenados en estantes contra una pared, debajo de los rociadores del techo, se tratan de manera diferente respecto a la separación de 18 in porque:", opts:["No impiden la superposición del rociado de varios rociadores del techo","Siempre necesitan 36 in","Siempre requieren rociadores en estantería","Nunca son combustibles"], re:"El almacenamiento en pared no bloquea la superposición del rociado de varios rociadores del techo como lo hace el almacenamiento en isla, por lo que la regla de 18 in se aplica de manera diferente. Fuente: separación al almacenamiento de NFPA 13 (almacenamiento en pared)."},
  {id:465, q:"Las cuerdas inferiores de las viguetas de barra, las vigas y elementos estructurales similares son ejemplos de obstrucciones evaluadas usando:", opts:["El factor K","La carga de ocupantes","La fórmula de pérdida por fricción","La regla de la viga / reglas de distancia a la obstrucción"], re:"Los elementos estructurales como las vigas y las cuerdas inferiores de las viguetas se evalúan con las reglas de obstrucción (regla de la viga) de la NFPA 13 que rigen la distancia del rociador a la obstrucción y la altura del deflector. Fuente: obstrucciones a la descarga de NFPA 13 (regla de la viga)."},
  {id:466, q:"Las luminarias, los ductos y elementos no estructurales similares que obstruyen la descarga se denominan en la NFPA 13 como:", opts:["Aparatos certificados","Riostras sísmicas","Soportes de tubería","Obstrucciones a la descarga del rociador"], re:"Los elementos no estructurales que bloquean el rociado son 'obstrucciones a la descarga del rociador' y deben abordarse reubicando rociadores o agregando cobertura. Fuente: obstrucciones a la descarga de NFPA 13."},
  {id:467, q:"Mantener la separación requerida por debajo de los deflectores y la distancia adecuada del rociador a la obstrucción es principalmente responsabilidad de:", opts:["Solo el ocupante del edificio después de la mudanza","El diseñador/instalador en la instalación, y el propietario durante la ocupación","La empresa de agua","El contratista de alarmas"], re:"Las separaciones adecuadas deben diseñarse/instalarse según la NFPA 13, y el propietario debe mantenerlas (p. ej., no apilar el almacenamiento demasiado alto) durante la ocupación. Fuente: reglas de separación/obstrucción de NFPA 13; mantenimiento de separaciones de NFPA 25."},
  {id:468, q:"Si se agrega un nuevo entrepiso (mezzanine), ducto o tabique debajo de un sistema de rociadores existente, el instalador debe:", opts:["Ignorarlo","Retirar permanentemente los rociadores afectados","Evaluar las obstrucciones y agregar o reubicar rociadores según lo requiera la NFPA 13","Solo aumentar la presión del sistema"], re:"Las nuevas obstrucciones pueden crear áreas de sombra; la NFPA 13 requiere evaluarlas y agregar/reubicar rociadores para restaurar la cobertura. Fuente: obstrucciones de NFPA 13; modificaciones del sistema."},
  {id:469, q:"En áreas sujetas a terremotos, la NFPA 13 requiere que la tubería de rociadores se proteja contra daños principalmente mediante:", opts:["Pintura adicional","Cabezas de rociadores más grandes","Riostras antibalanceo, acoplamientos flexibles y separaciones","Mayor presión de agua"], re:"La protección sísmica usa riostras antibalanceo, acoplamientos flexibles, restricción de líneas ramales y separaciones en las penetraciones para resistir el movimiento del terremoto. Fuente: protección sísmica de NFPA 13 (Capítulo sobre Protección de Tubería contra Daños donde está Sujeta a Terremotos)."},
  {id:470, q:"Las riostras antibalanceo que resisten el movimiento perpendicular al recorrido de la tubería se denominan:", opts:["Riostras longitudinales","Riostras laterales","Riostras verticales","Acoplamientos flexibles"], re:"Las riostras antibalanceo laterales resisten el movimiento horizontal perpendicular a la tubería; las riostras longitudinales resisten el movimiento paralelo a la tubería. Fuente: definiciones de riostras sísmicas de NFPA 13."},
  {id:471, q:"Las riostras antibalanceo que resisten el movimiento paralelo al recorrido de la tubería se denominan:", opts:["Riostras laterales","Riostras longitudinales","Abrazaderas de montante","Soportes"], re:"Las riostras longitudinales resisten el movimiento a lo largo (paralelo) del recorrido de la tubería; las riostras laterales resisten el movimiento perpendicular. Fuente: definiciones de riostras sísmicas de NFPA 13."},
  {id:472, q:"En las tuberías principales de alimentación y transversales (cross mains), la NFPA 13 generalmente requiere riostras antibalanceo laterales espaciadas a no más de:", opts:["40 pies entre centros","20 pies de separación","80 pies de separación","100 pies de separación"], re:"Las riostras antibalanceo laterales se colocan a intervalos que no exceden 40 pies (12 m) entre centros a lo largo de las tuberías principales. Fuente: espaciamiento de riostras sísmicas de NFPA 13 (riostras laterales)."},
  {id:473, q:"En las tuberías principales de alimentación y transversales, la NFPA 13 generalmente requiere riostras antibalanceo longitudinales espaciadas a no más de:", opts:["40 pies de separación","80 pies entre centros","60 pies de separación","120 pies de separación"], re:"Las riostras antibalanceo longitudinales se colocan a intervalos que no exceden 80 pies (24 m) entre centros a lo largo de las tuberías principales de alimentación y transversales. Fuente: espaciamiento de riostras sísmicas de NFPA 13 (riostras longitudinales)."},
  {id:474, q:"En la parte superior de un montante (riser) de rociadores, la NFPA 13 generalmente requiere:", opts:["Sin riostras","Solo un acoplamiento flexible y nada más","Solo un soporte","Riostra de cuatro vías (lateral y longitudinal combinadas)"], re:"Se requiere riostra de cuatro vías (lateral y longitudinal combinadas) en la parte superior de los montantes y donde los montantes atraviesan pisos. Fuente: riostras sísmicas de NFPA 13 (riostra de cuatro vías en montantes)."},
  {id:475, q:"Los acoplamientos flexibles en los montantes generalmente se requieren dentro de qué distancia de la parte superior e inferior del montante?", opts:["24 in","12 in","6 in","48 in"], re:"Los acoplamientos flexibles se requieren dentro de 24 in (610 mm) de la parte superior e inferior de los montantes (con excepciones para montantes muy cortos). Fuente: NFPA 13 sísmico (acoplamientos flexibles en montantes)."},
  {id:476, q:"Los acoplamientos flexibles se instalan en los sistemas de rociadores sísmicos para:", opts:["Aumentar la presión de agua","Eliminar la necesidad de cualquier riostra","Permitir el movimiento controlado en puntos donde se espera movimiento diferencial","Reducir el diámetro de la tubería"], re:"Los acoplamientos flexibles acomodan el movimiento diferencial/relativo en los montantes, las juntas sísmicas del edificio y ubicaciones similares, trabajando junto con las riostras rígidas en otros lugares. Fuente: NFPA 13 sísmico (propósito de los acoplamientos flexibles)."},
  {id:477, q:"Donde la tubería de rociadores contra incendios cruza una junta de separación sísmica (de expansión) del edificio, la NFPA 13 requiere:", opts:["Una conexión soldada rígida","Flexibilidad/separación para acomodar el movimiento en ambos lados de la junta","Retirar la tubería","Solo duplicar las riostras"], re:"La tubería que cruza juntas de separación sísmica debe incluir provisiones (conjuntos flexibles/separación) para permitir el movimiento independiente de las dos secciones del edificio. Fuente: conjuntos de separación sísmica de NFPA 13."},
  {id:478, q:"Se requiere separación alrededor de la tubería de rociadores donde atraviesa paredes, pisos o plataformas en áreas sísmicas para que:", opts:["El agua pueda fugarse","La tubería pueda pintarse","La tubería no se dañe por el movimiento relativo del elemento del edificio","La tubería quede oculta"], re:"La separación (o un manguito flexible) en las penetraciones evita que el elemento rígido del edificio cizalle o aplaste la tubería durante el movimiento sísmico. Fuente: NFPA 13 sísmico (separación en penetraciones)."},
  {id:479, q:"La separación nominal requerida alrededor de tubería de 1 in a 3-1/2 in que atraviesa paredes/pisos en diseños sísmicos generalmente es:", opts:["Aproximadamente 1 in","Sin separación","Aproximadamente 2 in","Aproximadamente 6 in"], re:"La NFPA 13 generalmente requiere una separación nominal de 1 in alrededor de tubería de 1 in a 3-1/2 in (y 2 in para 4 in y mayor) en las penetraciones, a menos que se provean acoplamientos flexibles/manguitos. Fuente: separación sísmica en penetraciones de NFPA 13."},
  {id:480, q:"Un conjunto de riostra antibalanceo debe ser capaz de resistir cargas en:", opts:["Solo la dirección descendente","Solo la dirección ascendente","Solo el flujo de agua horizontal","Tanto tensión como compresión a lo largo de la riostra"], re:"Las riostras antibalanceo sísmicas deben resistir cargas horizontales que actúan en ambas direcciones (tensión y compresión) a lo largo del eje de la riostra. Fuente: riostras sísmicas de NFPA 13 (direcciones de carga)."},
  {id:481, q:"La porción de tubería cuya carga sísmica es soportada por una riostra antibalanceo dada se denomina la ___ de la riostra:", opts:["Zona de influencia","Zona de fricción","Área de riesgo","Niple del montante"], re:"Cada riostra antibalanceo soporta la carga sísmica de una 'zona de influencia' definida de tubería; las cargas se suman dentro de esa zona para dimensionar la riostra. Fuente: riostras sísmicas de NFPA 13 (zona de influencia / cálculo de carga)."},
  {id:482, q:"La restricción de fin de línea / línea ramal en diseños sísmicos está destinada a:", opts:["Aumentar el flujo","Limitar el movimiento lateral excesivo de los extremos de línea ramal sin riostra","Reemplazar todos los soportes","Reducir la demanda de agua"], re:"Las restricciones de línea ramal y de extremo limitan el balanceo lateral de la tubería que de otro modo no está arriostrada, reduciendo la posibilidad de rotura en accesorios/rociadores. Fuente: NFPA 13 sísmico (restricción de líneas ramales)."},
  {id:483, q:"Los componentes de las riostras sísmicas tales como riostras, sujetadores y fijaciones a la estructura deben ser:", opts:["Certificados/aprobados e instalados a la estructura capaz de soportar la carga","Cualquier herraje a la mano","Hechos de madera","Opcionales en todas las jurisdicciones"], re:"Los miembros de las riostras, los accesorios y las fijaciones estructurales deben estar certificados/aprobados y anclados a la estructura del edificio capaz de resistir las cargas sísmicas calculadas. Fuente: riostras sísmicas de NFPA 13 (componentes y fijación a la estructura)."},
  {id:484, q:"En California, la protección sísmica de la tubería de rociadores contra incendios es requerida porque:", opts:["Es puramente opcional en todas partes","Solo las ciudades costeras tienen terremotos","Gran parte del estado está en zonas de alto riesgo sísmico y los códigos lo exigen","El agua se congela en California"], re:"La alta actividad sísmica de California lleva al CFC/NFPA 13 a requerir protección sísmica de los sistemas de rociadores en todo el estado en las áreas aplicables. Fuente: capítulo sísmico de NFPA 13; provisiones sísmicas de los California Building Standards."},
  {id:485, q:"En California, la clasificación de la CSLB para un Contratista de Protección contra Incendios es:", opts:["C-10","C-36","C-16","C-20"], re:"La C-16 es la clasificación de la CSLB para un Contratista de Protección contra Incendios. Fuente: CSLB Licensing Classifications, C-16 Fire Protection."},
  {id:486, q:"La clasificación C-16 de la CSLB autoriza a un contratista a diseñar, fabricar e instalar:", opts:["Solo el cableado eléctrico de alarmas contra incendios","Todos los tipos de sistemas de protección contra incendios (excluyendo los sistemas eléctricos de alarma)","Solo detectores de humo residenciales","Solo tubería subterránea de gas"], re:"Un contratista C-16 diseña, fabrica e instala todos los tipos de sistemas de protección contra incendios y el equipo asociado, excluyendo los sistemas eléctricos de alarma. Fuente: descripción de la clasificación C-16 de la CSLB (CCR Título 16 §832.16)."},
  {id:487, q:"El cableado de los sistemas eléctricos de alarma contra incendios generalmente está fuera del alcance de la C-16 y en su lugar corresponde a ¿qué clasificación?", opts:["C-16","C-36 (Plomería)","C-10 (Eléctrica)","C-4 (Calderas)"], re:"El cableado de los sistemas eléctricos de alarma está excluido de la C-16 y se realiza bajo la clasificación eléctrica C-10. Fuente: descripción C-16 de la CSLB (excluye sistemas eléctricos de alarma); C-10 Electrical."},
  {id:488, q:"El personal que instala o repara sistemas de protección contra incendios basados en agua bajo una licencia C-16 para proyectos comerciales/multifamiliares generalmente debe poseer:", opts:["Una licencia de bienes raíces","Una comisión de notario","Una licencia de plomería C-36","Una certificación de Instalador de Rociadores contra Incendios (Fire Sprinkler Fitter)"], re:"Los calificadores C-16 y los trabajadores de nivel oficial que instalan/reparan sistemas de protección contra incendios basados en agua para viviendas comerciales o multifamiliares deben obtener una certificación de Fire Sprinkler Fitter. Fuente: CSLB Industry Bulletin 24-02; requisitos de fire sprinkler fitter del Código H&S."},
  {id:489, q:"La CSLB en sí forma parte de ¿qué departamento de California?", opts:["El Departamento de Asuntos del Consumidor","CAL FIRE","Caltrans","La Junta de Impuestos sobre Franquicias (Franchise Tax Board)"], re:"La Contractors State License Board (CSLB) está dentro del Departamento de Asuntos del Consumidor de California. Fuente: CSLB / Department of Consumer Affairs."},
  {id:490, q:"Antes de comenzar la mayoría de las instalaciones comerciales de rociadores contra incendios, el contratista normalmente debe obtener:", opts:["Nada en absoluto","Solo una prueba de flujo de hidrante","Solo una tarjeta de presentación","Un permiso de construcción/incendios y planos aprobados de la AHJ"], re:"Generalmente se requiere un permiso y planos aprobados por la AHJ antes de instalar un sistema de rociadores contra incendios; trabajar sin un permiso puede ser una violación del código. Fuente: California Fire Code §105 permisos; CFC §901.2 revisión de planos."},
  {id:491, q:"Los planos de trabajo (planos de taller) de rociadores contra incendios presentados para aprobación generalmente son preparados/aprobados por:", opts:["Cualquier persona sin licencia","Personas calificadas y revisados/aprobados por la AHJ (y el profesional de diseño cuando se requiere)","El lector del medidor de agua","El ocupante del edificio"], re:"Los planos de trabajo son preparados por personas calificadas y deben ser revisados/aprobados por la AHJ antes de la instalación; muchos proyectos también requieren un profesional de diseño registrado. Fuente: planos de trabajo de NFPA 13; CFC §901.2."},
  {id:492, q:"Después de la instalación y antes de que un sistema de rociadores se ponga en servicio, la NFPA 13 requiere que el contratista realice y documente:", opts:["Ninguna prueba","Solo una inspección de pintura","Solo un vistazo visual","Pruebas de aceptación, incluida una prueba hidrostática y un lavado (flushing)"], re:"Las pruebas de aceptación (prueba hidrostática, lavado de tuberías subterráneas/acometidas, prueba de drenaje principal, etc.) deben realizarse y documentarse antes de que el sistema sea aceptado. Fuente: aceptación del sistema de NFPA 13 (prueba hidrostática 200 psi / 50 psi por encima de la estática durante 2 horas)."},
  {id:493, q:"La prueba hidrostática de aceptación estándar para un nuevo sistema de rociadores bajo la NFPA 13 generalmente es:", opts:["200 psi (o 50 psi por encima de la estática si la estática supera 150 psi) durante 2 horas","50 psi durante 30 minutos","1,000 psi durante 24 horas","Sin presión, solo agua"], re:"La nueva tubería de rociadores se prueba hidrostáticamente a 200 psi durante 2 horas (o 50 psi por encima de la estática donde la presión estática supera 150 psi). Fuente: prueba hidrostática de NFPA 13 (aceptación)."},
  {id:494, q:"Al finalizar, la NFPA 13 requiere que el contratista instalador proporcione al propietario:", opts:["Nada","Solo la orden de compra original","Solo una confirmación verbal","Un Certificado de Materiales y Pruebas del Contratista (Contractor's Material and Test Certificate)"], re:"El contratista instalador debe completar y proporcionar el Certificado de Materiales y Pruebas del Contratista que documenta los materiales, las pruebas y los resultados. Fuente: Contractor's Material and Test Certificate de NFPA 13."},
  {id:495, q:"La responsabilidad de un contratista C-16 por un sistema de rociadores contra incendios generalmente incluye:", opts:["Solo vender las piezas","Diseñar, instalar, probar y proporcionar la documentación requerida según el código","Solo pintar la tubería","Solo inspeccionar el trabajo de otros contratistas"], re:"El contratista C-16 diseña, fabrica, instala, prueba y proporciona la documentación requerida para el sistema de protección contra incendios, dentro del alcance de la clasificación. Fuente: descripción C-16 de la CSLB; instalación y aceptación de NFPA 13."},
  {id:496, q:"Instalar sistemas de rociadores contra incendios en California sin la licencia de contratista adecuada puede resultar en:", opts:["Acción disciplinaria, sanciones y contratos no exigibles","Una felicitación","Mejora automática de la licencia","Nada bajo la ley"], re:"Contratar sin licencia en California es ilegal y puede llevar a sanciones, acción disciplinaria y contratos que no son legalmente exigibles por la parte sin licencia. Fuente: California Business & Professions Code §7028 y siguientes; aplicación de la CSLB."},
  {id:497, q:"El umbral monetario legal general por encima del cual se requiere una licencia de contratista para un solo trabajo de construcción en California es:", opts:["$100 o más","$5,000 o más","$500 o más (mano de obra y materiales)","$50,000 o más"], re:"Generalmente se requiere una licencia de contratista de la CSLB cuando el costo combinado de mano de obra y materiales de un trabajo es de $500 o más. Fuente: California Business & Professions Code §7048; CSLB."},
  {id:498, q:"Los sistemas de tubería vertical (standpipe) (p. ej., las conexiones de manguera NFPA 14 para uso del cuerpo de bomberos) caen dentro del alcance de ¿qué clasificación como protección contra incendios basada en agua?", opts:["Solo C-10","Solo C-20","C-16 Protección contra Incendios","Solo B Edificación General"], re:"Los sistemas de tubería vertical (basados en agua) son parte del alcance de protección contra incendios C-16 de instalar todos los tipos de sistemas de protección contra incendios. Fuente: descripción C-16 de la CSLB; tuberías verticales NFPA 14."},
  {id:499, q:"Cuando un sistema de rociadores contra incendios se conecta a un suministro de agua público, el contratista también debe coordinar con el proveedor de agua respecto a:", opts:["El color de la pintura de la pared","La selección de la alfombra","La prevención de reflujo (backflow) y la conexión de servicio","Las tejas del techo"], re:"La conexión a un suministro público requiere coordinar la prevención de reflujo y la conexión de servicio con el proveedor de agua/AHJ. Fuente: California Plumbing Code / requisitos de reflujo de la AHJ; conexión de suministro de agua de NFPA 13."},
  {id:500, q:"Un contratista C-16 que realiza trabajo que requiere solo tareas incidentales y suplementarias de otro oficio para completar el proyecto de protección contra incendios puede:", opts:["Realizar ese trabajo incidental y suplementario como parte del proyecto C-16","Nunca tocar el trabajo de ningún otro oficio","Debe contratar a un contratista general por cada tornillo","Perder la licencia automáticamente"], re:"Las reglas de la CSLB permiten que un contratista especializado tome y ejecute trabajo que es incidental y suplementario a la realización del trabajo del oficio para el cual está licenciado. Fuente: CSLB CCR Título 16 §831 (incidental y suplementario)."}
];
